-- Poems batch 170
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1658d3b2-f919-476f-8514-62258e21dd27','過峽山寺','呂定','宋','宋诗','song-poetry','','[]','峽江江上峽山寺，落日峰巒翠作堆。',64,'全唐诗/poet.song.168000.json','["峽江江上峽山寺，落日峰巒翠作堆。", "雲擁半空樓殿出，天然一幅畫圖開。", "仙人採藥和光洞，釋子翻經化樂臺。", "顧我紅塵車馬客，題詩無暇掃蒼苔。"]'),
('8a043586-d345-4425-9c16-e0e115c8e488','登越王臺','呂定','宋','宋诗','song-poetry','','[]','海上荒臺草樹平，登臨不盡古人情。',64,'全唐诗/poet.song.168000.json','["海上荒臺草樹平，登臨不盡古人情。", "白雲萬里懷親舍，紅日中天望帝京。", "百粵山川秋歷落，山城樓閣晚崢嶸。", "醉來徙倚欄干曲，聽徹西風畫角聲。"]'),
('2466767f-9d48-46b0-b6c8-5bdb9046f612','浴日亭和蘇學士韻','呂定','宋','宋诗','song-poetry','','[]','危亭突兀倚青山，坐對扶桑碧海灣。',64,'全唐诗/poet.song.168000.json','["危亭突兀倚青山，坐對扶桑碧海灣。", "紫霧欲生龍伯廟，洪濤先涌虎門關。", "光摇宇宙花生眼，影動闌干酒上顔。", "遥望蓬萊宮闕曉，一輪飛挂碧雲間。"]'),
('e90ee2ba-715d-4128-a1cb-5a757d249941','遊海珠寺','呂定','宋','宋诗','song-poetry','','[]','何年神物抱珠遊，遺向滄浪第一洲。',64,'全唐诗/poet.song.168000.json','["何年神物抱珠遊，遺向滄浪第一洲。", "五色化成金世界，六鼇擎出寶香樓。", "光涵蛟室星辰動，影落龍宮日月浮。", "萬古團團天地裏，磬聲敲出海門秋。"]'),
('750db074-e547-4daf-a3a4-471d8f1bab99','登廣城樓','呂定','宋','宋诗','song-poetry','','[]','三尺龍泉事遠遊，越王臺上望南州。',64,'全唐诗/poet.song.168000.json','["三尺龍泉事遠遊，越王臺上望南州。", "一天雨過千山曉，萬里風來五月秋。", "江郭樓臺蠻客市，海門烟日蜑家舟。", "臨戎不有安邊策，應愧常何薦馬周。"]'),
('b83c63ce-7082-460e-b669-d97864b2aa62','謁金華寺六祖法堂','呂定','宋','宋诗','song-poetry','','[]','坐閲人間幾百年，雙趺渾似後來禪。',64,'全唐诗/poet.song.168000.json','["坐閲人間幾百年，雙趺渾似後來禪。", "空空明鏡臺前地，寂寂紅塵境外天。", "風動法林從虎過，雲生咒鉢解龍眠。", "至今月到層樓上，應共祥光午夜圓。"]'),
('366fee05-0e7c-4795-a2b8-c38254dfb4ae','新秋雨過述懷','宋光宗','宋','宋诗','song-poetry','','[]','中興日月明，王氣山河在。',24,'全唐诗/poet.song.168000.json','["中興日月明，王氣山河在。", "萬物飾昭回，稽首王言大。"]'),
('4399d6fc-5dba-4d33-b190-372eabeebf5c','會僚屬賞海棠偶有題詠','宋光宗','宋','宋诗','song-poetry','','[]','濃淡名花産蜀鄉，半含風露浥新妝。',32,'全唐诗/poet.song.168000.json','["濃淡名花産蜀鄉，半含風露浥新妝。", "嬌嬈不減舊時態，誰與丹青爲發揚。"]'),
('f75d17e2-97ec-4ad7-8c1a-2ea6482c2d11','觀海棠有成','宋光宗','宋','宋诗','song-poetry','','[]','東風用意施顔色，艷麗偏宜著雨時。',32,'全唐诗/poet.song.168000.json','["東風用意施顔色，艷麗偏宜著雨時。", "朝詠暮吟看不足，羨他逸蝶宿深枝。"]'),
('07db6df9-6bbf-4168-b786-45930b891e14','待月詩','宋光宗','宋','宋诗','song-poetry','','[]','入夜跏趺多待月，移時箕踞爲看山。',64,'全唐诗/poet.song.168000.json','["入夜跏趺多待月，移時箕踞爲看山。", "苔生晚片應知靜，雪動秋根會見閒。", "瘦鶴獨隨行藥後，高僧相對試茶間。", "疏篁百本松千尺，莫怪頻頻此往還。"]'),
('9e6f523a-1565-413f-8f10-b95b2c72508c','賜余復','宋光宗','宋','宋诗','song-poetry','','[]','臨軒策士豈徒然，嗣守丕基務得賢。',64,'全唐诗/poet.song.168000.json','["臨軒策士豈徒然，嗣守丕基務得賢。", "爾吐忠言攄素藴，吾縻好爵副詳延。", "愛君憂國毋終怠，厚澤深仁頼廣宣。", "賜宴瓊林修故事，朕心期待見詩篇。"]'),
('78311244-d6b7-43e3-9cb4-8b3572a2a21e','和燕射','宋光宗','宋','宋诗','song-poetry','','[]','秋深欲曉歛輕烟，翠木森圍萬里川。',64,'全唐诗/poet.song.168000.json','["秋深欲曉歛輕烟，翠木森圍萬里川。", "閶闔啟關傳法駕，玉津按武會英賢。", "皇皇聖父明如日，挺挺良臣直似弦。", "韜武歡呼稱萬壽，未饒天保報恩篇。"]'),
('85b2758e-4c8b-4662-b398-1894c8a31b0c','題陸瑾漁家風景圖','宋光宗','宋','宋诗','song-poetry','','[]','翠嵐迎步興何長，笑領漁翁入醉鄉。',32,'全唐诗/poet.song.168000.json','["翠嵐迎步興何長，笑領漁翁入醉鄉。", "日暮渚田微雨後，鷺鷥閒暇稻花凉。"]'),
('18884929-21cc-44bb-a2c3-e110adca7429','題徐崇嗣沒骨牡丹圖','宋光宗','宋','宋诗','song-poetry','','[]','已過穀雨十六日，猶見牡丹鬭淺紅。',32,'全唐诗/poet.song.168000.json','["已過穀雨十六日，猶見牡丹鬭淺紅。", "曾不争先及開早，能陪芍藥到薰風。"]'),
('76e0a06c-6f26-4947-a781-8246479cdba4','題楊補之紅梅圖','宋光宗','宋','宋诗','song-poetry','','[]','去年枝上見紅芳，約畧紅葩傅淺妝。',32,'全唐诗/poet.song.168000.json','["去年枝上見紅芳，約畧紅葩傅淺妝。", "今日亭中足顔色，可能無意謝東皇。"]'),
('898161a2-887c-4762-a150-8bab68d24fda','題張萱游行士女圖','宋光宗','宋','宋诗','song-poetry','','[]','閒來洞口訪劉君，緩步輕擡玉線裙。',32,'全唐诗/poet.song.168000.json','["閒來洞口訪劉君，緩步輕擡玉線裙。", "細白桃花擲流水，更無言語倚彤雲。"]'),
('a25d259d-4071-4c8a-9677-567bd4a8b289','賜楊萬里','宋光宗','宋','宋诗','song-poetry','','[]','黄蘆洲上雪初乾，風撼枯枝晚更寒。',32,'全唐诗/poet.song.168000.json','["黄蘆洲上雪初乾，風撼枯枝晚更寒。", "靜艤小舟誰得似，生涯瀟洒一漁竿。"]'),
('989065d0-ccaf-4c81-accf-b4c27fe21c95','句  其一','宋光宗','宋','宋诗','song-poetry','','[]','細疊輕綃色倍濃，晚霞猶在綠陰中。',16,'全唐诗/poet.song.168000.json','["細疊輕綃色倍濃，晚霞猶在綠陰中。"]'),
('3249ef33-8952-437f-b208-2fdc3fbe01f4','句  其二','宋光宗','宋','宋诗','song-poetry','','[]','晴野花侵路，春陂水上橋。',12,'全唐诗/poet.song.168000.json','["晴野花侵路，春陂水上橋。"]'),
('758d85d7-03af-4fd7-9b77-b992472d1177','句  其三','宋光宗','宋','宋诗','song-poetry','','[]','綺霞初結處，珠露未晞時。',12,'全唐诗/poet.song.168000.json','["綺霞初結處，珠露未晞時。"]'),
('66b95bc0-a161-42f5-9670-ada22dcea5b6','句  其四','宋光宗','宋','宋诗','song-poetry','','[]','蓼岸飛寒蝶，汀沙戲水禽。',12,'全唐诗/poet.song.168000.json','["蓼岸飛寒蝶，汀沙戲水禽。"]'),
('c2ae8a19-3866-4ca7-b651-40ae01cd1000','梅','張縯','宋','宋诗','song-poetry','','[]','向來懶不賦梅詩，禪榻忘機鬢已絲。',64,'全唐诗/poet.song.168000.json','["向來懶不賦梅詩，禪榻忘機鬢已絲。", "月戶忽逢雙玉立，春風又見一年期。", "樓高縹緲明霜影，竹冷橫斜浸雪枝。", "尚笑閒塵除未盡，暗香猶著夢魂知。"]'),
('d9916487-d642-4db7-921c-aa57c655f6b1','雲岩寺  其一','張縯','宋','宋诗','song-poetry','','[]','棟宇何年有，雲岩擁樹深。',48,'全唐诗/poet.song.168000.json','["棟宇何年有，雲岩擁樹深。", "山僧傳舊險，詩者有行吟。", "雲影侵巾屨，江聲送古今。", "荔枝何用數，撫字每勞心。"]'),
('f5c28444-f844-46ab-83e9-902159a66e85','雲岩寺  其二','張縯','宋','宋诗','song-poetry','','[]','檻外滔滔水，岩前冉冉雲。',48,'全唐诗/poet.song.168000.json','["檻外滔滔水，岩前冉冉雲。", "行人舟似葉，題墨蘚生紋。", "歲月帆檣去，山川楚蜀分。", "十年三艤棹，永愧北山文。"]'),
('d43ca6f5-1e5e-4c73-8f22-be71e9a6463e','次袁說友巫山十二峰古風二十五韻','張縯','宋','宋诗','song-poetry','','[]','化工神偉開物姿，劖石萬仞不作癡。',384,'全唐诗/poet.song.168000.json','["化工神偉開物姿，劖石萬仞不作癡。", "巍峰聳立威鳳舉，急挾怒流奔馬遲。", "隠然萬里形勝重，信矣四海遊觀奇。", "天開匹練勢巀嶪，雲擁列嶂青參差。", "輿圖悚視天設險，舟檝競與江東之。", "何年宇宙此盤據，遠攬泰華宜肩隨。", "胸吞雲夢盪物表，眥决飛鳥忘神疲。", "元戎授任盛節制，列艦徑度羅旌旗。", "天香來時滿衣袖，講殿幾日辭書帷。", "詞源浩蕩春峽水，句律飄揚秋桂枝。", "天門有路穿水去，筆力到古羣峰低。", "遠參退之賦山囿，下陋樊川娛水嬉。", "有神相宅理應爾，夢賦靡曼奚其爲。", "流轉不根憐已久，高詠取正今逢時。", "昔年飛輓忝將指，異境名言猶念茲。", "大篇巨軸窺勝賞，赤甲白鹽神坐馳。", "有從絕唱發奇偉，衆作絢采同彰施。", "德風草偃閫以外，觀頌下轉江之湄。", "甯須三年奏漢計，行復八彩瞻堯眉。", "慈恩論契肯隔面，草堂枉駕欣解頤。", "我方卧雲書自伴，公詠入相衣宜緇。", "少須凋瘵盡撫摩，大賑廩粟歌噫嘻。", "會看丹詔來北闕，更上岷嶺登峨嵋。", "江山得助協嘉會，賡載歸寫明良詩。"]'),
('f0d57ad1-8d80-43e0-9a98-53aa6a4145c3','題三峽堂','張縯','宋','宋诗','song-poetry','','[]','羣山危立接雲天，一水東朝會百川。',64,'全唐诗/poet.song.168000.json','["羣山危立接雲天，一水東朝會百川。", "泱漭堪輿無此壯，崔嵬疏鑿定何年。", "千秋躍馬興亡夢，一點飛鳬上下船。", "時有剛風來浩渺，起予高興九秋邊。"]'),
('fcb645ba-74c4-43e6-a3ee-51aca7b6013c','諸丈賡示前章再次韻','張縯','宋','宋诗','song-poetry','','[]','桃李層層媚遠天，碧蕪映带綺成川。',64,'全唐诗/poet.song.168000.json','["桃李層層媚遠天，碧蕪映带綺成川。", "英靈舊有凌雲賦，混一長看建武年。", "老去無知經世用，夢歸欲問泝江船。", "請君妙語驚頹懶，一笑詩壇酒社邊。"]'),
('fe0e4a04-53af-4b80-bec0-c43c19eb3ec9','奉陪安撫大卿登八陣臺覽觀忠武侯諸葛公遺像偶成長句','張縯','宋','宋诗','song-poetry','','[]','白帝城西魚腹浦，十月江平見津滸。',160,'全唐诗/poet.song.168000.json','["白帝城西魚腹浦，十月江平見津滸。", "當年累石紛成行，此地卧龍經講武。", "轅門外建嚴中權，列陣相承存後伍。", "何人蛇勢識常山，未數魚麗矜鄭拒。", "懸知精神貫金石，尚想號令嚴鉦鼓。", "老兵料敵應疑生，川后澂波其敢侮。", "向令赤伏有遺符，下睨皇州直指取。", "云何遺跡司神明，獨靳豐功被寰宇。", "高城置酒供臨眺，往事興懷增歎撫。", "巍然王佐三代前，信矣名言照千古。"]'),
('6f7395ad-27ad-4c6e-9147-1d5d6cf41112','萬安驛','張縯','宋','宋诗','song-poetry','','[]','勁兵重卒付胡奴，⿰區支雀⿰區支魚計自疏。',36,'全唐诗/poet.song.168000.json','["勁兵重卒付胡奴，⿰區支雀⿰區支魚計自疏。", "地入萬安知幾許，却憐此日始囘車。"]'),
('ed3fe3b3-14d2-41e6-9ae0-b621460cc92a','題沔州諸葛武侯廟','張縯','宋','宋诗','song-poetry','','[]','赤伏終休運，前營落大星。',48,'全唐诗/poet.song.168000.json','["赤伏終休運，前營落大星。", "皇王空禮樂，江漢閟英靈。", "斷壟牛羊入，空山草木青。", "經時須此牧，清淚灑泉扃。"]'),
('c566b797-8772-4d3b-8b35-5d8133ebda15','九日登方山','滕璘','宋','宋诗','song-poetry','','[]','知君夙昔愛登山，特地相携上峻巒。',64,'全唐诗/poet.song.168000.json','["知君夙昔愛登山，特地相携上峻巒。", "豈但登高如杜牧，故應訪舊憶朱寬。", "凝眸直欲小東魯，振袂如將近廣寒。", "幸有酒尊供笑語，不愁歸路十分難。"]'),
('7c65b081-2251-4fc2-80c5-aa43d0b3204c','靈棲巖','宋蒙','宋','宋诗','song-poetry','','[]','嶻嶻嶪嶪山如簇，磊磊落落石如屋。',96,'全唐诗/poet.song.168000.json','["嶻嶻嶪嶪山如簇，磊磊落落石如屋。", "上有綠樹之陰陰，下有寒溜之涔涔。", "通天有竇十餘丈，遊子捫蘿來復往。", "是中端合巢神仙，桃花流水何杳然。", "我來正值春風暮，似笑賢勞又還去。", "準擬釃酒聊從容，對此坐想飛來峯。"]'),
('5816538e-502f-4f8d-a61e-d0bb97cfadb4','次袁說友巫山十二峰二十五韻','閭丘泳','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','舟行觀山無定姿，篷底兀坐真兒癡。',384,'全唐诗/poet.song.168000.json','["舟行觀山無定姿，篷底兀坐真兒癡。", "層崖複嶺正雜遝，平岡橫阜俄逶遲。", "晴嵐參天固競秀，深崖挺石尤多奇。", "遥岑浮眉綠點點，飛瀑懸劍鋒差差。", "飽聞巫山妙天下，今誦公詩如見之。", "蓬仙來應人間世，妙齡便有聲名隨。", "日談經術輔主聖，久領國計嗤駑疲。", "共推經邦濟川楫，暫建分陝元戎旗。", "百城聽命仰賜履，三邊制勝如籌帷。", "長江高唐神女峽，萬里昆崙分一枝。", "峯巒森立入霄漢，塔廟選勝居高低。", "響山猨啼聲若嘯，迎棹鴉舞來如嬉。", "金母分畀神靈職，孰云朝暮陽臺爲。", "琅函蘂笈發天秘，贊禹治水唐虞時。", "英辭一洗千載陋，寫之琬琰宜在茲。", "人思傳本快先睹，蔡邕石經車馬馳。", "北暢威名被沙漠，西奠夷落連黔施。", "帝遣雲軿鎮南極，祠宮姑寓江之湄。", "湘君時過鼓瑶瑟，宓妃豈復揚蛾眉。", "金關已侔坐少廣，丹經孰授踰期頤。", "野人塵容粗知學，素守亦復涅不緇。", "朅來乘軺職飛輓，兩見祈穀歌噫嘻。", "疲氓崎嶇上轉粟，舊業荒落南窺嶷。", "勞生屢已度劍棧，清游頗念登峨嵋。"]'),
('f833551d-9fa3-4eee-ad1d-9ea4932a60bd','與張樞密話舊作','薛揚祖','宋','宋诗','song-poetry','','[]','羸軀苦善病，日與藥裹親。',108,'全唐诗/poet.song.168000.json','["羸軀苦善病，日與藥裹親。", "藉彼參苓功，扶此憂患身。", "思君若饑渴，相憐同病人。", "余身本蒲柳，寧竢秋風晨。", "君誠松柏姿，何患不長春。", "容面一若丹，鬢髮一若銀。", "來日安可期，往事曷足陳。", "不能罄君罍，奚以浣我塵。", "吹笙將鼓瑟，慚余非嘉賓。"]'),
('cf3c143d-d2b8-4bf4-9564-b3ab87717e12','郊居寫志','薛揚祖','宋','宋诗','song-poetry','','[]','過庭聞曲禮，在野習王風。',48,'全唐诗/poet.song.168000.json','["過庭聞曲禮，在野習王風。", "世亂思休否，兒愚藉發蒙。", "雲霞海色裏，烟火雨聲中。", "所喜田間事，比鄰自昔同。"]'),
('330b4b70-af30-49f5-9316-ced63b821817','送表弟朱拙夫以縣尉赴新安','薛揚祖','宋','宋诗','song-poetry','','[]','散金結客不求償，落落生平此熱腸。',64,'全唐诗/poet.song.168000.json','["散金結客不求償，落落生平此熱腸。", "七尺許君何慷慨，一朝用世果循良。", "滿城山色侵官舍，徧地溪聲度女牆。", "邑長若逢潘岳輩，肯教名獨起河陽。"]'),
('0c80b6b8-cb4e-4be0-9d06-362392b6d8a9','朱元晦過訪  其一','盛璲','宋','宋诗','song-poetry','','[]','蒼松翠竹映斜暉，野菊花開過客稀。',32,'全唐诗/poet.song.168000.json','["蒼松翠竹映斜暉，野菊花開過客稀。", "葉底黄蟲作寒繭，雨餘蝴蝶滿園飛。"]'),
('fcc04628-1a6d-43e8-ab5c-7a20862de335','朱元晦過訪  其二','盛璲','宋','宋诗','song-poetry','','[]','梅花樹下三間屋，挂壁枯桐盡日閑。',32,'全唐诗/poet.song.168000.json','["梅花樹下三間屋，挂壁枯桐盡日閑。", "有客過門彈一曲，斷雲殘雪滿空山。"]'),
('ce23d27a-9331-4fab-93a8-7a87c28dc076','題高城雪堂','祝勛','宋','宋诗','song-poetry','','[]','築室烟霞窟，門開紫翠堆。',48,'全唐诗/poet.song.168000.json','["築室烟霞窟，門開紫翠堆。", "真成雲挽住，不爲景催回。", "山月窺檐入，溪風掠坐來。", "鑪薰兼茗飲，浄拂綠琴埃。"]'),
('501c7217-658d-4c42-91d7-591e1e8e255a','釣臺','李誼','宋','宋诗','song-poetry','','[]','姜居渭水爲周相，嚴隠桐江不漢臣。',32,'全唐诗/poet.song.168000.json','["姜居渭水爲周相，嚴隠桐江不漢臣。", "試把二公較名節，誰知總是一絲綸。"]'),
('41546b7e-7e0a-49e3-b819-93d25f67f962','釣魚臺','陳允升','宋','宋诗','song-poetry','','[]','羅浮山崒嵂，安有釣魚臺。',216,'全唐诗/poet.song.168000.json','["羅浮山崒嵂，安有釣魚臺。", "臺居觀東隅，此名從何來。", "昔時爨下童，辛勤水與柴。", "歲久功行完，豹變山陰霾。", "一朝採幽澗，恍然江海涯。", "篙師艤舟在，相與語詼諧。", "爨童有行計，篙師相與偕。", "得魚饋主翁，辭去挽不回。", "傍者躡其蹤，扁舟往巖崖。", "始信武陵源，有路通塵埃。", "回視所遺魚，化作溝中材。", "古有恒真人，事豈欺我哉。", "太公渭水濱，白頭佐□□。", "子陵七里灘，清風永可懷。", "爨人去幾秋，魚臺尚崔嵬。", "此名照青史，此石封蒼苔。", "我來筆其事，靈蹤救沈埋。", "山中勝事多，對此空徘徊。"]'),
('6d3ed4d8-8eb7-4aaf-8f3d-c4f3b1d30faf','慶梅州劉侯修葺程鄉學宮落成  其一','林陶','宋','宋诗','song-poetry','','[]','孰不爲邦，孰守其鄉。',50,'全唐诗/poet.song.168000.json','["孰不爲邦，孰守其鄉。", "如被錦衣，晝行輝煌。", "侯曰上恩，曷敢弭忘。", "何以報之，俾民向方。", "言葺泮宮，於鄉有光。"]'),
('3b166424-0f10-4ff3-99cb-0e7372736706','慶梅州劉侯修葺程鄉學宮落成  其二','林陶','宋','宋诗','song-poetry','','[]','宣聖南面，珠旒衮章。',50,'全唐诗/poet.song.168000.json','["宣聖南面，珠旒衮章。", "十哲侑坐，羣賢繢廊。", "六齋分列，小學峙傍。", "談經議道，春祠秋嘗。", "我侯戾止，率由典常。"]'),
('ef821723-b93f-4881-8cdf-842c0af1b27a','慶梅州劉侯修葺程鄉學宮落成  其三','林陶','宋','宋诗','song-poetry','','[]','闇誾諸生，振鷺來翔。',50,'全唐诗/poet.song.168000.json','["闇誾諸生，振鷺來翔。", "詩書禮樂，游息修藏。", "勉爾行業，爲時俊良。", "毋毀於隨，毋嬉於荒。", "三歲大比，用賓於王。"]'),
('dc6c66f8-6cb5-4636-b0a3-dace9883d22f','六一堂','范令聞','宋','宋诗','song-poetry','','[]','□□□□法，□□□□□。',96,'全唐诗/poet.song.168000.json','["□□□□法，□□□□□。", "□□□□□，□□□雪人。", "□□□□照，□□江漢炳。", "靈□□物□，生五色虎□。", "□山□長□，□□□□□。", "□簡三□秩，滿□中□□。", "然囊衣度雲，棧□□□與。", "七賢□襁負，中□□金産。"]'),
('032f4fb2-c31e-4637-a0e7-848b6b94eb4a','楚公鷹','范令聞','宋','宋诗','song-poetry','','[]','與鷹寫真惟楚公，與公作歌惟老杜。',96,'全唐诗/poet.song.168000.json','["與鷹寫真惟楚公，與公作歌惟老杜。", "畫託此歌以不朽，至今人誦摶空句。", "相傳妙畫舊通靈，烏鵲不敢巢庭樹。", "饑未飽肉資遠擊，凜然戴角乃□顧。", "枯枝絕筆半已訛，飛鳥脫字無緣補。", "好事能來一賞音，不必移之在縑素。"]'),
('e6cee9dc-e6a9-47dd-b0a3-623ffac9ed11','回龍院','范令聞','宋','宋诗','song-poetry','','[]','柏人去弗宿，萬安退而止。',168,'全唐诗/poet.song.168000.json','["柏人去弗宿，萬安退而止。", "見幾懲貫高，噬臍嬖妃子。", "畏避雖同途，興亡乃異軌。", "江邊招提小，樓閣半傾圮。", "回薄二里餘，六龍駐於此。", "愁橫雲蓋山，悶繫羅带水。", "歷歷斜谷路，去天尺有咫。", "昨夜雨中鈴，哀音猶在耳。", "畫像赭衣袂，挾一弓兩矢。", "侑以聖雲孫，祖武略相似。", "劍外塵再蒙，黄明著年紀。", "今我弔陳迹，行邁亦靡靡。", "吹動波間皺，正值秋風起。", "安得如漁翁，垂釣江之涘。"]'),
('a65c4e4b-1bed-41f8-8779-0fbbbd1a95c6','褒公亭','范令聞','宋','宋诗','song-poetry','','[]','唐變租庸調之後，皇朝列聖踵□餘。',32,'全唐诗/poet.song.168000.json','["唐變租庸調之後，皇朝列聖踵□餘。", "□科若使猶仍舊，人到于今□奠居。"]'),
('53432629-2575-4da9-b678-b2ccfbfdd8ce','九女山','黄唐','宋','宋诗','song-poetry','','[]','粼粼新綠起前峯，拂拂垂楊煙雨中。',32,'全唐诗/poet.song.168000.json','["粼粼新綠起前峯，拂拂垂楊煙雨中。", "安得一簑浮短艇，玉鱗飛上釣絲風。"]'),
('2354ecec-49b2-418d-b1b5-73e14da80645','西谿湖散步','趙若盈','宋','宋诗','song-poetry','','[]','遠岫平林嶂夕陽，翻濤翠麥已蒸黄。',32,'全唐诗/poet.song.168000.json','["遠岫平林嶂夕陽，翻濤翠麥已蒸黄。", "此行莫謂無高興，題品新詩入錦囊。"]'),
('63bbcf2e-0071-450a-9d97-0f6ea73d8abf','大泉洞','趙若渚','宋','宋诗','song-poetry','','[]','通羊幾岩壑，茲洞如修航。',48,'全唐诗/poet.song.168000.json','["通羊幾岩壑，茲洞如修航。", "泉聲轟鼓激，澗氣侵衣涼。", "臨流網銀鯽，艤棹觴桂漿。", "此中有真趣，其樂良未央。"]'),
('6eceb72b-89bc-40c5-abe8-6c2363524eae','雙溪橋亭','趙孟禹','宋','宋诗','song-poetry','','[]','東溪西溪雙合流，鳬鳥鷗鳥相和鳴。',32,'全唐诗/poet.song.168000.json','["東溪西溪雙合流，鳬鳥鷗鳥相和鳴。", "斯景逼人描不得，滄浪一曲浣塵纓。"]'),
('dc9854ea-1e1e-4a18-bde8-46d0123bc810','經理西山同二客二弟姪輩侍太孺人游觀聯句','喻興之','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.168000.json','["無正文。"]'),
('fe476821-b7c6-4b74-9179-c84821ea8030','黄香橙','李𡉙','宋','宋诗','song-poetry','','[]','黄雲冉冉曉蒼蒼，閑倚平湖只自香。',32,'全唐诗/poet.song.168000.json','["黄雲冉冉曉蒼蒼，閑倚平湖只自香。", "較似寒梅雖未至，依然風韻挾風霜。"]'),
('a7186267-9a68-4736-9fa1-7734d0a44629','北園酌酒觀鶴','李𡉙','宋','宋诗','song-poetry','','[]','靜看瀺灂幾遊鱗，爭似玄裳縞袂春。',32,'全唐诗/poet.song.168000.json','["靜看瀺灂幾遊鱗，爭似玄裳縞袂春。", "幾度有書招不至，應慚側翅傍他人。"]'),
('ff88a2b2-a0c9-4f08-b3fb-df4e10ca990a','題清虛庵皇甫真人坦之隠居','李塾','宋','宋诗','song-poetry','','[]','寶墨光分眄禁春，超然晏坐寂怡神。',64,'全唐诗/poet.song.168000.json','["寶墨光分眄禁春，超然晏坐寂怡神。", "力辭漢殿從游樂，乞得康廬自在身。", "黄屋記曾參扈從，白衣猶憶指山人。", "恐虛立馬前宵夢，柱下無材忝世臣。"]'),
('7310b0d3-1239-4038-b7a6-268683415bb4','過寶應湖','呂存中','宋','宋诗','song-poetry','','[]','半升濁酒試蓴羹，賤買魚蝦已厭烹。',32,'全唐诗/poet.song.168000.json','["半升濁酒試蓴羹，賤買魚蝦已厭烹。", "淺水衣蒲有船過，淡煙籠月更人行。"]'),
('35c2f310-c457-4133-8a53-6ba420879fb0','九仙山','陳元通','宋','宋诗','song-poetry','','[]','九仙曾住九山頭，仙去山空歲月幽。',64,'全唐诗/poet.song.168000.json','["九仙曾住九山頭，仙去山空歲月幽。", "爲愛遍尋方外侶，乘閒便向洞前遊。", "蒼苔斷處蹤猶在，玉局殘來子未收。", "換骨丹砂應幾轉，吾生結得此緣不。"]'),
('3cf77f3a-0492-48f0-a9c8-12ca1356384f','五日登五華巖','陳元通','宋','宋诗','song-poetry','','[]','來此逢端午，山間薇蕨肥。',48,'全唐诗/poet.song.168000.json','["來此逢端午，山間薇蕨肥。", "盈虧看井脉，消息驗玄機。", "饑辦胡麻飯，寒供薜荔衣。", "俗緣今覺盡，纔到已忘歸。"]'),
('60bccae6-e4f2-49ac-a2c1-bb3219b022bd','丹崖','方士繇','宋','宋诗','song-poetry','','[]','丹崖石氣凝高秋，碧溪上引天河流。',83,'全唐诗/poet.song.168000.json','["丹崖石氣凝高秋，碧溪上引天河流。", "金堂石室不可到，玉棺莓苔生古愁。", "僊人昔乘紫雲去，白馬摇鞭在何處。", "茫茫塵世那得知，幔亭空記當年事。", "君不見茂林松柏已蕭疎，乾魚猶祭同亭祠。"]'),
('171a27e3-8077-4449-a827-c1c02a45dce3','竹','方士繇','宋','宋诗','song-poetry','','[]','鳳尾森森半已舒，玳文滴瀝畫難如。',32,'全唐诗/poet.song.168000.json','["鳳尾森森半已舒，玳文滴瀝畫難如。", "虛心不貯相思恨，還作風流向綺疏。"]'),
('7ab95d08-c713-49df-bcf0-768f04bcb214','鷄豚社','方士繇','宋','宋诗','song-poetry','','[]','稻葉青青水滿塍，夕陽林下賽田神。',32,'全唐诗/poet.song.168000.json','["稻葉青青水滿塍，夕陽林下賽田神。", "投身便入鷄豚社，老去人間懶問津。"]'),
('0aaabfa9-f164-4952-80a2-7407bd3eb27d','答故人','方士繇','宋','宋诗','song-poetry','','[]','天涯春色已平分，桃李陰陰晝掩門。',64,'全唐诗/poet.song.168000.json','["天涯春色已平分，桃李陰陰晝掩門。", "黄素久無人問字，綠醽時有客來樽。", "棲遲未嘆流光遠，寂寞還令此道存。", "珍重故人勤問訊，暮年憂樂任乾坤。"]'),
('ec4fbae1-338e-41a8-b1bc-f957a184fab8','崇安分水道中','方士繇','宋','宋诗','song-poetry','','[]','溪流清淺路橫斜，日暮牛羊自識家。',32,'全唐诗/poet.song.168000.json','["溪流清淺路橫斜，日暮牛羊自識家。", "梅葉陰陰桃李盡，春光已到白桐花。"]'),
('303f7816-3dbd-4f8b-8e0e-c0d0d648f957','寒棲館','方士繇','宋','宋诗','song-poetry','','[]','蒼崖凌絳霄，橫席坐高迥。',24,'全唐诗/poet.song.168000.json','["蒼崖凌絳霄，橫席坐高迥。", "遥夜聞吹簫，山空月華冷。"]'),
('8082efac-f05c-4b95-b5c4-52206a1ce409','偶成長句','方士繇','宋','宋诗','song-poetry','','[]','北風日日閉柴門，落盡梅花雨暗村。',64,'全唐诗/poet.song.168000.json','["北風日日閉柴門，落盡梅花雨暗村。", "虛閣留春宜夜永，寒爐撥火借春恩。", "貧知身外親交少，老覺人間歲月奔。", "空負平生江海意，只今心事與誰論。"]'),
('d4d121e8-6639-4f5c-9b5a-c17caca30b6b','昇山即事','方士繇','宋','宋诗','song-poetry','','[]','一徑西風裏，閑房客未歸。',48,'全唐诗/poet.song.168000.json','["一徑西風裏，閑房客未歸。", "砌苔侵野屐，林葉上秋衣。", "黄卷經心嬾，青綸入夢稀。", "還書報妻子，莫厭故山薇。"]'),
('37edb0fe-419c-494a-a742-05b907898a36','句  其一','方士繇','宋','宋诗','song-poetry','','[]','肯向淵明拚一醉，何妨乘興過籬東。',16,'全唐诗/poet.song.168000.json','["肯向淵明拚一醉，何妨乘興過籬東。"]'),
('dbd70142-d112-408f-8000-71a7c4ba83e3','句  其二','方士繇','宋','宋诗','song-poetry','','[]','幾酌碧筩陪笑詠。',8,'全唐诗/poet.song.168000.json','["幾酌碧筩陪笑詠。"]'),
('0f3b98a6-d449-4749-88fa-acf057f7ac8a','句  其三','方士繇','宋','宋诗','song-poetry','','[]','不復雲軿去自留，却憑飛鵲集中流。',16,'全唐诗/poet.song.168000.json','["不復雲軿去自留，却憑飛鵲集中流。"]'),
('32f83cf9-e74a-4aae-bef4-0a47b0a0ea2e','句  其四','方士繇','宋','宋诗','song-poetry','','[]','流連兒女意，香滿曝衣樓。',12,'全唐诗/poet.song.168000.json','["流連兒女意，香滿曝衣樓。"]'),
('5febb304-f345-44a5-97d8-5fed1da52435','手影戲','釋惠明','宋','宋诗','song-poetry','','[]','三尺生綃作戲臺，全憑十指逞詼諧。',32,'全唐诗/poet.song.168000.json','["三尺生綃作戲臺，全憑十指逞詼諧。", "有時明月燈窗下，一笑還從掌握來。"]'),
('8dd7c912-0dd7-403d-a51c-7bda927c2948','詠菖蒲','釋惠明','宋','宋诗','song-poetry','','[]','根下塵泥一點無，性便泉石愛清孤。',32,'全唐诗/poet.song.168000.json','["根下塵泥一點無，性便泉石愛清孤。", "當時不惹湘江恨，葉葉如何有淚珠。"]'),
('5d4c3824-4e77-4b59-8f0d-7c456e41c468','偈頌八首  其一','釋宗印','宋','宋诗','song-poetry','','[]','二由一有，一亦莫守，平地上死人無數。',56,'全唐诗/poet.song.168000.json','["二由一有，一亦莫守，平地上死人無數。", "一心不生，萬法無咎，屎窖裏頭出頭沒。", "孤迥迥，峭巍巍。", "花須連夜發，莫待曉風吹。"]'),
('c49fb00d-748b-47da-bb50-0d8c88dfac75','偈頌八首  其二','釋宗印','宋','宋诗','song-poetry','','[]','春山青，春水綠，春風包裹無纖粟。',44,'全唐诗/poet.song.168000.json','["春山青，春水綠，春風包裹無纖粟。", "目前事，量外機，東村王老暗攢眉。", "暗攢眉，獨脚山魈舞柘枝。"]'),
('bc1b124d-dc5e-4027-85f2-0d2261f7bfd4','偈頌八首  其三','釋宗印','宋','宋诗','song-poetry','','[]','不用不用，千聖不共。',46,'全唐诗/poet.song.168000.json','["不用不用，千聖不共。", "如是如是，蝮蝎蛇虺。", "不是不是，徹骨徹髓。", "進前退後遶禪牀，掣電之機落二三。"]'),
('43d7266c-f5b4-4797-8e4a-1036e9d2fa7e','偈頌八首  其四','釋宗印','宋','宋诗','song-poetry','','[]','鐵崑崙兒喫一攧，南海波斯舞不徹。',32,'全唐诗/poet.song.168000.json','["鐵崑崙兒喫一攧，南海波斯舞不徹。", "夜半失却攔腰帛，笑倒東村王大伯。"]'),
('51502de9-c64b-40ab-9f54-0bb568f44251','偈頌八首  其五','釋宗印','宋','宋诗','song-poetry','','[]','通身畫錦赤骨力，賣扇老婆手遮日。',48,'全唐诗/poet.song.168000.json','["通身畫錦赤骨力，賣扇老婆手遮日。", "無手人，一拳是一拳。", "無足漢，一踢是一踢。", "阿呵呵，九九元來八十一。"]'),
('8271783f-5a09-4de7-aa5b-41e7088ee445','偈頌八首  其六','釋宗印','宋','宋诗','song-poetry','','[]','平如鏡，嶮如崖。',40,'全唐诗/poet.song.168000.json','["平如鏡，嶮如崖。", "擬即失，動即乖。", "不擬不動自纏縛，別有生機掘地埋。", "雲門親見陳蒲鞋。"]'),
('2276f9a1-08b4-4cd0-9af8-91700b41a6e6','偈頌八首  其七','釋宗印','宋','宋诗','song-poetry','','[]','多子塔前，風行草偃。',58,'全唐诗/poet.song.168000.json','["多子塔前，風行草偃。", "育王門下，正令重行。", "掀翻舊日規模，從教佛祖乞命。", "不是第一句，亦非格外機。", "寸釘才入木，遍界火星飛。"]'),
('5850d91e-9f91-4606-80ee-651e66e48109','偈頌八首  其八','釋宗印','宋','宋诗','song-poetry','','[]','路見不平，拔劍相助。',20,'全唐诗/poet.song.168000.json','["路見不平，拔劍相助。", "傷鱉如龜，必應有主。"]'),
('7ff0f63c-5ef7-414d-982b-2730444189e5','頌古三首  其一','釋宗印','宋','宋诗','song-poetry','','[]','死人眼，死人手。',41,'全唐诗/poet.song.168000.json','["死人眼，死人手。", "金烏飛，玉兔走。", "直截根源，取之左右。", "張翁醉倒官街，元是李翁喫私酒。"]'),
('b2e55e89-973a-49d7-9653-4b084c13ce3e','頌古三首  其二','釋宗印','宋','宋诗','song-poetry','','[]','一畝之地，三蛇九鼠。',20,'全唐诗/poet.song.168000.json','["一畝之地，三蛇九鼠。", "物是定價，錢是足數。"]'),
('b25e36f1-38f8-41c5-a6d5-07a5ad5d825b','頌古三首  其三','釋宗印','宋','宋诗','song-poetry','','[]','不如隨分納些些，喚作平常事已差。',32,'全唐诗/poet.song.168000.json','["不如隨分納些些，喚作平常事已差。", "綠草溪邊頭角露，一簑烟雨屬誰家。"]'),
('74ab51a7-e6e8-41a2-96ee-5f915a53a2bf','偈頌四首  其一','釋道濟','宋','宋诗','song-poetry','','[]','一手動時千手動，一眼觀時千眼觀。',32,'全唐诗/poet.song.168000.json','["一手動時千手動，一眼觀時千眼觀。", "既是名爲觀自在，何須拈弄幾多般。"]'),
('20448c6e-0044-4c6f-bed1-baa790bf0bd7','偈頌四首  其二','釋道濟','宋','宋诗','song-poetry','','[]','背倚寒岩，面如滿月。',20,'全唐诗/poet.song.168000.json','["背倚寒岩，面如滿月。", "盡大地人，只見半截。"]'),
('aeb8945c-1305-437c-be82-747ee682b61d','偈頌四首  其三','釋道濟','宋','宋诗','song-poetry','','[]','一塊兩塊，佛也不怪。',30,'全唐诗/poet.song.168000.json','["一塊兩塊，佛也不怪。", "一醒兩醒，佛也不嗔。", "一碗兩碗，佛也不管。"]'),
('e65b71c5-b8a6-428f-b6bc-7bc3ea3caf02','偈頌四首  其四','釋道濟','宋','宋诗','song-poetry','','[]','小黄碗內幾星麩，半是酸虀半是瓠。',32,'全唐诗/poet.song.168000.json','["小黄碗內幾星麩，半是酸虀半是瓠。", "誓不出生違佛教，出生之後碗中無。"]'),
('f75e66d3-fff2-40b5-890d-479c7a27640b','與沈五官李提點飲酒席間作七首  其一','釋道濟','宋','宋诗','song-poetry','','[]','慣會饕齋覓主人，身邊零鈔沒分文。',32,'全唐诗/poet.song.168000.json','["慣會饕齋覓主人，身邊零鈔沒分文。", "誰知撞見真經紀，不遇檀那怎脫身。"]'),
('c9b675a2-34bc-4849-9f7b-3781e2abc84f','與沈五官李提點飲酒席間作七首  其二','釋道濟','宋','宋诗','song-poetry','','[]','平生只愛呷黄湯，數日無錢買得嘗。',32,'全唐诗/poet.song.168000.json','["平生只愛呷黄湯，數日無錢買得嘗。", "今幸見君君莫阻，再求幾碗潤枯腸。"]'),
('c0da6ea3-724c-4a8a-99cd-a6722dd4fc75','與沈五官李提點飲酒席間作七首  其三','釋道濟','宋','宋诗','song-poetry','','[]','昔日曾聞李謫仙，飲酒一斗詩百篇。',32,'全唐诗/poet.song.168000.json','["昔日曾聞李謫仙，飲酒一斗詩百篇。", "感君慨賜無慳吝，貧衲何嘗出口涎。"]'),
('eca71926-51a7-4382-9ff3-3eac81743a28','與沈五官李提點飲酒席間作七首  其四','釋道濟','宋','宋诗','song-poetry','','[]','自來酒量無拘管，惟有窮坑填不滿。',32,'全唐诗/poet.song.168000.json','["自來酒量無拘管，惟有窮坑填不滿。", "要同畢卓卧缸邊，告君再覓三十碗。"]'),
('f2d99c97-6869-43ec-b678-74766d725d9c','與沈五官李提點飲酒席間作七首  其五','釋道濟','宋','宋诗','song-poetry','','[]','每日貪盃又宿娼，風流和尚豈尋常。',32,'全唐诗/poet.song.168000.json','["每日貪盃又宿娼，風流和尚豈尋常。", "袈裟常被胭脂染，直裰時聞膩粉香。"]'),
('b7374bcf-02d9-4dc3-8a7d-338179bc425f','與沈五官李提點飲酒席間作七首  其六','釋道濟','宋','宋诗','song-poetry','','[]','滿庫瓊芳鬭色鮮，就中一朵最堪憐。',32,'全唐诗/poet.song.168000.json','["滿庫瓊芳鬭色鮮，就中一朵最堪憐。", "恁伊萬種風流態，惟有禪心似鐵堅。"]'),
('44c62f89-955a-46fb-a9e4-fdf3d25c9f02','與沈五官李提點飲酒席間作七首  其七','釋道濟','宋','宋诗','song-poetry','','[]','昔我父娘作此態，生我這箇臭皮袋。',32,'全唐诗/poet.song.168000.json','["昔我父娘作此態，生我這箇臭皮袋。", "我心不比父娘心，我心除酒都不愛。"]'),
('95ea2243-6e5e-43be-b310-d2487eb14546','宿劉行首家作二首  其一','釋道濟','宋','宋诗','song-poetry','','[]','暫假夫妻一宿眠，禪心淫慾不相連。',32,'全唐诗/poet.song.168000.json','["暫假夫妻一宿眠，禪心淫慾不相連。", "昨宵姑順君台意，多與虔婆五貫錢。"]'),
('64045c11-6290-45c9-b99f-a158959b15cf','宿劉行首家作二首  其二','釋道濟','宋','宋诗','song-poetry','','[]','從來諸事不相關，獨有香醪真箇貪。',32,'全唐诗/poet.song.168000.json','["從來諸事不相關，獨有香醪真箇貪。", "清早若無三碗酒，怎禁門外朔風寒。"]'),
('d853b14c-54d6-4682-ad6f-343b65e6f985','題洗馬池','釋道濟','宋','宋诗','song-poetry','','[]','昔日曾聞洗馬池，悠然此景在西溪。',64,'全唐诗/poet.song.168000.json','["昔日曾聞洗馬池，悠然此景在西溪。", "風生水面波紋細，日上堤邊樹影低。", "水底青天沉翡翠，波中明月浸琉璃。", "何如花下退朝去，喜看鴛鴦戲石磯。"]'),
('f0691706-a30d-43e9-b794-77526aa96a69','寧棘庵講主失竊','釋道濟','宋','宋诗','song-poetry','','[]','啞喫黄瓜苦自知，將絲就縱落人機。',64,'全唐诗/poet.song.168000.json','["啞喫黄瓜苦自知，將絲就縱落人機。", "低田缺水遭天旱，古菓安身著鬼迷。", "賊去關門無物了，病深服藥請醫遲。", "竹筒種火空長炭，夜半描龍畫向誰。"]'),
('b3cc4cd5-5e29-4986-a0c6-3b315c2ed077','嘲靈隠寺印鐵牛','釋道濟','宋','宋诗','song-poetry','','[]','幾百年來靈隠寺，如今却被鐵牛閂。',64,'全唐诗/poet.song.168000.json','["幾百年來靈隠寺，如今却被鐵牛閂。", "蹄中有漏難耕種，鼻孔撩天不受穿。", "道眼何如馿眼瞎，寺門常似獄門關。", "冷泉有水無鷗鷺，空使留名在世間。"]'),
('73bd7633-1555-4738-8343-9dac6e04e199','題靈隠寺西堂粉壁','釋道濟','宋','宋诗','song-poetry','','[]','小小庵兒小小窗，小小房兒小小床。',32,'全唐诗/poet.song.168000.json','["小小庵兒小小窗，小小房兒小小床。", "出入小童并小行，小心伏事小西堂。"]'),
('391e04cd-92a7-4d70-ae55-71f857b7d0c6','諷阻臨安趙府尹伐凈慈寺門松  其一','釋道濟','宋','宋诗','song-poetry','','[]','亭亭百尺接天高，曾與山僧作故交。',64,'全唐诗/poet.song.168000.json','["亭亭百尺接天高，曾與山僧作故交。", "滿望枝柯千載茂，可憐刀斧一齊拋。", "窗前不覩龍蛇影，耳畔無聞風雨號。", "最苦早間飛去鶴，晚回不見舊時巢。"]'),
('d07693db-aba4-4cae-9945-9dd2acb45b68','諷阻臨安趙府尹伐凈慈寺門松  其二','釋道濟','宋','宋诗','song-poetry','','[]','白石磷磷積翠嵐，翠嵐深處結茅庵。',64,'全唐诗/poet.song.168000.json','["白石磷磷積翠嵐，翠嵐深處結茅庵。", "煮茶迎客月當戶，採藥出門雲滿籃。", "琴掛葛絃鳴素志，窗開風拂罷清談。", "今朝偶識東坡老，四大皆空不用參。"]'),
('0c48dc90-21bb-4363-b273-8837d20cdd5b','酒醉後作','釋道濟','宋','宋诗','song-poetry','','[]','本是修來四果身，風顛作逞混凡人。',68,'全唐诗/poet.song.168000.json','["本是修來四果身，風顛作逞混凡人。", "能施三昧神通力，便指凡人出世津。", "經卷無心看，禪機有意親，醉時喝佛罵天真。", "渾身不見些兒好，一點靈光絕勝人。"]'),
('201a7d11-7776-4d52-ab3a-28f93f31dea1','浄慈寺火災','釋道濟','宋','宋诗','song-poetry','','[]','無名一點起逡巡，大厦千間盡作塵。',32,'全唐诗/poet.song.168000.json','["無名一點起逡巡，大厦千間盡作塵。", "非是我佛不靈感，故要樓臺一度新。"]'),
('1a32b188-8e36-4716-ab90-218cd6f7312c','與常長老飲酒席間作','釋道濟','宋','宋诗','song-poetry','','[]','極目烟波遠接天，紅塵疎處結三椽。',64,'全唐诗/poet.song.168000.json','["極目烟波遠接天，紅塵疎處結三椽。", "不憂風景來朝沒，只恐水雲到晚連。", "青黛山邊飛白鷺，綠楊堤畔泊漁船。", "悠然此地真堪樂，半是人間半是仙。"]'),
('a3e2e4fe-a069-410b-abb8-a745962df255','餛飩','釋道濟','宋','宋诗','song-poetry','','[]','包羅萬象，性氣粗豪。',68,'全唐诗/poet.song.168000.json','["包羅萬象，性氣粗豪。", "清浄爲根，禮恭叉手。", "通身上縫隙無餘，鑊湯裏倒番觔斗。", "把得定橫吞豎吞，把不定東走西走。", "宜是山僧嚼破時，泥牛滿地頻哮吼。"]'),
('64343a91-0e5e-4754-ae13-2e7c3b5c2e31','爲救一後生作','釋道濟','宋','宋诗','song-poetry','','[]','後生後生，忽犯天嗔。',40,'全唐诗/poet.song.168000.json','["後生後生，忽犯天嗔。", "前生惡業，今生縹身。", "老僧救汝，歸奉母親。", "諸惡莫作，免得禍臨。"]'),
('6c10f933-57e7-4ccf-bcf5-4364ce819c1c','影壁自贊','釋道濟','宋','宋诗','song-poetry','','[]','面黄以蠟，骨瘦如柴。',34,'全唐诗/poet.song.168000.json','["面黄以蠟，骨瘦如柴。", "這般模樣，只好投齋。", "也有些兒差異，說禪不用安排。"]'),
('ae353771-e3a5-4361-b952-257aa6fffe02','呈馮太尉','釋道濟','宋','宋诗','song-poetry','','[]','削髮披緇已有年，只同詩酒是姻緣。',64,'全唐诗/poet.song.168000.json','["削髮披緇已有年，只同詩酒是姻緣。", "閙看彌勒空中戲，困向毗盧頂上眠。", "撒手便能欺十聖，低頭端不顧三賢。", "茫茫宇宙無人識，猶道顛僧遶市廛。"]'),
('6aa675e9-d983-4c26-872c-2b0960188de8','真像沈提點求贊','釋道濟','宋','宋诗','song-poetry','','[]','遠看不是，近看不像。',112,'全唐诗/poet.song.168000.json','["遠看不是，近看不像。", "費盡許多工夫，畫出這般模樣。", "眉如掃箒，一張大口。", "不會非言，只會喫酒。", "看看白頭，常常赤脚。", "有色無心，有染無著。", "醉眠不管江海波，渾身藍縷害風魔。", "桃花柳葉無心戀，月白風清笑與歌。", "倒騎馿子歸天嶺，釣月耕雲自琢磨。"]'),
('35d214db-715d-41d5-b22d-3abbff9ec709','與張提點共飲席間作','釋道濟','宋','宋诗','song-poetry','','[]','每日終朝醉似泥，未嘗一日不昏迷。',85,'全唐诗/poet.song.168000.json','["每日終朝醉似泥，未嘗一日不昏迷。", "細君發怒將言罵，道是人間喫酒兒。", "莫要管，你休癡，人生能有幾多時。", "杜康曾唱蓮花落，劉伶好飲舞囉哩，陶淵明賞菊醉東籬。", "今日皆歸去，留得好名兒。"]'),
('553d4081-9350-4a6f-b793-3bad266a11d4','湖中夕泛歸南屏四絕  其一','釋道濟','宋','宋诗','song-poetry','','["\u897f\u6e56"]','幾度西湖獨上船，篙師識我不論錢。',32,'全唐诗/poet.song.168000.json','["幾度西湖獨上船，篙師識我不論錢。", "一聲啼鳥破幽寂，正是山橫落照邊。"]'),
('a1a8f94e-fabe-4963-a0f0-fb157e750152','湖中夕泛歸南屏四絕  其二','釋道濟','宋','宋诗','song-poetry','','[]','湖上春光已破慳，湖邊楊柳拂雕闌。',32,'全唐诗/poet.song.168000.json','["湖上春光已破慳，湖邊楊柳拂雕闌。", "算來不用一文買，輸與山僧閑往還。"]'),
('fa8ab01c-215f-48f3-b351-8554e5e29f92','湖中夕泛歸南屏四絕  其三','釋道濟','宋','宋诗','song-poetry','','[]','出岸桃花紅錦英，夾堤楊柳綠絲輕。',32,'全唐诗/poet.song.168000.json','["出岸桃花紅錦英，夾堤楊柳綠絲輕。", "遥看白鷺窺魚處，衝破平湖一點青。"]'),
('8b6f3c22-1726-407e-ba7d-a0549591e343','湖中夕泛歸南屏四絕  其四','釋道濟','宋','宋诗','song-poetry','','["\u897f\u6e56"]','五月西湖凉似秋，新荷吐蕊暗香浮。',32,'全唐诗/poet.song.168000.json','["五月西湖凉似秋，新荷吐蕊暗香浮。", "明年花落人何在，把酒問花花點頭。"]'),
('ef631a42-87dc-4bef-807f-4559faf6c658','海螄頌','釋道濟','宋','宋诗','song-poetry','','[]','此物生在東海西，又無鱗甲又無衣。',32,'全唐诗/poet.song.168000.json','["此物生在東海西，又無鱗甲又無衣。", "雖然不入紅羅帳，常與佳人做嘴兒。"]'),
('690ada12-1db6-42bb-835a-8e000c1ed90e','雨傘','釋道濟','宋','宋诗','song-poetry','','[]','一竿翠竹，巧匠批欒。',56,'全唐诗/poet.song.168000.json','["一竿翠竹，巧匠批欒。", "條條有眼，節節皆穿。", "四大假合，柄在人手。", "歸家放下，並不爭先。", "直饒甕瀉盆傾下，一搭權爲不漏天。"]'),
('37148439-1e39-4d6d-99d6-d4475b6afd90','聞王媽媽家做小祥功德作二首  其一','釋道濟','宋','宋诗','song-poetry','','[]','唐家閧里閑遊賞，媽媽家中請和尚。',32,'全唐诗/poet.song.168000.json','["唐家閧里閑遊賞，媽媽家中請和尚。", "三百襯錢五味食，羊毛出在羊身上。"]'),
('a43fec7b-c852-4c72-9b10-7d2ee0e59d33','聞王媽媽家做小祥功德作二首  其二','釋道濟','宋','宋诗','song-poetry','','[]','媽媽好善結良緣，齋僧不論聖和凡。',32,'全唐诗/poet.song.168000.json','["媽媽好善結良緣，齋僧不論聖和凡。", "經資齋襯明捨施，少間暗裏送來還。"]'),
('e4b0821d-4044-44ea-8de5-19e0135ec22f','墨竹','釋道濟','宋','宋诗','song-poetry','','[]','數枝淡竹翠生光，一點無塵自有香。',32,'全唐诗/poet.song.168000.json','["數枝淡竹翠生光，一點無塵自有香。", "好似葛陂龍化後，却留清影在虛堂。"]'),
('6fc379b5-483e-439f-b26c-bb7b6aec0b21','題壁','釋道濟','宋','宋诗','song-poetry','','[]','你家醤一缸，內有毒蛇藏。',24,'全唐诗/poet.song.168000.json','["你家醤一缸，內有毒蛇藏。", "若無老僧說，人口俱被傷。"]'),
('75678876-c322-4f55-9b32-2e7f90e4adf0','扇畫','釋道濟','宋','宋诗','song-poetry','','[]','一枝風柳一蟬鳴，畫出規模宛似生。',32,'全唐诗/poet.song.168000.json','["一枝風柳一蟬鳴，畫出規模宛似生。", "莫謂其中絕音響，報君消息甚分明。"]'),
('0aa431fc-6af5-4aab-bf18-026d016123ab','弟子求衣鉢','釋道濟','宋','宋诗','song-poetry','','[]','來時無一物，去時無一物。',24,'全唐诗/poet.song.168000.json','["來時無一物，去時無一物。", "若要我衣鉢，兩箇光卵核。"]'),
('f33dbe49-d792-4664-b28e-4c3fa840a119','辭世頌','釋道濟','宋','宋诗','song-poetry','','[]','六十年來狼藉，東壁打到西壁。',28,'全唐诗/poet.song.168000.json','["六十年來狼藉，東壁打到西壁。", "如今收拾歸來，依舊水連天碧。"]'),
('18070aad-c15e-4219-9434-b641bce84f0a','寂後寄少林長老二首  其一','釋道濟','宋','宋诗','song-poetry','','[]','片帆飛過浙江東，回首樓臺渺漠中。',32,'全唐诗/poet.song.168000.json','["片帆飛過浙江東，回首樓臺渺漠中。", "傳與諸山詩酒客，休將有限恨無窮。"]'),
('cca2e9e0-9dd8-4048-8bed-1788d3f2af21','寂後寄少林長老二首  其二','釋道濟','宋','宋诗','song-poetry','','[]','脚絣緊繫興無窮，拄杖挑雲入亂峯。',32,'全唐诗/poet.song.168000.json','["脚絣緊繫興無窮，拄杖挑雲入亂峯。", "欲識老僧行履處，天台南岳舊家風。"]'),
('6389809e-69bb-45cc-b887-76d5a97ddde9','題玉泉','釋道濟','宋','宋诗','song-poetry','','[]','千章老木冷涵秋，今日重來話舊游。',144,'全唐诗/poet.song.168000.json','["千章老木冷涵秋，今日重來話舊游。", "一池寒水浸虛碧，清光瑩澈凝不流。", "中有神龍隠頭角，爲雨爲霖滋旱涸。", "聖主垂衣風雨調，龍亦安眠在丘壑。", "人來初不覩真龍，但見金鯽浮沈中。", "昂頭擺尾得其所，我疑便是池中龍。", "殷勤一語龍聽取，汝以何緣墮龍伍。", "良由一念嗔所生，畢竟難逃鱗甲苦。", "驀然直下便回光，願力資深福寰宇。"]'),
('cb508823-c465-4348-8e01-6187c3e2eba2','頌古四首','釋道濟','宋','宋诗','song-poetry','','[]','道冠儒履釋袈裟，和會三家作一家。',32,'全唐诗/poet.song.168000.json','["道冠儒履釋袈裟，和會三家作一家。", "忘却率陀天上路，雙林端坐待龍華。"]'),
('94d30726-ef5c-4d19-b13b-64b9a51c8574','維摩居士示疾毗耶離城  其一','釋道濟','宋','宋诗','song-poetry','','[]','一箇病維摩，無風自起波。',24,'全唐诗/poet.song.168000.json','["一箇病維摩，無風自起波。", "富嫌千口少，貧恨一身多。"]'),
('b9821ebd-ba16-4ecc-94eb-a945cfe8e57c','維摩居士示疾毗耶離城  其二','釋道濟','宋','宋诗','song-poetry','','[]','不契梁王暗渡江，一身無地避慚惶。',32,'全唐诗/poet.song.168000.json','["不契梁王暗渡江，一身無地避慚惶。", "九年面壁成何事，賺却平人入鑊湯。"]'),
('8d3d748b-01c0-4707-909b-ba0706d2fe21','維摩居士示疾毗耶離城  其三','釋道濟','宋','宋诗','song-poetry','','[]','元是黄梅舊日僧，事師年老氣彌增。',64,'全唐诗/poet.song.168000.json','["元是黄梅舊日僧，事師年老氣彌增。", "翻身颺下栽松钁，轉步來分照世燈。", "皮袋假於溪畔女，衣盂付與嶺南能。", "佳聲籍籍能長久，雨過淮山碧萬層。"]'),
('b6c0e7c6-c45f-4a5d-b09f-0b3a0cc9c9b4','游洞霄','釋道濟','宋','宋诗','song-poetry','','[]','平明發餘杭，扁舟泝清流。',192,'全唐诗/poet.song.168000.json','["平明發餘杭，扁舟泝清流。", "登岸五六里，小逕穿林丘。", "奇峯聳天柱，九鎖巖谷幽。", "雲根立仙館，勝處非人謀。", "入門氣象雄，金碧欺兩眸。", "彈棊古松下，啼鳥聲相酬。", "羽衣讀黄庭，內景宜自修。", "蓬萊隔弱水，九轉即可求。", "坡翁昔賦詩，刻石記舊游。", "溪山增偉觀，萬古傳不休。", "我來弔陳迹，枯腸怯冥搜。", "執炬入大滌，襟袖寒颼颼。", "懸崖石乳滴，千歲無人收。", "樵夫指巖窟，此處通龍湫。", "方期過東洞，紅日驚西投。", "徘徊出山去，空使猿鶴愁。"]'),
('a259d349-c648-4888-ba3f-5f016fd71dca','詩一首','釋道濟','宋','宋诗','song-poetry','','["\u897f\u6e56"]','何須林景勝瀟湘，只願西湖化爲酒。',32,'全唐诗/poet.song.168000.json','["何須林景勝瀟湘，只願西湖化爲酒。", "和身卧倒西湖邊，一浪來時吞一口。"]'),
('e7ac5aa4-4673-48e5-85aa-aca60f187cb6','九里松','釋道濟','宋','宋诗','song-poetry','','[]','九里松陰路，青泉映白沙。',24,'全唐诗/poet.song.168000.json','["九里松陰路，青泉映白沙。", "誰知三伏暑，小草有幽花。"]'),
('ee82163f-7aeb-47e3-925c-3067e7b04b3d','句','釋道濟','宋','宋诗','song-poetry','','[]','藕荷無數滿沙洲。',8,'全唐诗/poet.song.168000.json','["藕荷無數滿沙洲。"]'),
('ad18953b-55a7-4169-9a1e-f47576dc8921','古意二首  其一','王阮','宋','宋诗','song-poetry','','[]','西風策策翻葉鳴，錦機停梭人暗驚。',32,'全唐诗/poet.song.168000.json','["西風策策翻葉鳴，錦機停梭人暗驚。", "歸心欲附潮頭去，潮頭不肯到湓城。"]'),
('883590eb-05ab-47c4-a48c-de39446ed344','古意二首  其二','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭九月湖水乾，倒影夜瞰星斗攢。',32,'全唐诗/poet.song.168000.json','["洞庭九月湖水乾，倒影夜瞰星斗攢。", "水官籋浪蹴寒玉，船過兩耳聲珊珊。"]'),
('d8e914c0-0e3b-420b-84b6-5db4b4318d13','明妃曲一首','王阮','宋','宋诗','song-poetry','','[]','胡塵漠漠風捲沙，明妃馬上彈琵琶。',147,'全唐诗/poet.song.168000.json','["胡塵漠漠風捲沙，明妃馬上彈琵琶。", "琵琶一曲思歸譜，明妃淚盡胡兒舞。", "胡兒不道思歸苦，更問漢宮餘幾許。", "古來和戎人似鐵，漢家和戎人似雪。", "午窗一抹春山橫，萬里關河不須設。", "燕支帳寒秋復春，翠被不禁愁殺人。", "人生不可無黄金，無黄金兮死沉淪。", "明妃也莫怨青塚，死有佳名生有用。", "君不見秦樓當日卷衣女，一一空隨宿草腐。"]'),
('d1a20e32-d097-442c-8c00-dec73e089048','續湖陰曲一首','王阮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','上林鳴蛙私邪官，金陵指顧成長安。',160,'全唐诗/poet.song.168000.json','["上林鳴蛙私邪官，金陵指顧成長安。", "唾壺一曲玉如意，聲斷石城鋒鏑寒。", "從來龍化中興主，不似黄鬚阿奴武。", "當時斬鞅心下事，今日揚鞭目中虜。", "黄埃散漫重瞳微，雨師不灑疑人知。", "夢回日轉驚已午，馬驕風疾那容追。", "一聲吉語禁門靜，萬國笙歌丹仗整。", "山傾海動忽燃臍，地闢天開誰問鼎。", "長江千里真險哉，煌煌晉業流秦淮。", "江濤一洗妖氛息，湖陰千古琉璃碧。"]'),
('99e088bd-e17f-46fa-9a45-65198cd87b5b','代胡倉進聖德惠民詩一首','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','平楚皆膏壤，成湯忽旱年。',288,'全唐诗/poet.song.168000.json','["平楚皆膏壤，成湯忽旱年。", "人知聖慮切，恩遣使臣宣。", "乙卯饑荒後，長沙富庶全。", "紀年四十載，斗米二三錢。", "縣縣人煙密，村村景物妍。", "朱蹄驕柳陌，金鐙麗花鈿。", "習此民成懶，加之吏不虔。", "力耕終苟且，勸課或遷延。", "綠野田多曠，潢池惡未悛。", "曷嘗修稼政，但見飾賓筵。", "豐稔時難保，盈虛理有還。", "自應成赤地，安得咎蒼天。", "義廩真良法，皇家以備先。", "積倉何止萬，存數僅餘千。", "濫以疏庸迹，來司歛散權。", "一身初抵此，四顧但茫然。", "奏發常平弊，財蒙內帑捐。", "敢云呈敏手，幸免奮空拳。", "蔑問秦輸閉，專稽稷懋遷。", "陸修流馬運，水作汎舟連。", "凡屬災傷事，深將利害研。", "兼并勤告諭，商旅漸喧闐。", "市直雖翔踴，官收却痛蠲。", "北來因鼎粟，南至出渠船。"]'),
('21beec04-ad38-4f12-b59b-29f5b83b826b','上九江唐舍人一首五十韻','王阮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','江左承南渡，潯陽控上流。',288,'全唐诗/poet.song.168000.json','["江左承南渡，潯陽控上流。", "平時稱用武，今日更防秋。", "六代規摹古，三江險阨周。", "高憑隆屏翰，下瞰握襟喉。", "呼吸聞吳楚，封疆矗斗牛。", "循良渡虎跡，神武射蛟遊。", "勝事餘蓮社，風光足庾樓。", "倚天開峻極，倒影湛飛浮。", "鼎敗香山徃，官輕靖節休。", "義門十世美，將業二王優。", "頃歲承平久，斯民習俗修。", "究心依學校，服力事田疇。", "獄凈苔荒砌，山深麥掛丘。", "共知忠義篤，肯陷矯誣羞。", "不料腥羶起，能令日月幽。", "雲屯滿赤縣，天意卒鴻溝。", "郡邑生荆棘，江湖識冕旒。", "竟捐形勢地，聚作虎狼陬。", "昔計何勝辱，群生亦暫偷。", "奇功思赫赫，內治頗悠悠。", "法令中間弊，流移不可留。", "未經真撫恤，還已困虔劉。", "對壘緣淮甸，長蛇致虜酋。", "雷聲忽天狗，旗尾又蚩尤。"]'),
('700cadde-ba3f-4047-ae94-2112eddce096','瑞麥謠一首','王阮','宋','宋诗','song-poetry','','[]','稗草化稻疑談空，我有異麥真年豐。',264,'全唐诗/poet.song.168000.json','["稗草化稻疑談空，我有異麥真年豐。", "三歧鼎足如爭雄，兩歧對秀攢眉峯。", "棣華英粲花影重，黄雲列陣翻春風。", "問此厥初何所從，塗山之陽一牧童。", "手持足接復一翁，三十八雙來無窮。", "慶元道大天下公，漸漸擢芒瑞時雍。", "不生內地生邊封，天以德致驚諸戎。", "周家之始西徂東，彼疆爲密此界崇。", "已而率育四海同，帝命盖自貽牟通。", "漁陽昔當漢之隆，亦有此瑞堪形容。", "氓謠不上甘泉宮，私以譽守疑非恭。", "濠梁獻祥不一逢，一生二生重熙中。", "今年分外佳氣濃，疆吏豈敢貪天功。", "歸禾擬奏區區忠，仄聞聖德方謙沖。", "班春于郊但勸農，諭以種麥莫懶慵。", "大麥更戒細細舂，明年從駕巡崆峒，此飯要到滹沱供。"]'),
('bae11ccc-f884-4a79-a76f-9ba353dc5ad3','和陶詩六首 和歸田園','王阮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','皇天亦愛我，生我匡廬山。',120,'全唐诗/poet.song.168000.json','["皇天亦愛我，生我匡廬山。", "勉承父母志，功名期少年。", "既無取日手，遠去窮虞淵。", "又無謀生才，廣有負郭田。", "富貴兩不諧，胡爲乎世間。", "眷言旉原居，宛在瀑布前。", "野曠易得月，谷虛常带煙。", "行歌紫芝曲，醉上香爐巔。", "念此百年身，有此足以閑。", "若乃不決去，使彼山悽然。"]'),
('f10860d5-1f34-4636-b1a4-f642c881ecd2','和陶詩六首 和飲酒','王阮','宋','宋诗','song-poetry','','[]','竹門固無鎖，俗客自不開。',96,'全唐诗/poet.song.168000.json','["竹門固無鎖，俗客自不開。", "而欲挾彼態，使我變所懷。", "鄉原善同俗，於德則有乖。", "乃知違世人，所貴在幽栖。", "客有愛我甚，命駕來衝泥。", "憐我與俗異，欲我與世諧。", "甚知客言是，甚知余心迷。", "淵明飲酒詩，賡以遺客回。"]'),
('26351e60-24f5-4fb0-85c4-d08c8359d163','和陶詩六首 和乞食','王阮','宋','宋诗','song-poetry','','[]','淮陰漂母事，不謂身見之。',84,'全唐诗/poet.song.168000.json','["淮陰漂母事，不謂身見之。", "長歌淵明詩，益信非虛辭。", "嗟余客長安，十載無休期。", "一飽不自足，况敢謀酒巵。", "曳裾富兒門，丐食酬一詩。", "達于公卿間，喧喧謂余非。", "雖知責我至，終亦無所貽。"]'),
('9ec2bb33-26f1-445b-a1b2-b6cb24cf44ab','和陶詩六首 和貧士','王阮','宋','宋诗','song-poetry','','[]','吾聞戴安道，不對王侯琴。',72,'全唐诗/poet.song.168000.json','["吾聞戴安道，不對王侯琴。", "當時豈不能，低眉求賞音。", "一曲朝得聞，千金夕來尋。", "捨之不肯顧，輕重得所斟。", "小人一時快，君子百世欽。", "貧士繄此辨，士乎當正心。"]'),
('f726719e-7677-494f-a99d-a51932ed0cca','和陶詩六首 和雜詩 其一','王阮','宋','宋诗','song-poetry','','[]','遑遑行路難，汲汲艱食迫。',72,'全唐诗/poet.song.168000.json','["遑遑行路難，汲汲艱食迫。", "井田邈不再，兼并蔽阡陌。", "永懷先父祖，遺我以清白。", "出門無所容，疑此天地窄。", "秋風瘦遥山，凉意愜行客。", "江南記舊遊，不歷歧王宅。"]'),
('e6edccfe-31d1-4082-b3e9-32f75ce38207','和陶詩六首 和雜詩 其二','王阮','宋','宋诗','song-poetry','','[]','淵明棄彭澤，歸歟在柴桑。',84,'全唐诗/poet.song.168000.json','["淵明棄彭澤，歸歟在柴桑。", "我里亦其側，俯視世粃糠。", "顧瞻無所憂，所憂在絕粮。", "敢辭躬耕勞，耒耜山之陽。", "惜哉命之窮，仍歲螟蟘傷。", "去爲游手民，足迹已四方。", "拂衣却歸去，焉用祖離觴。"]'),
('93fdc3ac-8350-4bf7-84c7-5c794b026e3f','陪晦翁登妙高峰一首','王阮','宋','宋诗','song-poetry','','[]','千崖盤屈曲，一塔矗空濛。',48,'全唐诗/poet.song.168000.json','["千崖盤屈曲，一塔矗空濛。", "它處只山好，此中兼水洪。", "縱觀疑犯斗，飛上覺凌風。", "常恨天難近，今朝路已通。"]'),
('995cb95a-aa0b-48d9-a4df-ddd3ba068076','送晦翁十首  其一','王阮','宋','宋诗','song-poetry','','[]','精微元不在河汾，原道詞雄亦淺聞。',32,'全唐诗/poet.song.168000.json','["精微元不在河汾，原道詞雄亦淺聞。", "自得正心誠意論，始知天未喪斯文。"]'),
('bf890aac-9172-4ee0-b210-7e48c25f4b88','送晦翁十首  其二','王阮','宋','宋诗','song-poetry','','[]','淵泉溥博與天大，土苴緒餘聊覺民。',32,'全唐诗/poet.song.168000.json','["淵泉溥博與天大，土苴緒餘聊覺民。", "千古濂溪好風月，一回拈出一回新。"]'),
('5902b7b0-450b-4d90-834e-55c55f8d54b6','送晦翁十首  其三','王阮','宋','宋诗','song-poetry','','[]','武夷山下孤高節，五老亭中撫字心。',32,'全唐诗/poet.song.168000.json','["武夷山下孤高節，五老亭中撫字心。", "出處本來無二致，詎分鍾鼎與山林。"]'),
('80e0d2a3-61b3-4042-9645-563e5ab0f59f','送晦翁十首  其四','王阮','宋','宋诗','song-poetry','','[]','靈臺一似大圓鏡，妍醜自分吾不知。',32,'全唐诗/poet.song.168000.json','["靈臺一似大圓鏡，妍醜自分吾不知。", "秋殺春生天道爾，先生喜怒一何私。"]'),
('0915a6a8-c714-4a6c-8960-d40afabe658f','送晦翁十首  其五','王阮','宋','宋诗','song-poetry','','[]','去年民食十分災，一力先生盡救回。',32,'全唐诗/poet.song.168000.json','["去年民食十分災，一力先生盡救回。", "今日手攀轅下者，人人都自翳桑來。"]'),
('eee24eb1-773c-41a5-b1c2-ab925cedad41','送晦翁十首  其六','王阮','宋','宋诗','song-poetry','','[]','移苗時節雨連天，白水青秧滿大田。',32,'全唐诗/poet.song.168000.json','["移苗時節雨連天，白水青秧滿大田。", "天欲先生歸去後，故留遺愛在豐年。"]'),
('a374091d-1cfb-4dd2-997a-bd5ca46421f5','送晦翁十首  其七','王阮','宋','宋诗','song-poetry','','[]','忌口年來積漸除，君王方信是真儒。',32,'全唐诗/poet.song.168000.json','["忌口年來積漸除，君王方信是真儒。", "稍移全活一州手，再使江西十郡蘇。"]'),
('571bab38-8b35-4d1f-a5a2-4324fbe2a153','送晦翁十首  其八','王阮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','白鹿堂中巧鑄顔，天留一派在廬山。',32,'全唐诗/poet.song.168000.json','["白鹿堂中巧鑄顔，天留一派在廬山。", "它時沂水春風裏，笑我於中獨自頑。"]'),
('bef79fc4-1182-43c0-8131-7a2b0d4e0464','送晦翁十首  其九','王阮','宋','宋诗','song-poetry','','[]','糟粕從來空自忙，筌蹄今幸得師忘。',32,'全唐诗/poet.song.168000.json','["糟粕從來空自忙，筌蹄今幸得師忘。", "明年重即韓門去，拈出胸中一瓣香。"]'),
('4821642c-e6ca-4e58-8078-7a33a4468deb','送晦翁十首  其一○','王阮','宋','宋诗','song-poetry','','[]','平生自謂此心剛，不信離樽可斷腸。',32,'全唐诗/poet.song.168000.json','["平生自謂此心剛，不信離樽可斷腸。", "今日江邊兩行淚，更無情緒折垂楊。"]'),
('f4dc1123-2220-488f-b51f-7111caa50ae9','同張安國遊萬杉寺一首','王阮','宋','宋诗','song-poetry','','[]','昭陵龍去奎文在，萬歲靈杉守百神。',32,'全唐诗/poet.song.168000.json','["昭陵龍去奎文在，萬歲靈杉守百神。", "四十二年真雨露，山川草木至今春。"]'),
('173d22f7-c472-4690-af77-a0e9fb42f935','重九再到張已隔世書詩牌後一首','王阮','宋','宋诗','song-poetry','','[]','碧紗籠底墨纔乾，白玉樓中骨已寒。',32,'全唐诗/poet.song.168000.json','["碧紗籠底墨纔乾，白玉樓中骨已寒。", "淚盡當年聯騎客，菊花時節獨來看。"]'),
('e525f173-65a1-410f-bc55-217980c86018','六言一首','王阮','宋','宋诗','song-poetry','','[]','秋色染成碧水，夜凉瘦落青山。',28,'全唐诗/poet.song.168000.json','["秋色染成碧水，夜凉瘦落青山。", "樹頭宿鳥歸盡，天外行人未還。"]'),
('e0b8b513-5bd6-42cd-a8f3-a91a5a9315d9','避暑煙水亭與王景文回紋聯句一首','王阮','宋','宋诗','song-poetry','','[]','顔舒且對清樽酒，晝永方濃翠幄陰。',64,'全唐诗/poet.song.168000.json','["顔舒且對清樽酒，晝永方濃翠幄陰。", "環珮響溪寒浪急，畫圖藏谷綉煙深。", "斑生石潤苔紋亂，碧度雲飛鳥影沉。", "閑館邃風來迥野，隔樓斜日轉疎林。"]'),
('64764b57-209e-40ed-8fd7-b7fe404449f2','虛飄飄一首','王阮','宋','宋诗','song-poetry','','[]','虛飄飄，雪花逢日照，柳絮入春摇。',56,'全唐诗/poet.song.168000.json','["虛飄飄，雪花逢日照，柳絮入春摇。", "腐草編浮屋，游絲織綵綃。", "老蚌三更光射月，風鳶一片紙干霄。", "虛飄飄，比人富貴猶堅牢。"]'),
('e3999ead-f766-4554-9c9f-ec49da1d81b6','滄洲閣集句二首  其一','王阮','宋','宋诗','song-poetry','','[]','滄洲有奇趣，吾道付滄洲。',48,'全唐诗/poet.song.168000.json','["滄洲有奇趣，吾道付滄洲。", "樹景中流見，船燈照島幽。", "轉思江海上，却著土山頭。", "野水無人渡，乘桴學聖丘。"]'),
('0d8edbea-7a48-4601-8bbe-dbe20816496f','滄洲閣集句二首  其二','王阮','宋','宋诗','song-poetry','','[]','洲島驟回合，冥冥菰蒲中。',48,'全唐诗/poet.song.168000.json','["洲島驟回合，冥冥菰蒲中。", "清流中落烏，遵渚有歸鴻。", "水作青羅带，脚踏赤鯶公。", "蓬壺雖遼絕，長嘯激清風。"]'),
('82ea0c2b-c345-4781-8043-0dc0e1d5c209','新昌書座右屏一首','王阮','宋','宋诗','song-poetry','','[]','私罪不可有，公罪不可無。',48,'全唐诗/poet.song.168000.json','["私罪不可有，公罪不可無。", "退作陶淵明，進學何易于。", "便願列循吏，寧甘爲鄙夫。", "禍福置不問，吾民其少蘇。"]'),
('19c4cfca-a1f7-444f-b798-6f5b917ead83','新昌留別一首','王阮','宋','宋诗','song-poetry','','[]','奉命誅求下戶貧，抗章懇白上官嗔。',64,'全唐诗/poet.song.168000.json','["奉命誅求下戶貧，抗章懇白上官嗔。", "與其重歛毒千室，寧以深文中一身。", "吏務循良邦有頼，士雖貧賤氣宜伸。", "空煙亭下桃花水，好送扁舟欲去人。"]'),
('8f72a4f1-4885-416b-a62a-04879a063ff8','龍舒朱獻賓主漢陽簿棄官以歸予亦不合丐去爲賦一首','王阮','宋','宋诗','song-poetry','','[]','浪作鸞棲去，驚隨鶴怨還。',48,'全唐诗/poet.song.168000.json','["浪作鸞棲去，驚隨鶴怨還。", "無心漢江水，有節皖公山。", "此事真堪話，諸公寧厚顔。", "嗟予亦興盡，昨夜已投閑。"]'),
('8929adda-7bed-4cbe-bcf1-e42aedba67e1','題靖節先生祠一首','王阮','宋','宋诗','song-poetry','','[]','先生新布政，誰遣小兒來。',48,'全唐诗/poet.song.168000.json','["先生新布政，誰遣小兒來。", "爾面何須識，其心端可猜。", "有名高日月，無力救氛埃。", "百世千秋後，聞風亦遽回。"]'),
('214faf19-ec98-4ce1-bab4-b48b7112bbfb','昌國偶成一首','王阮','宋','宋诗','song-poetry','','[]','諸邑皆山可夜馳，海中昌國力難施。',64,'全唐诗/poet.song.168000.json','["諸邑皆山可夜馳，海中昌國力難施。", "風潮阻渡由天地，期會申嚴限日時。", "願以老身從此免，忍將人命逼諸危。", "交門山下須臾死，肉食諸公知不知。"]'),
('3cbfc62a-0956-4ae1-b3bd-a4ed41be2168','留別昌國五首  其一','王阮','宋','宋诗','song-poetry','','[]','妄意絃歌學子游，迄無三異比中牟。',32,'全唐诗/poet.song.168000.json','["妄意絃歌學子游，迄無三異比中牟。", "丁寧今夜東風雨，添起潮頭急去休。"]'),
('c8a52e6e-af0a-43d4-b478-0c637534ba38','留別昌國五首  其二','王阮','宋','宋诗','song-poetry','','[]','全家雖脫海波危，舊治無人詠十奇。',32,'全唐诗/poet.song.168000.json','["全家雖脫海波危，舊治無人詠十奇。", "孤奉明恩顔似甲，却嗔兒女笑嘻嘻。"]'),
('9457822e-c2a2-4f6b-8605-a770eb9a3e45','留別昌國五首  其三','王阮','宋','宋诗','song-poetry','','[]','三山月淡白銀闕，九老春閑紫石宮。',32,'全唐诗/poet.song.168000.json','["三山月淡白銀闕，九老春閑紫石宮。", "此去能爭幾多地，恨無仙骨到其中。"]'),
('8db6181a-8e67-4c64-9a3e-bb577fea9141','留別昌國五首  其四','王阮','宋','宋诗','song-poetry','','[]','當時底事乞身歸，萬物何曾與我違。',32,'全唐诗/poet.song.168000.json','["當時底事乞身歸，萬物何曾與我違。", "最是臨行更腸斷，海鷗猶自掠船飛。"]'),
('4f406a67-1647-4d0e-a9c3-94d52dba1db2','留別昌國五首  其五','王阮','宋','宋诗','song-poetry','','[]','扶桑曾見日騰空，老去歸田不復東。',32,'全唐诗/poet.song.168000.json','["扶桑曾見日騰空，老去歸田不復東。", "一覺短簷他日夢，起來惆悵曉窗紅。"]'),
('21dc9e79-837e-4977-9560-7963001189d4','昌國秩滿次陳糾祖行韻一首','王阮','宋','宋诗','song-poetry','','[]','昔之督郵逐彭澤，今之督郵眷昌國。',96,'全唐诗/poet.song.168000.json','["昔之督郵逐彭澤，今之督郵眷昌國。", "不令自賦歸去來，更以新詩祖行色。", "開緘墨濕雨濛濛，細讀字字含清風。", "塵埃三載足昏塞，一聽妙語還醒鬆。", "持歸柴桑有茅舍，揭之其間作佳話。", "非惟可詫陶淵明，亦愧當年督郵者。"]'),
('04896c21-2a07-4a8d-87f2-d8089f36132c','題四羊圖一首','王阮','宋','宋诗','song-poetry','','[]','三百維羣世不見，廼以四羊爲一圖。',160,'全唐诗/poet.song.168000.json','["三百維羣世不見，廼以四羊爲一圖。", "人言此圖出韋偃，不知韋偃有意無。", "巖巖參天一古木，下有輕荑滿郊綠。", "雪髯隠約黑暈中，沙肋微茫筆端足。", "昔聞韋侯畫馬工，杜陵長歌歌古松。", "孰知畫羊更如此，世間絕藝誰能窮。", "蘄春太守好事者，珍藏有此希世畫。", "嗟予得見雙眼明，此一轉語久難下。", "三羊遊戲芳草茵，一羊輒登枯樹根。", "安得添我作牧人，爲公鞭此一敗羣。"]'),
('18fd58e9-e124-4654-8baa-ed4bd19ba932','楊白花一首','王阮','宋','宋诗','song-poetry','','[]','天河秋來有時見，秋江人去無還期。',64,'全唐诗/poet.song.168000.json','["天河秋來有時見，秋江人去無還期。", "南風北風日爭吹，三十六宮空淚垂。", "塞鴻已作隨陽去，社燕寧論故巢住。", "安得胡越爲一家，春風來訪紅桃花。"]'),
('c3609d55-3e8e-4a19-a835-66dc449591b5','題東林一首','王阮','宋','宋诗','song-poetry','','[]','屏迹敷淺原，注目香爐峯。',228,'全唐诗/poet.song.168000.json','["屏迹敷淺原，注目香爐峯。", "飽聞送客溪，鼎新古梵宮。", "緬懷結社人，豈止避俗翁。", "一念薰戒香，千年仰玄蹤。", "蜂房始義熙，鳳曆當元豐。", "果有大士出，一與遺言同。", "堂堂照覺師，赫赫襄敏公。", "徹彼毗尼藏，揭我臨濟宗。", "元曰立成佛，坡曰僧中龍。", "少林來於西，雙林振以東。", "冥數其理暗，野燒中宵紅。", "天遣真道人，夜役衆鬼工。", "幻出翬飛簷，化成雷吼鍾。", "神運儼若初，佛法豈有終。", "余生慕真乘，願力愧祖風。", "再窺拈花座，駭歎折草功。", "請續香山堂，老此平臺中。", "白撫生池蓮，青友夾澗松。", "永劫不出門，寂照涵虛空。"]'),
('a7091099-1784-426b-9d3a-179980af8dba','館娃宮一首','王阮','宋','宋诗','song-poetry','','[]','釋越來妖艷，窮吳事儁遊。',264,'全唐诗/poet.song.168000.json','["釋越來妖艷，窮吳事儁遊。", "笑談遺廟社，繪罽及山丘。", "鵷宿離宮瓦，龍移別浦舟。", "楯陳金制巧，床瑩玉光浮。", "破雨驚楓落，馳煙入虎流。", "蓴羹摘千里，荷蓋擁長洲。", "緩緩花開陌，彎彎月照州。", "輕風香逕暖，微步屧廊幽。", "紅喜鱸堪切，黄嗔蟹不收。", "池痕測朝夕，鄉思屬溫柔。", "祇顧山銜日，何知餌带鈎。", "味於重處減，心記捧時謀。", "鯨鬣翻溟渤，金星犯斗牛。", "六千君子銳，二八國人憂。", "泰伯三稱讓，姑蘇一戰休。", "共沉那有井，獨墜苦無樓。", "人去扁舟遠，僧來野寺修。", "宮烏今駭散，臺鹿任鳴呦。", "月爲朱欄暗，山含翠黛愁。", "燭殘新別淚，泉咽舊歌喉。", "一代仇人事，千年壯士羞。", "東門抉眼在，怒氣溢潮頭。"]'),
('cb512148-c960-4937-b785-7b38cf436887','丙午寒食題凈土寺一首','王阮','宋','宋诗','song-poetry','','[]','方見繁紅綉小園，已隨流水泛前村。',64,'全唐诗/poet.song.168000.json','["方見繁紅綉小園，已隨流水泛前村。", "人於醽醁真無分，雨共鞦韆似有冤。", "投老故應諸事懶，問春能得幾分存。", "不須便作匆匆散，更把松梅子細論。"]'),
('ca3f4ec6-8fc4-4f5f-887e-67865c7c7752','再遊用前韻一首','王阮','宋','宋诗','song-poetry','','[]','十年不到此祇園，又爲支郎暫出村。',64,'全唐诗/poet.song.168000.json','["十年不到此祇園，又爲支郎暫出村。", "犬認行蹤增踴躍，燕驚離恨苦埋冤。", "鬢邊但覺新絲長，壁上惟餘舊墨存。", "但問桑麻添幾許，世間萬事不須論。"]'),
('ab1d0aa9-ed7a-44f1-94bf-c041aae207b2','洞庭題詠十一首 太湖','王阮','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','微生已覺漸休閑，老矣何心世路間。',32,'全唐诗/poet.song.168000.json','["微生已覺漸休閑，老矣何心世路間。", "盡把蟲魚束高閣，且拏雙槳泛湖山。"]'),
('7d195766-24e0-4c47-81c0-8a42e7436c06','洞庭題詠十一首 林屋','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','玉柱金庭鎖洞天，更將琳館鎮山川。',32,'全唐诗/poet.song.168000.json','["玉柱金庭鎖洞天，更將琳館鎮山川。", "碧簷委地剝風雨，不賜錢來今幾年。"]'),
('3403a461-efe6-4d90-b5d0-15e4c604e38b','洞庭題詠十一首 仙壇觀','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','羽蓋霓旌入絳霄，偃松長向古壇朝。',32,'全唐诗/poet.song.168000.json','["羽蓋霓旌入絳霄，偃松長向古壇朝。", "我來欲訂金丹訣，試著枯槎上斗杓。"]'),
('c9e90662-7de6-4e0e-bee4-dfd7708ef081','洞庭題詠十一首 宿靈佑觀謝沈君 其一','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','鳳翅出滄溟，扁舟過洞庭。',48,'全唐诗/poet.song.168000.json','["鳳翅出滄溟，扁舟過洞庭。", "銀河萬頃白，螺髻兩山青。", "凡隔幽墟洞，神傳嶽瀆經。", "不須尋上界，只此是青冥。"]'),
('7cfc969d-277b-4244-b731-975567b64617','洞庭題詠十一首 宿靈佑觀謝沈君 其二','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','水遠通天上，山浮似海中。',48,'全唐诗/poet.song.168000.json','["水遠通天上，山浮似海中。", "四圍銀色界，一簇畫屏風。", "秋熟漁樵市，雲連佛老宮。", "我來迷所指，多謝主人翁。"]'),
('882eaf49-53d7-4bc3-883f-5208aa37cc47','洞庭題詠十一首 龜山釣魚臺','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','鬼力神工劈石開，水邊因作釣魚臺。',32,'全唐诗/poet.song.168000.json','["鬼力神工劈石開，水邊因作釣魚臺。", "若爲未有嚴光到，留得絲綸待我來。"]'),
('5d8ef250-568a-416d-a77b-c215cc5e7ff3','洞庭題詠十一首 廣福上真宮','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','水色碧滄茫，山勢青周遭。',168,'全唐诗/poet.song.168000.json','["水色碧滄茫，山勢青周遭。", "壯哉杳渺峯，據此第一高。", "蕭梁古道場，歲月湮蓬蒿。", "有來天師孫，遠與朱葉曹。", "十年悉力營，萬瓦一手操。", "連甍集紫烟，開窗俯洪濤。", "枸杞號千年，夜鶴鳴九皋。", "坐令金丹爐，安此神火熬。", "英英文章伯，所至禿千毫。", "何此老鍊師，不著衮子褒。", "我汎重重湖，歘得片片桃。", "深窮草逕來，敢憚足力勞。", "其徒以爲恥，謂我不可逃。", "試補華黍詩，妄意續離騷。"]'),
('59a8ad29-001a-46ba-91ed-968e57c6c480','洞庭題詠十一首 橘圃 其一','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','外貌千層綠，中心一暈紅。',24,'全唐诗/poet.song.168000.json','["外貌千層綠，中心一暈紅。", "封侯吾不願，頗羨木奴豐。"]'),
('483347b3-c451-498c-a81f-7c06da811248','洞庭題詠十一首 橘圃 其二','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','懷歸空有感，包貢則無因。',24,'全唐诗/poet.song.168000.json','["懷歸空有感，包貢則無因。", "跳入商山去，添予作五人。"]'),
('c9b29edb-0a9f-4514-9553-f669f54213fd','洞庭題詠十一首 水月院','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','奏邸成遺恨，滄浪足勝遊。',24,'全唐诗/poet.song.168000.json','["奏邸成遺恨，滄浪足勝遊。", "一篇水月記，照徹五湖秋。"]'),
('314df721-e807-420e-a87b-7377b7d91b02','洞庭題詠十一首 小湖寺','王阮','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','去年禱雨旃檀林，慈雲賜我三日霖。',208,'全唐诗/poet.song.168000.json','["去年禱雨旃檀林，慈雲賜我三日霖。", "今年包山小湖寺，更得因緣禮大士。", "小湖氣象似寶陁，怪石列岸騰嵯峩。", "近山一抹橫脩蛾，遠山點滴浮青螺。", "四方上下皆滄波，清秋一片銀爲河。", "風平如鏡著水磨，有時粼粼緯碧羅。", "傾覆變動一剎那，蟄雷震起千蛟鼉。", "吾聞天形象雞子，大地爲黄白爲水。", "太湖沉沉九地底，小湖絕頂懸崖裏。", "信哉山澤通一氣，激而行之或可使。", "湖山固是人所樂，至人亦復酷愛此。", "浮海而來開精藍，蓮以草化紅臺三。", "願分一枝入西土，令我滅度生其間。"]'),
('fa2da6ef-91e1-4cb7-9f60-f3fbd1ceac79','洞庭題詠十一首 洞庭留別','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','嶺松歲古欲無根，水石秋深未有痕。',32,'全唐诗/poet.song.168000.json','["嶺松歲古欲無根，水石秋深未有痕。", "無限好山將不去，又依帆影過前村。"]'),
('72b9f1e7-49a7-42d5-8c2c-6f36332ef87c','題瑞昌良田寺覽秀軒一首','王阮','宋','宋诗','song-poetry','','[]','無心軒冕難招我，到眼雲山輒起予。',32,'全唐诗/poet.song.168000.json','["無心軒冕難招我，到眼雲山輒起予。", "不必凭欄更清賞，此身元在此山居。"]'),
('8ec18924-647e-4cb8-a716-cc6db8e63427','陪陳帥登孺子亭一首','王阮','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','未上滕王閣，先登孺子亭。',48,'全唐诗/poet.song.168000.json','["未上滕王閣，先登孺子亭。", "朝廷黨錮傳，湖海少微星。", "獨善非忘世，高風自有靈。", "東湖山上色，長爲此人青。"]'),
('e9d5f7d1-6996-41ce-a0bc-8cb2e619ec08','上巳日雁叉阻風呈宋彥起一首','王阮','宋','宋诗','song-poetry','','[]','往來定是一年一，時節長逢三月三。',64,'全唐诗/poet.song.168000.json','["往來定是一年一，時節長逢三月三。", "天氣未佳宜且住，樹猶如此我何堪。", "花飛與客渾無與，酒好招人只自慚。", "安得惠風和暢景，與君方櫂看淮南。"]'),
('8fd3925a-ccdb-4e1e-9807-606edeb6ac44','長風沙次宋丈韻一首','王阮','宋','宋诗','song-poetry','','[]','已將身世等河沙，又泛春江看浪花。',64,'全唐诗/poet.song.168000.json','["已將身世等河沙，又泛春江看浪花。", "錦纜牙檣君送酒，蓑衣蒻笠我浮家。", "淹留日覺青春暮，飄泊風兼細雨斜。", "安得崑崙能探水，試教來奏小琵琶。"]'),
('68cad778-ce92-4f34-ab50-1451bde3139d','投周益公三首  其一','王阮','宋','宋诗','song-poetry','','[]','洛中九老後，林下一人閑。',48,'全唐诗/poet.song.168000.json','["洛中九老後，林下一人閑。", "蘚篆易鍾鼎，泉聲先珮環。", "禪從止水定，詩挽正風還。", "却爲午橋惜，惜無螺浦山。"]'),
('61cc7a4a-44e1-40da-8069-8204fe751ebd','投周益公三首  其二','王阮','宋','宋诗','song-poetry','','[]','有錦雖當晝，無心侈賜銘。',48,'全唐诗/poet.song.168000.json','["有錦雖當晝，無心侈賜銘。", "筇拖雲際綠，箬戴雨中青。", "國老甘鄉老，台星復客星。", "不須添入畫，麟閣自圖形。"]'),
('c1d693d8-3755-4236-b314-437645b25a78','投周益公三首  其三','王阮','宋','宋诗','song-poetry','','[]','公相昔宜避，公閑今可從。',48,'全唐诗/poet.song.168000.json','["公相昔宜避，公閑今可從。", "分無先覩鳳，情有後凋松。", "一瓣今拈出，三熏敢不恭。", "誰書御李事，爲我贊登龍。"]'),
('e51cf08b-1645-47d2-8483-8c0a9714c995','瓜時有感一首','王阮','宋','宋诗','song-poetry','','[]','籬邊方對菊花黄，又報文移出草堂。',64,'全唐诗/poet.song.168000.json','["籬邊方對菊花黄，又報文移出草堂。", "三宿敢云桑下戀，四翁終願橘中藏。", "泉縈去路常低咽，酒向離亭不肯香。", "聖代多才焉用我，明年重上乞身章。"]'),
('23f1536e-e07d-44f3-86cd-6cef1c0eef48','有感再作三首  其一','王阮','宋','宋诗','song-poetry','','[]','出去夢中事，歸來醉後醒。',48,'全唐诗/poet.song.168000.json','["出去夢中事，歸來醉後醒。", "外貪垂老佚，中樂放心寧。", "花氣窗前入，禽聲枕上聽。", "自憐無此分，明日又飄零。"]'),
('2a297696-b1bd-432e-bc09-eda7414a7995','有感再作三首  其二','王阮','宋','宋诗','song-poetry','','[]','頓覺衰殘甚，難勝委寄隆。',48,'全唐诗/poet.song.168000.json','["頓覺衰殘甚，難勝委寄隆。", "驚惶牛喘月，悵望馬依風。", "忍看丹爐壞，終憐蕙帳空。", "明年花慢發，待我轉來紅。"]'),
('e3e32b5e-40ab-4488-8c7d-93f38ab6c2ff','有感再作三首  其三','王阮','宋','宋诗','song-poetry','','[]','石壁連綿靜，松風自在清。',48,'全唐诗/poet.song.168000.json','["石壁連綿靜，松風自在清。", "只知有此樂，不謂老于行。", "室鵩從何入，山猿累爾驚。", "回天誰有力，祗願效淵明。"]'),
('c1c728c8-f812-4743-8a18-b2684fcfdb33','次陸務觀韻寄王景文一首','王阮','宋','宋诗','song-poetry','','[]','朔風摇楚水，國步益艱辛。',48,'全唐诗/poet.song.168000.json','["朔風摇楚水，國步益艱辛。", "往事忽成夢，逆胡何日臣。", "凡今天下士，皆昔座中人。", "尚被中原髮，煩君與正巾。"]'),
('726bb36e-aef2-4ff4-b453-bb7a61f9a427','訪晦翁不遇一首','王阮','宋','宋诗','song-poetry','','[]','陳良千里赴周公，正值商山去一鴻。',32,'全唐诗/poet.song.168000.json','["陳良千里赴周公，正值商山去一鴻。", "腸斷膝行來處路，舞雩空過一番風。"]'),
('990956ed-6a71-4e16-9955-73bc2221f824','題武夷沖佑觀一首','王阮','宋','宋诗','song-poetry','','[]','九摺湍溪九摺山，玉簪羅带互回環。',32,'全唐诗/poet.song.168000.json','["九摺湍溪九摺山，玉簪羅带互回環。", "若爲脫得紅塵網，來結疎茆一兩間。"]'),
('6132b7cc-b32e-4251-a1cd-5c3f55225146','都下病起呈王樞密一首','王阮','宋','宋诗','song-poetry','','[]','不解彫蟲賦逐貧，又無饒舌論錢神。',64,'全唐诗/poet.song.168000.json','["不解彫蟲賦逐貧，又無饒舌論錢神。", "遭逢此鬼今番瘧，零落吾生有限身。", "舊學試溫渾易忘，新書欲謹自難真。", "時危壯士乃如此，爲報堂堂有位人。"]'),
('47e10043-b758-4bb5-ae0f-b28344381876','龍塘晚遊一首','王阮','宋','宋诗','song-poetry','','[]','五湖千里吞吳天，館娃宮殿何悠然。',160,'全唐诗/poet.song.168000.json','["五湖千里吞吳天，館娃宮殿何悠然。", "銀山鐵壘挽不動，萬丈夕陽如血鮮。", "野人固陋元不識，光芒奪眼眼無力。", "長安路遠人不來，信道舉頭惟見日。", "煌煌火德千載期，赤帝之子張赤旗。", "歲寒水冷自可畏，豈必夏盾同冬衰。", "馮夷舞歸驚且悅，幽壑沉沉忽金闕。", "媚川謾道水含珠，照水詎誇虹貫月。", "何處扁舟飛片帆，中有西子輕紅衫。", "想像玉顔人不遠，杖頭星斗寒相參。"]'),
('58cdf8c2-ff35-4f5a-8843-cad1f20ad14d','謝趙宰拜襄敏墓并留題二首  其一','王阮','宋','宋诗','song-poetry','','[]','班春故事亦年年，公獨推誠遠布宣。',64,'全唐诗/poet.song.168000.json','["班春故事亦年年，公獨推誠遠布宣。", "麗日借黄催麥壠，惠風吹綠散秧田。", "衆魚入夢蓑衣下，異雉飛馴桑蔭前。", "好詠十奇歸樂府，聖朝方採下民篇。"]'),
('322f4a39-a0f8-402d-bcef-2d781097ee51','謝趙宰拜襄敏墓并留題二首  其二','王阮','宋','宋诗','song-poetry','','[]','河湟人去鎖春蕪，三步遥勤一束芻。',64,'全唐诗/poet.song.168000.json','["河湟人去鎖春蕪，三步遥勤一束芻。", "盛事發揮千古烈，英詞噓動百年枯。", "故家零落今朝遇，此段孤高近世無。", "地下結成無限草，待公肅甲破幽都。"]'),
('c07b882d-927a-49e4-9feb-b6ad028e2d31','讀浯溪碑一首','王阮','宋','宋诗','song-poetry','','[]','魯惡吳同姓，唐嫌肅撫軍。',48,'全唐诗/poet.song.168000.json','["魯惡吳同姓，唐嫌肅撫軍。", "仲尼諱不語，元結謗於文。", "子固當承父，臣其可訕君。", "空令忠義士，歎息異吾聞。"]'),
('fe8169fb-7fab-48c6-a628-ad41564d5f2e','蘭亭一首','王阮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','金行中否野多遺，越禊諸賢不受覊。',64,'全唐诗/poet.song.168000.json','["金行中否野多遺，越禊諸賢不受覊。", "天朗氣清書上巳，春行秋令紀當時。", "九原寂寞不可作，一水縈回或在茲。", "歸去廬山定相問，爲公關報紫霄知。"]'),
('8d4a3ce2-31c1-46f2-86ef-acbd09bd5645','送沈侍郎二首  其一','王阮','宋','宋诗','song-poetry','','[]','獻納論思玉笋班，間因忠讜忤龍顔。',64,'全唐诗/poet.song.168000.json','["獻納論思玉笋班，間因忠讜忤龍顔。", "一朝錦水連江水，萬里何山與卞山。", "道大可能忘濟世，名高那得鎮投閑。", "天教一似蘇門下，先到筠陽却詔還。"]'),
('f119e7b0-6784-41f6-b6ce-2f0b1c425c7b','送沈侍郎二首  其二','王阮','宋','宋诗','song-poetry','','[]','重入脩門已有期，趣裝聊此著征衣。',64,'全唐诗/poet.song.168000.json','["重入脩門已有期，趣裝聊此著征衣。", "帝思宣室名儒對，人喜玄都舊客歸。", "高節不難全晚歲，亨途未必盡危機。", "願公且爲蒼生起，莫向苕溪戀翠微。"]'),
('d9920a45-b909-4ddd-9cbb-f7c9e989dc64','次韻范石湖北窗書懷一首','王阮','宋','宋诗','song-poetry','','[]','驕陽重鬰結，凉飆驚豁開。',120,'全唐诗/poet.song.168000.json','["驕陽重鬰結，凉飆驚豁開。", "排戶始奔突，轉隙少徘徊。", "仄聞風伯言，敬爲邦君來。", "邦君著之詩，快心吾已灰。", "獨念暑耘人，斯時若爲懷。", "所願均此施，醒然與之偕。", "有冰何心漿，有甕何心醅。", "莫吹天上雲，要洗田中埃。", "高枕謝北窗，披襟笑登臺。", "伏讀旨意大，倍使吾容齋。"]'),
('2d5dfdc5-57f4-4177-b9d2-9ec3a5c6f84b','用太白韻贈報恩南老一首','王阮','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','上人片雲孤，賤子亦萍蹤。',48,'全唐诗/poet.song.168000.json','["上人片雲孤，賤子亦萍蹤。", "兩枝同社蓮，千歲後凋松。", "今年九華山，去年五老峯。", "江南好風景，但願長相從。"]'),
('bc54f46f-c7c7-4da3-9e4f-f5a1ae52f0ab','次韻酬李周翰一首','王阮','宋','宋诗','song-poetry','','[]','大江固茫茫，一葦即可越。',168,'全唐诗/poet.song.168000.json','["大江固茫茫，一葦即可越。", "鄉來江與蘄，孰使我輩隔。", "溫溫李夫子，粲粲謫仙格。", "蕭然一竹關，白眼謝俗客。", "蚤充觀國賓，百中應百發。", "我玉空自良，彼怒輒反掇。", "歸歎儒冠誤，盡把氣習撤。", "收藏萬丈焰，不受一夫决。", "纍然駑馬中，倍覺騏驥別。", "嗟余偶傾蓋，辱許共映雪。", "快哉平生心，清風濯執熱。", "今惟仄席秋，正採鄉評月。", "豈無識真人，達君此奇節。", "春雷震一聲，指日看甲拆。"]'),
('588e9616-4194-4de8-917a-423c3f791076','廬江道中二首  其一','王阮','宋','宋诗','song-poetry','','[]','處處雲山異，時時氣象同。',48,'全唐诗/poet.song.168000.json','["處處雲山異，時時氣象同。", "官程嚴有限，王事冗無窮。", "晚色烘西日，霜威釀北風。", "人生真夢幻，底用苦匆匆。"]'),
('039a5ce7-5afc-4509-bc89-e02b0890276c','廬江道中二首  其二','王阮','宋','宋诗','song-poetry','','[]','老大添身倦，飄零減性豪。',48,'全唐诗/poet.song.168000.json','["老大添身倦，飄零減性豪。", "路塵知旱苦，山瘦覺秋高。", "若有持衡分，慚無汗馬勞。", "九原如可作，公瑾笑吾曹。"]'),
('a7028477-4cf1-4be8-84d4-7e3752b7dbfa','題嚴陵釣臺一首','王阮','宋','宋诗','song-poetry','','[]','西都庸庸生禍胎，東都切切繩公台。',192,'全唐诗/poet.song.168000.json','["西都庸庸生禍胎，東都切切繩公台。", "平生故人苦畏辱，坐定白雲那肯來。", "沉幾深略滿帝腹，且憩先生一雙足。", "使知天上麒麟兒，不似犬羊甘豢畜。", "渭濱老叟不自持，爲人人以鷹名之。", "豈識桐江一竿竹，依舊秋風魚正肥。", "古來賢者亦避世，往往適逢天地閉。", "得如建武亦不惡，又值首陽難降志。", "山木陰陰江面寒，此天別在壺中寬。", "幾曾流出桃花去，寶氣自駭人間觀。", "當時不願世知己，稱到于今却如此。", "塞馬得失天好還，千駟齊侯不窮理。"]'),
('ec82bdca-f180-4ea4-a040-3490cb9f6a74','禹穴一首','王阮','宋','宋诗','song-poetry','','[]','綠字煌煌錫禹疇，厥初龜負即天休。',32,'全唐诗/poet.song.168000.json','["綠字煌煌錫禹疇，厥初龜負即天休。", "轉爲玉札符經論，果有書藏此穴不。"]'),
('02a79bfd-800e-4c76-83ab-38d3eaba873c','禹廟一首','王阮','宋','宋诗','song-poetry','','[]','萬世衣裳脫介鱗，一祠寧足報恩深。',32,'全唐诗/poet.song.168000.json','["萬世衣裳脫介鱗，一祠寧足報恩深。", "長教天下江河順，始慰胼胝手足心。"]'),
('d39cde03-a00d-4af7-aca6-a9bebc3ef839','禹陵一首','王阮','宋','宋诗','song-poetry','','[]','禹駕黄龍入九霄，空山陰有百神朝。',32,'全唐诗/poet.song.168000.json','["禹駕黄龍入九霄，空山陰有百神朝。", "翠微不用熊羆守，乞與遺民共採樵。"]'),
('9d8afd83-b8fc-4359-ab85-dacbfe46532d','寄題識山堂一首','王阮','宋','宋诗','song-poetry','','[]','山體如如即我身，眼高纔是箇中人。',32,'全唐诗/poet.song.168000.json','["山體如如即我身，眼高纔是箇中人。", "錦囊忽上玉樓去，誰復如公更識真。"]'),
('a0b7b219-a6e8-4538-ba83-1b952fc0de50','龍門寺一首','王阮','宋','宋诗','song-poetry','','[]','傍石尋幽徑，窮源得梵城。',48,'全唐诗/poet.song.168000.json','["傍石尋幽徑，窮源得梵城。", "塔光侵地發，龍氣逼山清。", "是處堪吾老，何年遂此生。", "霜林知客意，一夜戰秋聲。"]'),
('7b1bcfbd-2740-44e2-8217-88cb0b7dfdbd','出郊訪沈洞主一首','王阮','宋','宋诗','song-poetry','','[]','抖擻塵埃暫出郊，一藤先訪羽人巢。',64,'全唐诗/poet.song.168000.json','["抖擻塵埃暫出郊，一藤先訪羽人巢。", "風翻翠浪催禾穗，秋放殷紅著樹梢。", "萬里家山懷五老，千年活計却三茅。", "明朝便好乘風去，不學浮屠更打包。"]'),
('6061d3b1-9130-438c-85f2-1d9dd102e48d','瀑布二首  其一','王阮','宋','宋诗','song-poetry','','[]','造物小兒不任事，一天元氣從淋漓。',64,'全唐诗/poet.song.168000.json','["造物小兒不任事，一天元氣從淋漓。", "雲中雨降自應爾，山上水行誰激之。", "幽林洶洶虛籟作，赫日粲粲寒光垂。", "謫仙獨步得興體，此外篇篇俱比詩。"]'),
('e572e1c2-704e-4f14-bccc-cd8386a65996','瀑布二首  其二','王阮','宋','宋诗','song-poetry','','[]','萬仞青空不可攀，天將飛瀑掛其間。',64,'全唐诗/poet.song.168000.json','["萬仞青空不可攀，天將飛瀑掛其間。", "一雙玉塔倚絕壁，兩道白雲騰半山。", "覆器以欹嗟魯廟，設瓴而建笑秦關。", "春風一卷出山去，萬里青秧抱甕閑。"]'),
('1c6e9677-087e-4653-b11e-b098df48b465','曹娥廟一首','王阮','宋','宋诗','song-poetry','','[]','英哉神女此江干，德與餘姚舜一般。',64,'全唐诗/poet.song.168000.json','["英哉神女此江干，德與餘姚舜一般。", "碧草凄凄埋玉冷，清風凜凜矗天寒。", "求生古患爲仁害，處死今知得所難。", "我自裴徊不忍去，非干潮小故盤桓。"]'),
('0dfc2254-ba1b-4663-8bee-2f4e0cfcd323','題高遠亭一首','王阮','宋','宋诗','song-poetry','','[]','小携樽酒作清遊，行到方壺最上頭。',64,'全唐诗/poet.song.168000.json','["小携樽酒作清遊，行到方壺最上頭。", "山在斷霞明處碧，水從白鳥去邊流。", "苦無妙句窺天巧，頼有名亭慰客愁。", "從此江南添勝景，未應獨數庾公樓。"]'),
('27f64804-b89d-4ca7-a5f7-3e12c1c0a7e3','過東林吊沈文伯一首','王阮','宋','宋诗','song-poetry','','[]','苕霅雖幽事，燕雲亦壯遊。',48,'全唐诗/poet.song.168000.json','["苕霅雖幽事，燕雲亦壯遊。", "寧虞就日館，不返度淮舟。", "死節千年在，私家萬事休。", "重來聯句地，清淚接溪流。"]'),
('4516c9e0-2cca-45fe-bd81-2a6f368173cb','次韻庸齋納凉一首','王阮','宋','宋诗','song-poetry','','[]','招提竹鑰不曾關，容我追凉突兀間。',64,'全唐诗/poet.song.168000.json','["招提竹鑰不曾關，容我追凉突兀間。", "石甃陰生寒水玉，天燈爍散火雲山。", "葛巾當晝何庸脫，葵扇非秋却暫閑。", "所愧岑參聊爾耳，强將詩與少陵班。"]'),
('06b695db-b716-40ee-a153-17d2905507cf','彭澤道中二首  其一','王阮','宋','宋诗','song-poetry','','[]','世路日益險，道根終自深。',48,'全唐诗/poet.song.168000.json','["世路日益險，道根終自深。", "因勞踏石足，倍起愛山心。", "地冷雪常在，歲窮天更陰。", "今宵投宿處，知度幾層林。"]'),
('b19e0119-f426-4eb1-8d41-03afe2052171','彭澤道中二首  其二','王阮','宋','宋诗','song-poetry','','[]','茲日定何日，前山連後山。',48,'全唐诗/poet.song.168000.json','["茲日定何日，前山連後山。", "吾曹凡事懶，此去幾時還。", "復辟尚英爽，棄官真等閑。", "異時懷二子，惆悵此山間。"]'),
('7ebbe3c6-42ea-426e-ba87-aeb20b39c6c0','溪山堂三首  其一','王阮','宋','宋诗','song-poetry','','[]','地勝年年別，人閑事事幽。',48,'全唐诗/poet.song.168000.json','["地勝年年別，人閑事事幽。", "水流縈檻角，山奮入簾鈎。", "舊好空馳馬，新盟但狎鷗。", "故人皆得路，何日共茲遊。"]'),
('c409fc77-1ba4-4a00-ba5f-bc3e40ca0967','溪山堂三首  其二','王阮','宋','宋诗','song-poetry','','[]','出去真危道，歸來適醉鄉。',48,'全唐诗/poet.song.168000.json','["出去真危道，歸來適醉鄉。", "田分禾穗合，江落木陰凉。", "璇極隨心闊，銅壺入夢長。", "一從輕卓魯，方悟有羲黄。"]'),
('378fdd4f-70f8-4016-b5a4-f98468706306','溪山堂三首  其三','王阮','宋','宋诗','song-poetry','','[]','簷敞祛紅日，窗虛揖白雲。',48,'全唐诗/poet.song.168000.json','["簷敞祛紅日，窗虛揖白雲。", "水痕一雨失，花氣午風薰。", "寂寂心無事，紛紛耳不聞。", "只須添道力，底用戰魔軍。"]'),
('fef87c0f-3e6c-49ed-bee6-4df37f21f3a5','尋真觀一首','王阮','宋','宋诗','song-poetry','','[]','鸞昇天上五峯青，龍住山中九疊屏。',32,'全唐诗/poet.song.168000.json','["鸞昇天上五峯青，龍住山中九疊屏。", "知有洞門藏水底，倚闌吾欲跳清泠。"]'),
('ac0f3a3c-5d94-4a67-b0aa-d7fae044ab81','延真觀一首','王阮','宋','宋诗','song-poetry','','[]','偃月堂成竟斲棺，延真人只葬衣冠。',32,'全唐诗/poet.song.168000.json','["偃月堂成竟斲棺，延真人只葬衣冠。", "浮雲眼見成騎虎，不似抽身穩跨鸞。"]'),
('802bc6c3-05b1-4c3c-8219-f71de3f8be72','挽張舍人安國四首  其一','王阮','宋','宋诗','song-poetry','','[]','天上張公子，人間第一流。',48,'全唐诗/poet.song.168000.json','["天上張公子，人間第一流。", "浮雲狨覆座，愕夢玉成樓。", "草蔓湖陰宅，松封曠口丘。", "忠魂招不返，欲問楚江頭。"]'),
('f97f75d4-3b20-418b-a909-c72e7bf813bd','挽張舍人安國四首  其二','王阮','宋','宋诗','song-poetry','','[]','志氣周瑜俊，謀謨賈誼嘉。',48,'全唐诗/poet.song.168000.json','["志氣周瑜俊，謀謨賈誼嘉。", "早先天下士，共服驥中驊。", "瞬息桑田改，傾摧嶽柱斜。", "傷心大手筆，零落紫薇花。"]'),
('14278a96-8f5f-4700-aa5f-e639e73c351c','挽張舍人安國四首  其三','王阮','宋','宋诗','song-poetry','','[]','忤世無如我，知音獨有君。',48,'全唐诗/poet.song.168000.json','["忤世無如我，知音獨有君。", "時陪文字飲，議殄犬羊羣。", "未脫雲間戍，先修地下文。", "天心終吝此，不復更從軍。"]'),
('a8a4b8d0-50e4-4d28-a9b9-a424bcd0f245','挽張舍人安國四首  其四','王阮','宋','宋诗','song-poetry','','[]','近別逾旬朔，俄傳訃問來。',48,'全唐诗/poet.song.168000.json','["近別逾旬朔，俄傳訃問來。", "初疑餘子謗，漸沸使人猜。", "竟作青黄木，終成怨怒雷。", "數行衰淚盡，吾意獨憐才。"]'),
('a13f7d57-b004-467b-8338-e2971abb4da4','池陽道中一首','王阮','宋','宋诗','song-poetry','','[]','日月狂風裏，悠悠小艇還。',48,'全唐诗/poet.song.168000.json','["日月狂風裏，悠悠小艇還。", "遶身衣带水，堆眼劍鋩山。", "歲月吾生老，煙塵客路艱。", "一天霜氣重，今夜碧蘆灣。"]'),
('ff66b310-8991-4d76-a598-78e494ef360c','江上一首','王阮','宋','宋诗','song-poetry','','[]','虜馬秋來健，吳儂水底藏。',48,'全唐诗/poet.song.168000.json','["虜馬秋來健，吳儂水底藏。", "荻花江面冷，草色岸頭荒。", "揚子真天險，淮南盡日忙。", "邊隅今夜甲，吾願莫飛霜。"]'),
('e625b1f5-9e23-41b3-94f6-ecc043c881e8','泛舟一首','王阮','宋','宋诗','song-poetry','','[]','霅川荷葉浦，彭蠡石榴頭。',48,'全唐诗/poet.song.168000.json','["霅川荷葉浦，彭蠡石榴頭。", "此地皆奇絕，平生所爛遊。", "從來貪水國，老去只漁舟。", "更有乘桴便，何人從我浮。"]'),
('4c6b4da2-a31b-4371-ab62-ac0ec7004dcf','雲居還值旱懷舊遊寄楊文仲二首  其一','王阮','宋','宋诗','song-poetry','','[]','憶扶湘竹杖，共扣趙州關。',48,'全唐诗/poet.song.168000.json','["憶扶湘竹杖，共扣趙州關。", "山好不容住，水流今載還。", "却從天上下，似出鏡中間。", "笑問楊夫子，何時再得閑。"]'),
('f5b218da-5c6c-431b-b77a-167d5021d9c5','雲居還值旱懷舊遊寄楊文仲二首  其二','王阮','宋','宋诗','song-poetry','','[]','四野盡龜兆，一天常火雲。',48,'全唐诗/poet.song.168000.json','["四野盡龜兆，一天常火雲。", "夜凉清似水，晝旱氣如焚。", "龍懶渾無用，天高寂不聞。", "我無田可慮，只慮衆紛紛。"]'),
('3c0a4dae-1595-4562-a818-7d2dcf51bcc9','郊居即事一首','王阮','宋','宋诗','song-poetry','','[]','涉世足悔吝，杜門安退藏。',48,'全唐诗/poet.song.168000.json','["涉世足悔吝，杜門安退藏。", "謗從閑處省，樂向靜中長。", "薜荔日緣壁，琅玕春透牆。", "近來無事作，渾以醉爲鄉。"]'),
('61238f82-7851-4e1c-bbea-a96b8a5fed21','謝張安國相過一首','王阮','宋','宋诗','song-poetry','','[]','元戎驅小隊，來赴野人期。',48,'全唐诗/poet.song.168000.json','["元戎驅小隊，來赴野人期。", "山靜傳呼遠，風輕遊賞宜。", "飛蘿穿杖屨，芳草煥旌旗。", "好借絲綸手，雕鎸一小詩。"]'),
('73bc0d3c-a6b0-4e71-8ec6-7fc8c4cf6ee8','宿淮南岸一首','王阮','宋','宋诗','song-poetry','','[]','一昔淮南岸，兩旬揚子江。',48,'全唐诗/poet.song.168000.json','["一昔淮南岸，兩旬揚子江。", "山川總極目，天地偶爲邦。", "竟日師虞老，何年虜自降。", "知心除是月，夜夜照蓬窗。"]'),
('3f2eacf4-0130-420c-8f5e-75057b0faf5e','贈尹氏子一首','王阮','宋','宋诗','song-poetry','','[]','有兒聰慧了羣書，底用金門與石渠。',32,'全唐诗/poet.song.168000.json','["有兒聰慧了羣書，底用金門與石渠。", "幸甚先生矜小友，一言端以正其初。"]'),
('a6e36353-5367-4385-91f3-4590e6353854','南至日呈詹司諫一首','王阮','宋','宋诗','song-poetry','','[]','消息盈虛理甚明，積陰盡處一陽生。',32,'全唐诗/poet.song.168000.json','["消息盈虛理甚明，積陰盡處一陽生。", "孤根莫厭風霜甚，昨夜春雷拆甲聲。"]'),
('a5b666bc-250d-4b20-91fd-fbb490fe76c0','入山遇雨宿開先寺二首  其一','王阮','宋','宋诗','song-poetry','','[]','擺落塵埃步入山，與僧相對浹旬間。',32,'全唐诗/poet.song.168000.json','["擺落塵埃步入山，與僧相對浹旬間。", "鶴林却笑題詩客，只得浮生半日閑。"]'),
('2b1bc964-7ca4-4b1f-94fc-eaf72b067599','入山遇雨宿開先寺二首  其二','王阮','宋','宋诗','song-poetry','','[]','雨漲泥痕卒未乾，斷橋無策濟歸鞍。',32,'全唐诗/poet.song.168000.json','["雨漲泥痕卒未乾，斷橋無策濟歸鞍。", "山靈有意留儂住，不作尋常俗駕看。"]'),
('999fc135-1a60-49f0-bbca-7b597a0ced94','龜父國賓二周丈同遊谷簾三首  其一','王阮','宋','宋诗','song-poetry','','[]','偶然得意挹珍流，二妙欣然共勝遊。',32,'全唐诗/poet.song.168000.json','["偶然得意挹珍流，二妙欣然共勝遊。", "怪得坐間無俗語，谷簾泉水建茶甌。"]'),
('201ce0cd-2ec9-4eed-8f3e-e444494e6730','龜父國賓二周丈同遊谷簾三首  其二','王阮','宋','宋诗','song-poetry','','[]','萬斛跳珠撒一空，水晶光透影玲瓏。',32,'全唐诗/poet.song.168000.json','["萬斛跳珠撒一空，水晶光透影玲瓏。", "籃輿不是歸來早，安得携瓶到此中。"]'),
('fa2cbc06-4b06-4567-803e-2fd1b05b93a7','龜父國賓二周丈同遊谷簾三首  其三','王阮','宋','宋诗','song-poetry','','[]','一飲清泠體便輕，絕知真液是長生。',32,'全唐诗/poet.song.168000.json','["一飲清泠體便輕，絕知真液是長生。", "歸來世事都忘盡，惟記白雲堆裏行。"]'),
('60da671e-34aa-4f50-90c1-d4161b527ca4','寄鄭器先一首','王阮','宋','宋诗','song-poetry','','[]','與子如兄弟，爲人痛疾讎。',48,'全唐诗/poet.song.168000.json','["與子如兄弟，爲人痛疾讎。", "暫時離別去，且欲謗讒休。", "敢忘秦方瘠，深知越共舟。", "少須三逕就，他日再追遊。"]'),
('296405e7-c10f-4d83-9850-0528a5cf976f','冬日見桃一首','王阮','宋','宋诗','song-poetry','','[]','梅意猶藏萼，桃腮已放花。',48,'全唐诗/poet.song.168000.json','["梅意猶藏萼，桃腮已放花。", "地疑時候惡，律恐統元差。", "寒漲漁舟水，春明道觀霞。", "老來無賞玩，癡坐惜年華。"]'),
('62d50957-ce58-4c95-a2f4-e42087ad9b2b','游洞霄宮一首','王阮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','洞天若限仙凡路，九鎖前山不易尋。',32,'全唐诗/poet.song.168000.json','["洞天若限仙凡路，九鎖前山不易尋。", "尚有康廬山下客，玉皇溫詔與登臨。"]'),
('b6cab0b9-64bb-4dfb-a6bd-79a9f38ad5f8','鐵柱觀一首','王阮','宋','宋诗','song-poetry','','[]','西晉旌陽令，南昌鐵柱宮。',48,'全唐诗/poet.song.168000.json','["西晉旌陽令，南昌鐵柱宮。", "人間依道庇，天上擢陰功。", "江靜蠻夷漲，爐存造化工。", "我來如有遇，舉袂欲凌風。"]'),
('4d0a213c-aa14-4f4f-8548-46edab73f276','九日有感一首','王阮','宋','宋诗','song-poetry','','[]','舉國無人分智囊，滿川龍血戰玄黄。',64,'全唐诗/poet.song.168000.json','["舉國無人分智囊，滿川龍血戰玄黄。", "百年馴致文明地，一日盡爲荆棘場。", "關輔渴思王鎮惡，蜀人尤喜杜黄裳。", "小臣試草中興頌，準擬還京奉上皇。"]'),
('04e3ef8a-42bc-4cac-bca1-b61d4313ec3d','和戴倅韻寄苗侯一首','王阮','宋','宋诗','song-poetry','','[]','靈壁歸師憤已平，黄河戍役又虛聲。',64,'全唐诗/poet.song.168000.json','["靈壁歸師憤已平，黄河戍役又虛聲。", "人言萬事總由命，天設五材難去兵。", "國有典刑元老在，地無形勢大江橫。", "西風若得淮南信，煩致空山慰客情。"]'),
('6aa29bd7-5039-4922-bd0b-0df97509b922','八月過西林一首','王阮','宋','宋诗','song-poetry','','[]','似應沙鷺有前期，裝點秋原景最宜。',64,'全唐诗/poet.song.168000.json','["似應沙鷺有前期，裝點秋原景最宜。", "落雨敗梧隨沆瀣，牽風寒藻舞淪漪。", "流旋碧玉渠初滿，剝盡黄花稻已衰。", "海裏是非休苦惱，不如學取步兵癡。"]'),
('f27c7483-ee49-4420-9dff-662975e231e4','蓬屋一首','王阮','宋','宋诗','song-poetry','','[]','長簷十尺庇堂東，疎漏從來盡是蓬。',64,'全唐诗/poet.song.168000.json','["長簷十尺庇堂東，疎漏從來盡是蓬。", "日影碎如秋葉下，雨聲灑似夜船中。", "竹因蠹盡多垂地，箬到枯時半掩空。", "此處想非人所競，衆雄應是不來攻。"]'),
('65834506-a89c-4f52-94b4-dc92423ed345','詹林宗携文見過一首','王阮','宋','宋诗','song-poetry','','[]','疇昔吾詹子，文章已足稱。',48,'全唐诗/poet.song.168000.json','["疇昔吾詹子，文章已足稱。", "近携新作至，遠比舊來增。", "迅灑行行雨，清嚴字字冰。", "桃花春浪近，坐看九霄鵬。"]'),
('6321e98f-956f-4993-8604-74880fc858c4','佚老堂二首  其一','王阮','宋','宋诗','song-poetry','','[]','洛中九老後，林下一人高。',48,'全唐诗/poet.song.168000.json','["洛中九老後，林下一人高。", "此去自當佚，向來誠獨勞。", "東湖歸踐履，南浦薦風騷。", "尚念匈奴在，家山未可褒。"]'),
('b7aa3efb-47ac-4f33-bd93-02a330c66952','佚老堂二首  其二','王阮','宋','宋诗','song-poetry','','[]','擺落釣衡地，追尋汗漫期。',48,'全唐诗/poet.song.168000.json','["擺落釣衡地，追尋汗漫期。", "馬閑無用處，鷗玩不驚時。", "人朴山林古，天全日月遲。", "可無劉白伴，時獻午橋詩。"]'),
('aad3512c-0089-4ca9-8bb2-854abed42684','早春示陳元達一首','王阮','宋','宋诗','song-poetry','','[]','北陸藏冰後，東風入律和。',48,'全唐诗/poet.song.168000.json','["北陸藏冰後，東風入律和。", "梅因三弄少，麥頼六花多。", "簪盍思喧馬，燈遊羨閙蛾。", "躬耕吾不倦，其奈沒田何。"]'),
('98df85c5-1064-48d8-be0d-53b9885faf36','余門羅雀久矣今日池內有鷗戲爲小詩呈叔夏一首','王阮','宋','宋诗','song-poetry','','[]','門冷人誰到，機忘物自知。',48,'全唐诗/poet.song.168000.json','["門冷人誰到，機忘物自知。", "舊來羅雀地，今是狎鷗池。", "身靜紅塵遠，心閑白日遲。", "本來無事說，拈出戲爲詩。"]'),
('3086a051-c79f-4c7a-a4b2-2a8653c4f4e1','宿五步港一首','王阮','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','兩岸各風物，四年三往還。',48,'全唐诗/poet.song.168000.json','["兩岸各風物，四年三往還。", "舟中五步港，雲外九華山。", "路遠虞衣闕，囊空慮食艱。", "大江吾隘爾，天地一魚灣。"]'),
('cb06e6d4-4d9a-49ad-85bd-691394b37a17','出豐城一首','王阮','宋','宋诗','song-poetry','','[]','摇摇旌旆出洪都，彌望田疇總廢墟。',64,'全唐诗/poet.song.168000.json','["摇摇旌旆出洪都，彌望田疇總廢墟。", "羸馬不前身突兀，耕夫相視笑軒渠。", "倚松茅屋斜開徑，近水人家半賣魚。", "蒲葉向冬猶未割，臨風遥憶路溫舒。"]'),
('a1e65d94-530d-4a1d-a5f1-b389dde011d1','宿祖印寺一首','王阮','宋','宋诗','song-poetry','','[]','下馬杉松石徑幽，暗泉一带抱山流。',64,'全唐诗/poet.song.168000.json','["下馬杉松石徑幽，暗泉一带抱山流。", "長廊隠隠丹青古，香霧濛濛日夜浮。", "缺月有情還委照，覊人無語獨登樓。", "急呼老瓦招歡伯，爲洗胸中萬斛愁。"]'),
('430a12c3-f257-43d9-bd36-688f7553ef49','投吏部汪書一首','王阮','宋','宋诗','song-poetry','','[]','銓選仍多弊，今年得偉人。',48,'全唐诗/poet.song.168000.json','["銓選仍多弊，今年得偉人。", "衣冠歸藻鑑，草芥倚陽春。", "冢宰天官貴，山公啟事新。", "請收才傑士，預作鳳池賓。"]'),
('e96ac422-e993-4fea-af88-fa3f3ebde842','遊三峽一首','王阮','宋','宋诗','song-poetry','','[]','玉淵真水府，三峽跨長虹。',48,'全唐诗/poet.song.168000.json','["玉淵真水府，三峽跨長虹。", "萬斛鎔銀瀉，千檛戰鼓雄。", "倚天危石立，透地密泉通。", "四海思霖雨，龍奚久在中。"]'),
('6206d67b-bef0-44a9-89da-85850cb0cba7','訪子虛不遇一首','王阮','宋','宋诗','song-poetry','','[]','曉入千山與萬山，白雲深處款幽關。',32,'全唐诗/poet.song.168000.json','["曉入千山與萬山，白雲深處款幽關。", "仙翁不許凡人識，走出紅塵不肯還。"]'),
('2d5c731e-a9b3-4dff-8557-f19de6bb7fa9','寄范石湖五首  其一','王阮','宋','宋诗','song-poetry','','[]','殊庭詔祿佚忠勤，祕殿升班寵舊勳。',32,'全唐诗/poet.song.168000.json','["殊庭詔祿佚忠勤，祕殿升班寵舊勳。", "試向午橋諸第問，有誰別墅得奎文。"]'),
('4e870a52-f863-49f9-b224-a58d825e6ae9','寄范石湖五首  其二','王阮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','銀山鐵壘洞庭秋，又見鴟夷一葉舟。',32,'全唐诗/poet.song.168000.json','["銀山鐵壘洞庭秋，又見鴟夷一葉舟。", "且是雲仍高一著，祗將山水事清遊。"]'),
('8893da86-7290-4540-a455-d54bd402e25f','寄范石湖五首  其三','王阮','宋','宋诗','song-poetry','','[]','湖山奔輳黛眉攢，湖水晶熒鏡面寒。',32,'全唐诗/poet.song.168000.json','["湖山奔輳黛眉攢，湖水晶熒鏡面寒。", "補衮之絲元未盡，西風吹上釣魚竿。"]'),
('4854b372-e0ce-4001-976a-fcbc9893ab5b','寄范石湖五首  其四','王阮','宋','宋诗','song-poetry','','[]','近來能辟千年穀，歸去非思一筯鱸。',32,'全唐诗/poet.song.168000.json','["近來能辟千年穀，歸去非思一筯鱸。", "聊示維摩隠几相，要教獅子致文殊。"]'),
('b15894a9-6e67-43c9-bff6-056b955f9e7a','寄范石湖五首  其五','王阮','宋','宋诗','song-poetry','','[]','彭澤歸來我自安，壺中尤覺太虛寬。',32,'全唐诗/poet.song.168000.json','["彭澤歸來我自安，壺中尤覺太虛寬。", "世間萬事都忘盡，只有公盟不敢寒。"]'),
('b85db7cc-c428-455b-93af-8cb266423502','遇流民有感一首','王阮','宋','宋诗','song-poetry','','[]','行盡江南處處山，無錢歸去買山閑。',32,'全唐诗/poet.song.168000.json','["行盡江南處處山，無錢歸去買山閑。", "自憐不在施爲地，空對流民數汗顔。"]'),
('f61c7b4d-ae8f-4d7d-b8f4-840f623f4f6b','過桃川萬壽宮二首  其一','王阮','宋','宋诗','song-poetry','','[]','人共桃花事一空，兔葵無數舞春風。',32,'全唐诗/poet.song.168000.json','["人共桃花事一空，兔葵無數舞春風。", "傷心俯仰成今古，知與劉郎事不同。"]'),
('0b796a31-7095-40ae-a3b8-0e2f31af9689','過桃川萬壽宮二首  其二','王阮','宋','宋诗','song-poetry','','[]','甕子洞頭魂黯黯，桃川山上目悽悽。',32,'全唐诗/poet.song.168000.json','["甕子洞頭魂黯黯，桃川山上目悽悽。", "自憐終失邯鄲步，不是重來舊路迷。"]'),
('f5f89f42-da66-4568-aa53-a90a2030c67b','題惠山泉一首','王阮','宋','宋诗','song-poetry','','[]','惠山泉似雪初消，不數松江第四橋。',32,'全唐诗/poet.song.168000.json','["惠山泉似雪初消，不數松江第四橋。", "解挹清泠洗氛祲，何時再有李文饒。"]'),
('65f3a82c-46e3-4f68-9833-3740e37e30fc','上巳日青龍道中一首','王阮','宋','宋诗','song-poetry','','[]','身倦尋春事，心懷結夏清。',48,'全唐诗/poet.song.168000.json','["身倦尋春事，心懷結夏清。", "猶臨曲水序，莫續麗人行。", "世態與吾異，生涯何日成。", "殷勤獨相送，江上午潮平。"]'),
('96f753ad-345b-46b3-b8da-9414ac5af141','舍弟挽余爲燈火計已而余出夜夢其以詩來感歎賦一首','王阮','宋','宋诗','song-poetry','','[]','吳頭望楚尾，兩處各窮愁。',48,'全唐诗/poet.song.168000.json','["吳頭望楚尾，兩處各窮愁。", "萬事吾皆失，三冬汝自修。", "人情千仞險，春事九分休。", "夢斷依然處，天涯一釣舟。"]'),
('5b0fdd2c-8a6b-4d47-849a-3d6e8c9cdb82','金市大水一首','王阮','宋','宋诗','song-poetry','','[]','日氣方穿戶，風潮忽及門。',48,'全唐诗/poet.song.168000.json','["日氣方穿戶，風潮忽及門。", "郊原雨脚密，窗牖浪花翻。", "船繫家家屋，帆飛處處村。", "江南一羈客，微命託乾坤。"]'),
('946fc5ea-8fa4-405a-8f86-637c18643e7f','奔牛閘遇使者議和一首','王阮','宋','宋诗','song-poetry','','[]','浩浩水千里，層層隄幾重。',48,'全唐诗/poet.song.168000.json','["浩浩水千里，層層隄幾重。", "誰爲此過顙，曲障爾朝宗。", "浪散忽成雪，潭昏那見龍。", "浮山何足論，聖德務含容。"]'),
('3ed9e343-e2de-4bfe-82bb-c34ce08bbc6f','題金山廟一首','王阮','宋','宋诗','song-poetry','','[]','事業生扶漢，英靈死芘吳。',48,'全唐诗/poet.song.168000.json','["事業生扶漢，英靈死芘吳。", "明知蓋世烈，正速闔門誅。", "日月夷黄道，乾坤衍赤符。", "空令百世下，歎息用心無。"]'),
('51c49356-31fd-424f-9715-557dfcccf491','九日獨泛松江一首','王阮','宋','宋诗','song-poetry','','[]','松江牢落一舟歸，中有人驚歲月違。',64,'全唐诗/poet.song.168000.json','["松江牢落一舟歸，中有人驚歲月違。", "太一自期蓮葉是，白衣何恨菊花非。", "水收四面郊原闊，霜入千山草木稀。", "已分滄洲付吾道，便應從此下漁磯。"]'),
('03bfbd09-346d-4dd5-92b5-507e98147dc0','九日陪金市諸友登高陽山二首  其一','王阮','宋','宋诗','song-poetry','','[]','途窮已負菊花期，尚得諸公慰所思。',64,'全唐诗/poet.song.168000.json','["途窮已負菊花期，尚得諸公慰所思。", "不遣白衣持酒至，共將烏帽入風吹。", "紫萸秋淺浮觴少，黄葉山高策杖遲。", "却恨社中人闕一，未將湯餠共追隨。"]'),
('754719e4-740a-4c92-8eeb-5cc57c6d51fb','九日陪金市諸友登高陽山二首  其二','王阮','宋','宋诗','song-poetry','','[]','讀書懷古恨難逢，不謂斯時乃有公。',64,'全唐诗/poet.song.168000.json','["讀書懷古恨難逢，不謂斯時乃有公。", "心自對談名利外，士知增價品題中。", "一樽此地論文樂，三逕何年結社同。", "待得塵蹤去留决，別將消息寄東風。"]'),
('9c94bfd1-f2c7-4fc6-b436-a343b0335ec7','龍塘久別乘月再到奉呈同社一首','王阮','宋','宋诗','song-poetry','','[]','龍塘疇昔擅雲烟，破月重來倍爽然。',64,'全唐诗/poet.song.168000.json','["龍塘疇昔擅雲烟，破月重來倍爽然。", "浮玉北堂三萬頃，扁舟西子二千年。", "青山識面爭迎櫂，白鷺知心不避船。", "華髮翛翛更何往，一茅終在此橋邊。"]'),
('c168b6be-d022-44ab-b6ca-40f638dc69ce','再用前韻一首','王阮','宋','宋诗','song-poetry','','[]','已無功業上凌煙，且泛扁舟逐計然。',64,'全唐诗/poet.song.168000.json','["已無功業上凌煙，且泛扁舟逐計然。", "自喜茲遊勝平日，不知今夕是何年。", "橫空蝃蝀聊欹枕，滿袖嬋娟永共船。", "同社賢豪多載酒，坐添清興浩無邊。"]'),
('6e5aa609-4b27-4fd9-96fd-e4afecfcfa28','姑蘇泛月一首','王阮','宋','宋诗','song-poetry','','[]','夜來誰共泛靈槎，飛上牽牛織女家。',64,'全唐诗/poet.song.168000.json','["夜來誰共泛靈槎，飛上牽牛織女家。", "但覺滿身天雨露，絕無一點世塵沙。", "秋將寒玉清風陣，月借鎔銀潑浪花。", "投曉歸來互相告，等閑休向俗人誇。"]'),
('bf709465-1b96-47f6-9ffa-bf9614495a52','九月六日泛舟航村而舟人不審誤抵道場之麓越二日登焉因過何山謾賦一首','王阮','宋','宋诗','song-poetry','','[]','千巖矗空濛，一水還葱蒨。',156,'全唐诗/poet.song.168000.json','["千巖矗空濛，一水還葱蒨。", "寺從馴虎立，山作盤龍轉。", "嗟予千里來，適此十年願。", "初拏蓮葉舟，誤逐桃花片。", "重携九節筇，上盡百結線。", "陰崖滴翠寒，竹韻含風戰。", "樹色爭煙霏，泓甃靡旱暵。", "載窺窣堵尖，平視蒼狗變。", "樓閣撐山光，城郭瞰波面。", "未覺髀肉酸，先苦銀海眩。", "晚尋小溪曲，更得何山便。", "平疇翠浪湧，返照金色現。", "回首笑月亭，消息真已薦。"]'),
('f7bd4837-2b1e-466e-997a-c84102bcd2db','留別金市諸友一首','王阮','宋','宋诗','song-poetry','','[]','扁舟昔東下，徒步却西歸。',48,'全唐诗/poet.song.168000.json','["扁舟昔東下，徒步却西歸。", "久客幸無恙，諸公皆可依。", "途窮須暫哭，鳥倦不能飛。", "他日相尋地，江南一翠微。"]'),
('b517b467-7f7a-43c0-98d6-184e019f59bd','都昌沿檄黟歙遇春一首','王阮','宋','宋诗','song-poetry','','[]','忽忽年華換，悠悠客路長。',48,'全唐诗/poet.song.168000.json','["忽忽年華換，悠悠客路長。", "春聲先水響，山氣欲花香。", "何補公家事，空隨吏役忙。", "白雲知此意，一片直都昌。"]'),
('4c6fe0b3-c08b-40d8-a8c9-742a33bdf4d9','陪諸公登廣福觀下望鼓蠡一首','王阮','宋','宋诗','song-poetry','','[]','水遶一圍带，山橫八字眉。',48,'全唐诗/poet.song.168000.json','["水遶一圍带，山橫八字眉。", "壯哉極目地，慰此凭欄時。", "剡縣可乘興，渼陂真好奇。", "相逢休務日，因得數言詩。"]'),
('3ef2f79e-f4d3-4434-8bec-13d6f23a39af','題落星寺一首','王阮','宋','宋诗','song-poetry','','[]','島石是處有，星辰曾霣無。',48,'全唐诗/poet.song.168000.json','["島石是處有，星辰曾霣無。", "莊嚴成凈土，怪誕出浮屠。", "蜃氣樓穿海，龍堆沙擁湖。", "盡除金碧像，吾欲舍吾徒。"]'),
('84ef66d1-ecd4-449d-86ef-f10efc7e014b','傳舍中竹一首','王阮','宋','宋诗','song-poetry','','[]','浪蘂浮花不足看，歲寒獨與此君觀。',64,'全唐诗/poet.song.168000.json','["浪蘂浮花不足看，歲寒獨與此君觀。", "籜龍滿野今千變，翔鳳何時下一餐。", "日對吏文瀟灑在，天生官地保全難。", "明年我亦江湖去，尚祝同年乞釣竿。"]'),
('d0ae9868-387b-4f4a-9e26-772d3a7adf47','除夕有感一首','王阮','宋','宋诗','song-poetry','','[]','不是功難立，其如興自闌。',48,'全唐诗/poet.song.168000.json','["不是功難立，其如興自闌。", "爲貧姑寸祿，漸喜得閑官。", "天下兵戈滿，壺中日月寬。", "慇懃除夜雪，衰謝莫能歡。"]'),
('bcda4f79-6260-44cd-9d84-14960a2ddcfc','秋日寄舍弟一首','王阮','宋','宋诗','song-poetry','','[]','一從婚宦別家鄉，又見西風雁作行。',64,'全唐诗/poet.song.168000.json','["一從婚宦別家鄉，又見西風雁作行。", "卧念昔言乘款段，夢尋新句得池塘。", "猿驚鶴怨草三尺，楚尾吳頭天一方。", "歸去兒童定相笑，秋容已上鬢邊霜。"]'),
('715de368-725e-4fca-b23a-466e887ede5e','九日途中有感一首','王阮','宋','宋诗','song-poetry','','[]','九日登高是故常，只今何事負年芳。',64,'全唐诗/poet.song.168000.json','["九日登高是故常，只今何事負年芳。", "紫萸欲佩憑誰繫，黄菊無人只自香。", "開拓愁邊須酒陣，包羅風景入詩囊。", "遥應親老持杯夜，肴核橫陳畫燭光。"]'),
('68dcf609-3ecf-45e3-9f2e-e69e189a2a9f','湖南道中三首  其一','王阮','宋','宋诗','song-poetry','','[]','失脚南來又兩年，故山猿鶴祇凄然。',32,'全唐诗/poet.song.168000.json','["失脚南來又兩年，故山猿鶴祇凄然。", "瀟湘不是無佳景，終覺壺中別有天。"]'),
('e4c6d113-cd54-4597-bbe0-27175b087f98','湖南道中三首  其二','王阮','宋','宋诗','song-poetry','','[]','已分餘生老一丘，尚因微祿少遲留。',32,'全唐诗/poet.song.168000.json','["已分餘生老一丘，尚因微祿少遲留。", "夢魂不待山資足，先入江南問釣舟。"]'),
('0f42cec3-38e8-488c-8e82-874e27fe2f15','湖南道中三首  其三','王阮','宋','宋诗','song-poetry','','[]','萬壑千巖我一家，別來空自鎖煙霞。',32,'全唐诗/poet.song.168000.json','["萬壑千巖我一家，別來空自鎖煙霞。", "閑雲不放行人望，故向東南角上遮。"]'),
('e4f234e1-9905-426e-a039-e51d2fb6b17e','登衡嶽三首  其一','王阮','宋','宋诗','song-poetry','','["\u8861\u5c71"]','羶羊腥犬沸中原，五嶽之中四嶽昏。',32,'全唐诗/poet.song.168000.json','["羶羊腥犬沸中原，五嶽之中四嶽昏。", "節義衡山獨不辱，萬年千載戴明恩。"]'),
('6563d57a-932a-421a-8f08-fd43e8c1dcfb','登衡嶽三首  其二','王阮','宋','宋诗','song-poetry','','["\u8861\u5c71"]','白衣蒼狗飛揚盡，翠巘蒼崖杖屨間。',32,'全唐诗/poet.song.168000.json','["白衣蒼狗飛揚盡，翠巘蒼崖杖屨間。", "獨到上封雷雨處，退之元未識衡山。"]'),
('5fde92fc-26eb-4f8e-8a3d-bfe1481d7c39','登衡嶽三首  其三','王阮','宋','宋诗','song-poetry','','[]','絕境當須著好詞，衰懷已覺不勝奇。',32,'全唐诗/poet.song.168000.json','["絕境當須著好詞，衰懷已覺不勝奇。", "煩君試向仙家問，怕有彌明更解詩。"]'),
('6711e224-c3a3-4ff6-b9f9-107ca917006a','題淡巖一首','王阮','宋','宋诗','song-poetry','','[]','浯溪已借元碑顯，愚谷還因柳序稱。',32,'全唐诗/poet.song.168000.json','["浯溪已借元碑顯，愚谷還因柳序稱。", "獨有淡巖人未識，故煩山谷到零陵。"]'),
('c651bbfc-ce0e-4881-98de-d6b6560e5a19','雪竇瀑布一首','王阮','宋','宋诗','song-poetry','','[]','碧空無雨忽潺潺，此水何人激在山。',64,'全唐诗/poet.song.168000.json','["碧空無雨忽潺潺，此水何人激在山。", "塔現玉光依石側，柱因冰凍瀝簷間。", "長風浩蕩更相和，元氣淋漓挽不還。", "欲究本來源出處，湘江誰借一枝斑。"]'),
('5c5dc5ab-4017-4bb8-8169-3372c97aeb4a','試院二首  其一','王阮','宋','宋诗','song-poetry','','[]','老催人去樂滄浪，十幅輕帆便可張。',32,'全唐诗/poet.song.168000.json','["老催人去樂滄浪，十幅輕帆便可張。", "尚有選材王事在，夜深來此校文章。"]'),
('28bf7b23-b3db-4151-ae18-40805d9ea8c2','試院二首  其二','王阮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','雨浸霜華冷作秋，廣文官舍益窮愁。',32,'全唐诗/poet.song.168000.json','["雨浸霜華冷作秋，廣文官舍益窮愁。", "夢魂却似知人意，偏到廬山脚下州。"]'),
('e8eeb4b7-ef16-4670-8a05-8820fcd57e1d','竹齋二首  其一','王阮','宋','宋诗','song-poetry','','[]','一圍寒綠鎖城闉，中有茅簷更絕塵。',32,'全唐诗/poet.song.168000.json','["一圍寒綠鎖城闉，中有茅簷更絕塵。", "千戶封侯千畝是，可憐燕頷虎頭人。"]'),
('269d2982-f268-4a4d-8bd9-8ac5f46eaa11','竹齋二首  其二','王阮','宋','宋诗','song-poetry','','[]','清陰翠色滿湘山，月下風前極目間。',32,'全唐诗/poet.song.168000.json','["清陰翠色滿湘山，月下風前極目間。", "第一莫污兒女淚，失身嫌作杖頭斑。"]'),
('91d09d71-5751-444c-bc12-4980ee2517e5','見梅有感一首','王阮','宋','宋诗','song-poetry','','[]','十月瀟湘盡放梅，南枝仍避北枝開。',32,'全唐诗/poet.song.168000.json','["十月瀟湘盡放梅，南枝仍避北枝開。", "客愁無奈春消息，腸斷江南驛使來。"]'),
('bff9456f-ae22-4d3b-9237-f05daa1a9360','次德和韻寄談李二丈二首  其一','王阮','宋','宋诗','song-poetry','','[]','心在淮山下，身行湘水中。',48,'全唐诗/poet.song.168000.json','["心在淮山下，身行湘水中。", "喜拋餘子去，恨不故人同。", "舊隠勞征夢，浮名任化工。", "衡陽春漸暖，終欲伴歸鴻。"]'),
('7d0d8e4d-3eb2-4671-b991-ac10b493abe1','次德和韻寄談李二丈二首  其二','王阮','宋','宋诗','song-poetry','','[]','喜脫諸公忌，愁違李與談。',48,'全唐诗/poet.song.168000.json','["喜脫諸公忌，愁違李與談。", "離群江以北，弔影楚之南。", "世故更千萬，心朋只二三。", "果能容我與，終共結茆庵。"]'),
('9a5e1fab-41fb-42f1-8e9b-ca88d0561901','次韻葉教二首  其一','王阮','宋','宋诗','song-poetry','','[]','但有形如槁，元無貨可珍。',48,'全唐诗/poet.song.168000.json','["但有形如槁，元無貨可珍。", "四方長逆旅，一念即明神。", "漫仕緣將母，非材敢教人。", "無功叨廩祿，祗覺蠹吾民。"]'),
('d97f3fed-4aa4-4155-8c46-b2e60385afe3','次韻葉教二首  其二','王阮','宋','宋诗','song-poetry','','[]','汩汩誠甘分，空空敢自珍。',48,'全唐诗/poet.song.168000.json','["汩汩誠甘分，空空敢自珍。", "樂雖思泮水，愚恐累溪神。", "怨謗從餘子，稱揚獨故人。", "功名非我事，自是葛天民。"]'),
('21bca7dd-2c91-48f0-b845-d92b7b8ec875','次韻來梓見贈一首','王阮','宋','宋诗','song-poetry','','[]','無心穀璧陪蒲璧，有分山光映水光。',64,'全唐诗/poet.song.168000.json','["無心穀璧陪蒲璧，有分山光映水光。", "子賤假令宜單父，淵明終合在柴桑。", "爲氓且盡今生力，責子寧須後代昌。", "爲問故人緣底事，不來同醉酒醅香。"]'),
('461e8439-f86d-406a-869b-61eb3fd44142','薦福寺一首','王阮','宋','宋诗','song-poetry','','[]','十七年間一夢迷，重來渾不辨東西。',32,'全唐诗/poet.song.168000.json','["十七年間一夢迷，重來渾不辨東西。", "院中誰識前時客，莫莫堂前老木犀。"]'),
('2dd07329-408a-4e31-9927-373839407b1a','普陀山觀音巖祈雨一首','王阮','宋','宋诗','song-poetry','','[]','南風不爲雨，躬即寶陀求。',48,'全唐诗/poet.song.168000.json','["南風不爲雨，躬即寶陀求。", "地勢到此盡，天河相接流。", "鼇舒千丈背，蜃吐數層樓。", "念彼觀音力，楊枝洒有秋。"]'),
('50508c78-fb8f-4842-b8ca-a1eb827174ff','陳彌高惠詩次韻言謝一首','王阮','宋','宋诗','song-poetry','','[]','南來日日訪人才，始得清詩副所懷。',64,'全唐诗/poet.song.168000.json','["南來日日訪人才，始得清詩副所懷。", "我計已成桴入海，君行初似橘踰淮。", "十年旅夢思乘興，千里征塵忽及階。", "見說又爲勳業去，獨能無意侶洪崖。"]'),
('d1dd2305-7dc4-43e5-b8c0-4318a84e6d7b','勸農題吉祥寺一首','王阮','宋','宋诗','song-poetry','','[]','傍石尋幽徑，窮原得梵城。',48,'全唐诗/poet.song.168000.json','["傍石尋幽徑，窮原得梵城。", "潮聲四面合，山色一團清。", "農合巡門勸，僧煩倒屣迎。", "明年吾更健，來伴此中耕。"]'),
('f92e35d4-3dd7-4307-8dfd-5e377e80e763','劉致政家東岡池蓮甚盛昔嘗飲焉賦此敘別二首  其一','王阮','宋','宋诗','song-poetry','','[]','一枝曾吸碧筩杯，萬丈潮頭忽見催。',32,'全唐诗/poet.song.168000.json','["一枝曾吸碧筩杯，萬丈潮頭忽見催。", "斜倚闌干獨惆悵，明年應是不能來。"]'),
('e3d32339-88ff-4d7c-8119-5b44c8e1a380','劉致政家東岡池蓮甚盛昔嘗飲焉賦此敘別二首  其二','王阮','宋','宋诗','song-poetry','','[]','世路東西自此分，酒樽何日再論文。',32,'全唐诗/poet.song.168000.json','["世路東西自此分，酒樽何日再論文。", "虎蹲山下一回首，望斷東岡是海雲。"]'),
('5e50cab7-e4b8-4174-9c8e-c44b651d43d8','浙江觀潮一首','王阮','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','水向東南聚，氣鍾子午間。',48,'全唐诗/poet.song.168000.json','["水向東南聚，氣鍾子午間。", "大洋一沸鼎，衆溜各循環。", "高岸忽爲谷，疾雷驚破山。", "三年浮海客，見此悟生還。"]'),
('6b972cc0-5021-40fd-83e6-cf78b1df0d3b','廣中南華寺一首','王阮','宋','宋诗','song-poetry','','[]','一水透南粵，高人憶老盧。',48,'全唐诗/poet.song.168000.json','["一水透南粵，高人憶老盧。", "如何拈不起，只爲本來無。", "匍匐三千里，披攘五百徒。", "都來些子事，焉用爾區區。"]'),
('14b1c836-fb42-436c-a64c-ce39e4a6ae9c','廣中二首  其一','王阮','宋','宋诗','song-poetry','','[]','黑金不肯化青金，奉命來催膽水淋。',64,'全唐诗/poet.song.168000.json','["黑金不肯化青金，奉命來催膽水淋。", "山骨舊疑天鑿透，溝流唯待雨來深。", "丹無九轉如方士，政有三官出上林。", "却謝黄茅除白髮，爲酬平日做僧心。"]'),
('2f23bcf1-88b5-4d03-812c-98094a448e23','廣中二首  其二','王阮','宋','宋诗','song-poetry','','[]','南來風土已安之，事已當還敢故違。',64,'全唐诗/poet.song.168000.json','["南來風土已安之，事已當還敢故違。", "銅柱略無功可錄，玉關空幸死前歸。", "眼看餘劑憐猶在，力凭征鞍覺尚微。", "此去上還官印綬，却來傳授祖師衣。"]'),
('ca7d09de-0f11-4827-a521-036f170ba9f9','黄公灘一首','王阮','宋','宋诗','song-poetry','','[]','水泝安流舟不難，人心自畏石頭頑。',32,'全唐诗/poet.song.168000.json','["水泝安流舟不難，人心自畏石頭頑。", "黄公誤聽作惶恐，玉局先生蓋謂灘。"]'),
('d007792b-0d2c-46da-a3b8-d02246185f7b','廬山太平宮一首','王阮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','貝闕岧嶤不可攀，遥分絳節下人間。',64,'全唐诗/poet.song.168000.json','["貝闕岧嶤不可攀，遥分絳節下人間。", "起元立道幾千歲，擇勝栖神第一山。", "膏雨應時豐綠野，真風與世養朱顔。", "山前老叟非仙骨，悵望丹崖蘚篆斑。"]'),
('26f58408-e839-45cc-a95a-571323f43147','北固山望揚州懷古','王阮','宋','宋诗','song-poetry','','[]','北固城高萬象秋，烟竿一縷認揚州。',64,'全唐诗/poet.song.168000.json','["北固城高萬象秋，烟竿一縷認揚州。", "試乘綠漲三篙水，要見朱簾十里樓。", "淚濕宮衣朝霧重，愁熏塞草夕陽浮。", "隋堤舊事無人問，兩兩垂楊繫客舟。"]'),
('613de4f2-19ec-4d75-991e-a26ab8f38904','曉起甘蔗洲','鞏豐','宋','宋诗','song-poetry','','[]','曉起東風惡，晴嵐忽變昏。',48,'全唐诗/poet.song.168000.json','["曉起東風惡，晴嵐忽變昏。", "船隨山共走，霧與水相吞。", "鉦鼓遥知寨，桑麻略辨村。", "雨來無準則，容易濕柴門。"]'),
('e0e9e5f2-dcca-4f37-a13b-8a3c871393b8','夜雨曉起方覺','鞏豐','宋','宋诗','song-poetry','','[]','夜雨鳴簷送五更，不驚高卧最多情。',64,'全唐诗/poet.song.168000.json','["夜雨鳴簷送五更，不驚高卧最多情。", "窗間細視花無恙，牆外隨聽屐有聲。", "數把柔絲堤柳嫩，一奩方鏡閘波清。", "出門眼界殊明潔，但覺春寒處處生。"]'),
('ea4b99a5-80ae-4b73-ac61-81aaafffd615','晨征','鞏豐','宋','宋诗','song-poetry','','[]','靜觀羣動亦勞哉，豈獨吾爲旅食催。',64,'全唐诗/poet.song.168000.json','["靜觀羣動亦勞哉，豈獨吾爲旅食催。", "雞唱未圓天已曉，蛙鳴初散雨還來。", "清和入序殊無暑，小滿先時政有雷。", "酒賤茶饒新麵熟，不妨乘興且徘徊。"]'),
('d369068b-1547-464e-b592-deacfe472076','離建','鞏豐','宋','宋诗','song-poetry','','[]','旅中多得早朝晴，野潤衣襟苦未清。',64,'全唐诗/poet.song.168000.json','["旅中多得早朝晴，野潤衣襟苦未清。", "時時數點雨猶落，隠隠一聲雷不驚。", "山入夏來差覺老，花從春去久無情。", "長汀又涉來時路，麥隴桑村小問程。"]'),
('cd96a8cd-60d3-4497-be72-05176d355a68','湖嶺下十里是爲湆澹灘行者多至此捨舟','鞏豐','宋','宋诗','song-poetry','','[]','急流方了又高岡，日永周旋未覺忙。',64,'全唐诗/poet.song.168000.json','["急流方了又高岡，日永周旋未覺忙。", "壁上字多知店老，嶺邊松茂喜車涼。", "叢叢亂篠承欹石，帖帖新荷戀小塘。", "湆澹惡灘應笑我，爲虞魚腹犯羊腸。"]'),
('f3dc57cf-c224-4adc-a417-3cf13047cf8a','寒夜','鞏豐','宋','宋诗','song-poetry','','[]','瓦欲飛霜水欲冰，蒲團今夜有塵凝。',64,'全唐诗/poet.song.168000.json','["瓦欲飛霜水欲冰，蒲團今夜有塵凝。", "爐寒閒取薪添火，窗暗時將燭助燈。", "久欲歸田游宦客，未能忘肉在家僧。", "於書更覺心情懶，病眼愁看細字蠅。"]'),
('a740975b-9569-4461-b534-72b7baa2d289','中旬休日呈巖老','鞏豐','宋','宋诗','song-poetry','','[]','近見東郊出土牛，燒燈已過又旬休。',64,'全唐诗/poet.song.168000.json','["近見東郊出土牛，燒燈已過又旬休。", "酸風鱗面慵開眼，細雨毛空怯上樓。", "百歲光陰真蟻穴，一年寒燠未鴻溝。", "偷閑文字聊遮眼，勳業悠悠且掉頭。"]'),
('1783c024-9b10-457a-8a14-adab97965f6c','哀呂東萊','鞏豐','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嗚呼呂夫子，天姿素顒昂。',288,'全唐诗/poet.song.168000.json','["嗚呼呂夫子，天姿素顒昂。", "文獻紹家學，刻意稽虞唐。", "看書眼如月，洞照所未詳。", "雲霧養豹質，彜尊瑑龍章。", "椎鋒裹頭歲，躡足遊四方。", "取友半楚越，篤志日自强。", "著眼囂塵上，口不掛否臧。", "堅車遵大路，驂轡多王良。", "筆陣萬人敵，嚴嚴亞夫營。", "既壯道愈焯，維斗揭太常。", "朝路閲時變，有意夫明昌。", "嗚呼命非耶，一病俄殂喪。", "百年能幾見，痛在予衷腸。", "恭惟經濟學，日就而月將。", "便便五經笥，笑視古錦囊。", "訂史參理亂，一一堪施行。", "聖伏道絕塞，繄我爲發明。", "無心著師說，獨遜時輩聲。", "盤礴九雲夢，胸次莫與京。", "爐烟對姬孔，脫落翰墨場。", "耳目所纂輯，如春之發生。", "退然避時譽，歛衽不肯當。", "居憂寄蕭寺，舉俗載其名。", "戶外履常滿，攝齊願升堂。"]'),
('50480e05-97a1-418a-9845-e1afcc37ef1c','芋洋嶺背聞雨聲滿山細聽林上槁葉風過之相戛擊而成音後先疏數中節清絕難狀篷籠夜雨未足爲奇','鞏豐','宋','宋诗','song-poetry','','[]','日未出扶桑，雲猶屯海嶽。',168,'全唐诗/poet.song.168000.json','["日未出扶桑，雲猶屯海嶽。", "宛是欲雨時，朝陰凜巖壑。", "霜林亂葉多，荏苒乾未落。", "颯颯滿空山，細聽微雨作。", "一葉初自吟，萬葉競相謔。", "就彼最高枝，相摩應宮角。", "燥響欲相憑，風來能領略。", "須臾不聞風，但聽雨索索。", "是雨亦無奇，如雨乃可樂。", "風停葉靜時，雨從何處著。", "霜野物聲乾，終带塵土濁。", "篷音非出虛，瓢音太傷朴。", "得似此聲清，瀟灑過笙鶴。", "天籟者非耶，夔襄不能學。"]'),
('d1ab991d-5f03-43ed-94ff-50422faa1c20','送湯麟之秀才往漢東從徐省元教授學詩','鞏豐','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','士遊鄉校間，如舟試津浦。',272,'全唐诗/poet.song.168000.json','["士遊鄉校間，如舟試津浦。", "所見小溪山，未見大島嶼。", "一旦遠游學，如舟涉江湖。", "所見寖以廣，變怪驚龍魚。", "人生本自有丘壑，陋巷棲遲窮亦樂。", "何必三江暨五湖，始助胸中疆界拓。", "我言隨寓耳目移，馬遷所以游會稽。", "向令俯僂但京國，未必大放雄深詞。", "君今濯秀雙溪水，下語不凡真可喜。", "若使循爲舉子文，定自棘門兒戲耳。", "古來妙技如屠龍，不療饑餒徒爲工。", "不如高科取富貴，如一棗葉持鍼鋒。", "挾冊將遊隨子國，親賢況是諸侯客。", "曾將好手冠南宮，行當闊步趨文石。", "奮飛欲往氣莫降，蒹葭莽莽天雨霜。", "揚瀾左蠡吞九澤，大孤小孤插長江。", "請停詩筆莫容易，大義聯翩且周禮。", "路途千里負笈人，併以經塗相指似。"]'),
('097a451d-9cf1-4b85-be1e-025de09fc8a4','大孤','鞏豐','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','大孤小孤在何許，大磯小磯忽當浦。',96,'全唐诗/poet.song.168000.json','["大孤小孤在何許，大磯小磯忽當浦。", "顛風吹浪未肯停，厭聽蕭蕭打篷雨。", "今春積雪深復深，爛銀猶照廬山陰。", "狐裘欲脫未可脫，蟻醁當斟誰與斟。", "晚來潮面烏如石，遥看知是長魚脊。", "篙人且下鐵貍奴，更與風波鬭今夕。"]'),
('88fd5fc8-4005-4e6d-acbf-12d8a21c0951','二蟲吟','鞏豐','宋','宋诗','song-poetry','','[]','鯤鵬至大兮，形載于莊周逍遥之篇。',176,'全唐诗/poet.song.168000.json','["鯤鵬至大兮，形載于莊周逍遥之篇。", "蟋蟀至小兮，名託于周公七月之雅。", "一則變化徙天池，一則悲鳴入牀下。", "周公作詩陳艱難，瑣屑如與婦子言。", "天經地緯發真藻，特驅小物歸毫端。", "鵬大無倫世無有，揮斥八極隘宇宙。", "世人有眼不見鵬，直頼莊周爲不朽。", "當年蟋蟀吟秋時，秦家宮殿隋家墀。", "鵬飛雖占九萬里，得地穩密誰如伊。", "大鵬擊水翔寥漠，蟋蟀逢春死籬落。", "二蟲得失何厚薄，天晴日午槐花落。"]'),
('48bfe8ee-e6b8-4c48-8eb7-96453d2a64c2','爲舉子時所用方硯小童滌之誤傷其左角','鞏豐','宋','宋诗','song-poetry','','[]','巾箱硯子何處得，溪翁用作待魚石。',192,'全唐诗/poet.song.168000.json','["巾箱硯子何處得，溪翁用作待魚石。", "博時不費杖頭錢，遂入余家掌文墨。", "父祖相傳晚畀予，自幼相隨真莫逆。", "七星象斗隠約明，一口如池方寸窄。", "憶曾携入對集英，僅畢春秋二三策。", "後來隨宦落江湖，同上武昌題赤壁。", "定交首尾三十所，晏子狐裘虞老屐。", "村童唐突豈偶然，一角微傷真可惜。", "大禹圭璽猶缺殘，因損不妨成友益。", "靈光一殿亦偶存，小物本來甘棄擲。", "贊經禆史則已多，論議失中天賜謫。", "敬追子産謝叔向，息黥補劓全吾璧。"]'),
('551c4eb8-3773-40b8-81d4-0362d1d147df','詠豫章蕉葉素扇','鞏豐','宋','宋诗','song-poetry','','[]','寶月乘鸞空復情，頗嫌携重愛携輕。',64,'全唐诗/poet.song.168000.json','["寶月乘鸞空復情，頗嫌携重愛携輕。", "犀皮赤柄終傷俗，細骨洪蕉竟入清。", "格調不殊蒲處士，工夫全藉楮先生。", "文饒空賦桐花鳳，絢麗虛成畫史名。"]'),
('d6e01e02-1f4b-4b81-9ea9-a505a14e0278','海棠','鞏豐','宋','宋诗','song-poetry','','[]','銜子來東海，仙巢有鳳雛。',240,'全唐诗/poet.song.168000.json','["銜子來東海，仙巢有鳳雛。", "華開新棣萼，莟結小茱萸。", "富貴天專與，嬌柔韻不粗。", "輕盈飛燕趙，韶麗彩鸞吳。", "入譜雖千品，傾城但一株。", "霧藏雲體魄，霜染雪肌膚。", "酒暈欺西子，冰姿笑藐姑。", "暖風唇破玉，寒雨淚凝珠。", "蝶喜穿油幙，蜂羞賦蜜租。", "葉如疎復密，香似有還無。", "浄灌岷江錦，濃施禁國朱。", "欲眠須客去，佯醉索人扶。", "劍外空逢杜，黄州却遇蘇。", "已多歸綺繡，唯未入氍毹。", "金谷非佳妾，雕陰是醜奴。", "自珍紅頰輔，應怪白髭鬚。", "照樹呼銀燭，澆叢命玉轤。", "有詩曾送別，無力爲噓枯。", "尤物空凡馬，芳春過白駒。", "尚憑花藻鑒，摘句已成圖。"]'),
('ea97eea5-06e3-4942-934a-0967288ea04a','炊熟日有愴松楸','鞏豐','宋','宋诗','song-poetry','','[]','小樓吹斷玉笙哀，春半餘寒去復來。',32,'全唐诗/poet.song.168000.json','["小樓吹斷玉笙哀，春半餘寒去復來。", "五歲不澆墳土上，望江心折刺桐開。"]'),
('d6ec924f-25b2-40e8-bac2-1426b82cd6c1','雪汀見二鷗三鵲對立','鞏豐','宋','宋诗','song-poetry','','[]','二鷗三鵲羽毛鮮，立在方沙更可憐。',32,'全唐诗/poet.song.168000.json','["二鷗三鵲羽毛鮮，立在方沙更可憐。", "全似爛柯棋勢裏，白棋初讓黑棋先。"]'),
('d094a183-3f44-48b2-99ad-c249768faec2','晚晴便有春意','鞏豐','宋','宋诗','song-poetry','','[]','風正波平可進橈，水光山影暮相交。',32,'全唐诗/poet.song.168000.json','["風正波平可進橈，水光山影暮相交。", "殘陽欲去猶回首，一抹斜紅曳竹梢。"]'),
('2acdb3a7-16c0-4769-8a62-358e255e8ff0','洞霄即事','鞏豐','宋','宋诗','song-poetry','','[]','積蘚青踰一寸痕，山靈守護幾千春。',32,'全唐诗/poet.song.168000.json','["積蘚青踰一寸痕，山靈守護幾千春。", "長藤橫繫巖邊木，何日重來挂葛巾。"]'),
('9f061a6e-2d6c-435b-a108-bf299ea65522','翠微亭','鞏豐','宋','宋诗','song-poetry','','[]','行迹年來到處希，獨於巖壑有深期。',32,'全唐诗/poet.song.168000.json','["行迹年來到處希，獨於巖壑有深期。", "鵝溪道士能相屬，請和空山木落詩。"]'),
('79b09552-18e8-4b67-89c9-d2763c868689','翠蛟亭泉出天柱之趾將至洞霄門數折下墜方春盛時如蛟飲澗亭當木石最奇處舊取東坡詩語名以舞翠客謂不若直名翠蛟爲不費答知宮事王君思明欣改之爲賦一首','鞏豐','宋','宋诗','song-poetry','','[]','木石相因依，妙處在得水。',204,'全唐诗/poet.song.168000.json','["木石相因依，妙處在得水。", "遇其相合時，澗蹙水多止。", "巍巍天柱峯，雙洞空無底。", "怪石抱川迴，灌木參天起。", "青蛟走玉骨，玄脈貫石髓。", "屈折暫得伸，掀舞如掉尾。", "亭成自何年，不陋亦不侈。", "秋深泉少縮，亭影照清泚。", "忽遇水飛流，亭在銀濤裏。", "愁蛟捲亭去，相距不盈咫。", "一落墜兩谼，力竭勢方已。", "終疑入江湖，赴海日千里。", "昨夜山雨豪，梧竹盡風靡。", "轟雷與石鬭，蛟怒幾欲死。", "吾亭方宴然，清曉見窗几。", "因携一樽來，與客相料理。", "剩擬畫將歸，題詩却留此。"]'),
('9d1a48b1-a522-451f-85d8-0cb308103f18','迎暉亭','鞏豐','宋','宋诗','song-poetry','','[]','我來將值日午時，千峰照耀碧玻璃。',92,'全唐诗/poet.song.168000.json','["我來將值日午時，千峰照耀碧玻璃。", "集賢村前俯列屋，寶林木石呈幽姿。", "人言可比雙徑雄，勝處乃在阿堵中。", "崇崗層嶂屹亭在，似約老眼來窺東。", "日出烏鳥飛，日入牛羊下。", "再遊當與夸父期，不用山僧遠迎迓。"]'),
('8fb28a5a-7084-45f5-a876-a4c0f526974a','題阮孚墓','鞏豐','宋','宋诗','song-poetry','','[]','千古高風挽不回，故山花落又花開。',32,'全唐诗/poet.song.168000.json','["千古高風挽不回，故山花落又花開。", "莫欺亭畔蒼蒼蘚，曾印高人屐齒來。"]'),
('595a79d8-df85-42a4-bff6-4f7383739080','句  其一','鞏豐','宋','宋诗','song-poetry','','[]','簷端疎竹前生瘦，瓶裏寒梅到死香。',16,'全唐诗/poet.song.168000.json','["簷端疎竹前生瘦，瓶裏寒梅到死香。"]'),
('268adc48-9423-4520-8426-3865a608c97e','句  其二','鞏豐','宋','宋诗','song-poetry','','[]','嬌容自是難將息，也愛春晴也怕晴。',16,'全唐诗/poet.song.168000.json','["嬌容自是難將息，也愛春晴也怕晴。"]'),
('2dd943c9-4376-459f-b1da-9ad4ade593ce','瓊花','趙師𢍰','宋','宋诗','song-poetry','','[]','香得坤靈秀氣全，蘂珠團外蝶翩翩。',32,'全唐诗/poet.song.168000.json','["香得坤靈秀氣全，蘂珠團外蝶翩翩。", "親曾后土祠中看，不是人間聚八仙。"]'),
('559cf966-5e76-48a9-b130-ed293dc14a78','駕詣景寧宮行春','趙師𢍰','宋','宋诗','song-poetry','','[]','風傳御道蹕聲清，兩道紗籠列火城。',32,'全唐诗/poet.song.168000.json','["風傳御道蹕聲清，兩道紗籠列火城。", "雲護帝尊天未曉，衆星環拱極星明。"]'),
('fac8b9bd-1d20-429a-adf0-025a6c6de294','綠萼梅','趙師𢍰','宋','宋诗','song-poetry','','[]','南枝飛影到橫窗，點點凌寒學弄妝。',64,'全唐诗/poet.song.168000.json','["南枝飛影到橫窗，點點凌寒學弄妝。", "玉色不親紅粉鏡，冰肌宜褪綠羅裳。", "向人驕小春先動，越樣尖新夜更香。", "不爲此花排日醉，廣平真是鐵心腸。"]'),
('4640b218-5667-4a34-8446-98f1dbd316ee','元夕','趙師𢍰','宋','宋诗','song-poetry','','[]','古來燈火盛維揚，今歲元宵樂未央。',32,'全唐诗/poet.song.168000.json','["古來燈火盛維揚，今歲元宵樂未央。", "祇欠明皇擁仙仗，綵雲高處舞霓裳。"]'),
('95c1364c-6a81-435d-b39b-015a93bcbefe','句','趙師𢍰','宋','宋诗','song-poetry','','[]','都在吟情句眼中。',8,'全唐诗/poet.song.168000.json','["都在吟情句眼中。"]'),
('8f4d2be0-3d86-485a-8d0d-be866a7c11ff','賢牧堂','朱萬年','宋','宋诗','song-poetry','','[]','師𢍰使衆作祠堂，要學朱張與鄭王。',32,'全唐诗/poet.song.168000.json','["師𢍰使衆作祠堂，要學朱張與鄭王。", "大家飛上梧桐樹，自有旁人說短長。"]'),
('6d54237f-05bc-49ad-ab51-da9a7c2df81d','游虎丘','趙彥橚','宋','宋诗','song-poetry','','[]','文書窮日幾時休，得得尋幽到虎丘。',64,'全唐诗/poet.song.168000.json','["文書窮日幾時休，得得尋幽到虎丘。", "望處平蕪迷遠近，林端飛鳥去夷猶。", "吳王事古遺人恨，西子名存逝水流。", "從昔邦君多賦詠，可無一事繼前修。"]'),
('aeb0bb4f-6bd2-45db-9742-ce8fff379738','仲夏賞月次雪齋韻','司馬儼','宋','宋诗','song-poetry','','[]','世事故前定，冥符今夜圓。',48,'全唐诗/poet.song.168000.json','["世事故前定，冥符今夜圓。", "詩同人偶合，酒與月俱全。", "萬物自有數，一毫皆係天。", "人生莫惆悵，對景數招延。"]'),
('caa40e72-638f-4faf-88ba-9b5fa3f2085d','廣惠倉','廖唐英','宋','宋诗','song-poetry','','[]','屢豐多黍稌，先備富倉箱。',36,'全唐诗/poet.song.168000.json','["屢豐多黍稌，先備富倉箱。", "豈但三年蓄，優爲萬室藏。", "君恩何以報，努力事耕桑。"]'),
('5466374a-a7ad-4a62-9aff-c7e82267cac3','白紵詞','郭晞宗','宋','宋诗','song-poetry','','[]','遥夜迢迢夜未央，井梧月色啼寒螿，感時念往誰不傷。',80,'全唐诗/poet.song.168000.json','["遥夜迢迢夜未央，井梧月色啼寒螿，感時念往誰不傷。", "婕妤寵絕辭昭陽，手中團扇篋中藏。", "吳姬織紵秋蟬翼，一絲往復千情積。", "金粟尺量金斗熨，爲君裁袍爲君惜，同盛同衰莫相失。"]'),
('72728fa9-4ba6-4a5e-ae50-dd5a6dbccd5d','姑蘇臺','郭晞宗','宋','宋诗','song-poetry','','[]','春花開，秋雁來，長風幾度姑蘇臺。',36,'全唐诗/poet.song.168000.json','["春花開，秋雁來，長風幾度姑蘇臺。", "不見臺上人，臺下月徘徊，一樹梧桐生綠苔。"]'),
('be3d2f38-4960-4833-a392-a21248185c5f','水簾泉','周緒','宋','宋诗','song-poetry','','[]','群峯峩峩衝北極，一水如簾瀉層碧。',64,'全唐诗/poet.song.168000.json','["群峯峩峩衝北極，一水如簾瀉層碧。", "嶽神自古不許捲，留在眼前蒙怪石。", "綵霞倒影朝爲緣，缺月遥掛當幽夕。", "非惟只助小山景，却入民田作膏澤。"]'),
('320c4b42-c48d-45ce-8b7e-09a181dab139','書事','周緒','宋','宋诗','song-poetry','','[]','北客樂馳驅，髀肉渾不生。',108,'全唐诗/poet.song.168000.json','["北客樂馳驅，髀肉渾不生。", "輕風入馬蹄，一瞬萬里平。", "朝發長安都，暮抵受降城。", "陰山聞鬼哭，征人晝夜行。", "黄塵雖染衣，紫翠堪奪睛。", "男兒平生遊，壯志多屢驚。", "荆楚豈不佳，舟楫非吾情。", "休誇魚稻鄉，莫戀烟波清。", "幸能脫毛錐，側聽匣中鳴。"]'),
('04f753f7-dd62-4536-a8c0-548d1b421f5c','黄陵題詠二首  其一','林采','宋','宋诗','song-poetry','','[]','艤棹黄陵岸，虔趨帝女祠。',48,'全唐诗/poet.song.168000.json','["艤棹黄陵岸，虔趨帝女祠。", "奠椒隨楚俗，拂石讀韓碑。", "北渚來何遠，南巡事莫追。", "凄然鼓靈瑟，起舞想馮夷。"]'),
('095a43f4-d492-4415-ac67-464c947bbf06','黄陵題詠二首  其二','林采','宋','宋诗','song-poetry','','[]','地接熊湘尾，天開龍壽山。',48,'全唐诗/poet.song.168000.json','["地接熊湘尾，天開龍壽山。", "精藍依石峽，遠岫點煙鬟。", "青草渺茫外，黄陵顧盼間。", "攀緣尋古跡，足倦不知還。"]'),
('18a0b33d-070f-43d4-9f4c-86c6b921c336','勸耕','林采','宋','宋诗','song-poetry','','[]','釣螺江上一耕夫，誤挂簪裳計已疎。',64,'全唐诗/poet.song.168000.json','["釣螺江上一耕夫，誤挂簪裳計已疎。", "來此勸農申告誡，要渠僇力事耕鋤。", "田疇耒耜能無倦，禾稼收成自有餘。", "戶曉更煩諸父老，俾知太守意勸渠。"]'),
('7e0289c7-a42b-4218-9d5f-9eaef07ec002','登覽','林采','宋','宋诗','song-poetry','','[]','二十四峰排玉蒼，天開巖洞若堂堂。',64,'全唐诗/poet.song.168000.json','["二十四峰排玉蒼，天開巖洞若堂堂。", "壇星七點夜橫斗，石佛三身時放光。", "神護奎文常炳煥，仙遺丹灶久凄凉。", "登臨不覺江村暮，歸旗翩翩渡野航。"]'),
('deaff3b7-c717-4ec5-a051-818bdca546de','句','林采','宋','宋诗','song-poetry','','[]','江浙東頭六勸耕，隨緣却到古南平。',16,'全唐诗/poet.song.168000.json','["江浙東頭六勸耕，隨緣却到古南平。"]'),
('7c905928-3112-4443-9a5d-b3d59abeae4e','題李伯時飛騎習射圖','王叔簡','宋','宋诗','song-poetry','','[]','飛毬飲羽柳如截，馬氣橫生人更傑。',80,'全唐诗/poet.song.168000.json','["飛毬飲羽柳如截，馬氣橫生人更傑。", "不作遊觀御寶津，騎戰還應一當百。", "天家行樂少人知，龍眠屬從天上歸。", "意象慘淡研精微，曹霸以來無此奇。", "壯夫披圖雙淚垂，時危那得生致之。"]'),
('efbfeda0-00a4-4ef9-8955-087ca4a59f73','送鶴還齊雲','張釜','宋','宋诗','song-poetry','','[]','胎仙誰遣到塵寰，盡日清吟伴我閑。',64,'全唐诗/poet.song.168000.json','["胎仙誰遣到塵寰，盡日清吟伴我閑。", "不作沖天支遁想，頗疑携箭佐卿還。", "欲追鸞駕煙霞上，肯處雞羣伯仲間。", "爲語齊雲好看取，他年我欲訪緱山。"]'),
('afac3a21-b407-4c78-94be-9618c4edd9f3','游澹巖  其一','張釜','宋','宋诗','song-poetry','','[]','澹巖類古隠君子，一見可洗千劫塵。',64,'全唐诗/poet.song.168000.json','["澹巖類古隠君子，一見可洗千劫塵。", "清曠信出世間境，經行如畫圖中人。", "幽泉涓涓不硋墜，靈草苒苒非關春。", "題詩因昔□游子，冷眼閲盡惟唐珉。"]'),
('cacca04b-2622-4a4b-ad27-07da3fb37512','游澹巖  其二','張釜','宋','宋诗','song-poetry','','[]','真仙窟宅在人境，應有鸞駕乘雲歸。',64,'全唐诗/poet.song.168000.json','["真仙窟宅在人境，應有鸞駕乘雲歸。", "物華創見訝三島，墜脈遠來從九疑。", "有石可礪食蘗齒，有泉可濯凝塵衣。", "清游未足雞報午，一尊會合人生稀。"]'),
('072160f8-dbf4-49ea-bb56-b577c9572593','游山七絕 曾公洞','張釜','宋','宋诗','song-poetry','','[]','欲訪真仙小有天，路窮崖絕俯靈泉。',32,'全唐诗/poet.song.168000.json','["欲訪真仙小有天，路窮崖絕俯靈泉。", "相君聊試濟川手，翳鳳驂鸞盡有緣。"]'),
('5fc6358c-6c59-4213-9b65-4fe7283f19d2','游山七絕 棲霞洞','張釜','宋','宋诗','song-poetry','','[]','雲封霧鎖半天寒，短杖攀緣扣玉關。',32,'全唐诗/poet.song.168000.json','["雲封霧鎖半天寒，短杖攀緣扣玉關。", "見說碧虛風景別，儻容投老寄塵顔。"]'),
('cb3c3aa6-38bb-46ab-b3af-5f26b6a63d7e','游山七絕 龍隠洞','張釜','宋','宋诗','song-poetry','','[]','何年此地蟄飛龍，石壁蜿蜒尚有蹤。',32,'全唐诗/poet.song.168000.json','["何年此地蟄飛龍，石壁蜿蜒尚有蹤。", "爲報龍公莫貪睡，郡人於爾卜豐凶。"]'),
('9e078269-1928-47cd-8016-b59295e515e6','游山七絕 訾家洲','張釜','宋','宋诗','song-poetry','','[]','訾洲風物柳州文，開□□□□夢魂。',32,'全唐诗/poet.song.168000.json','["訾洲風物柳州文，開□□□□夢魂。", "老去一尊酬望眼，淡烟衰草莽連村。"]'),
('56d8af09-ab3f-4a5b-a56c-265e3886800f','游山七絕 水月洞 其一','張釜','宋','宋诗','song-poetry','','[]','水際空明月正圓，人行月裏水如天。',32,'全唐诗/poet.song.168000.json','["水際空明月正圓，人行月裏水如天。", "道旁聽得人爭指，半是當年折桂仙。"]'),
('5bc49bde-69c4-4270-abdb-2f21ee9e1acc','游山七絕 水月洞 其二','張釜','宋','宋诗','song-poetry','','[]','千年佛閣與雲齊，足力窮時目力移。',32,'全唐诗/poet.song.168000.json','["千年佛閣與雲齊，足力窮時目力移。", "堪笑癡兒誇壯麗，那知芥子納須彌。"]'),
('e5dbfde2-c439-488a-aa75-0c12103ecd42','游山七絕 千山觀','張釜','宋','宋诗','song-poetry','','[]','小立東風紫翠顛，畫屏展盡一山川。',32,'全唐诗/poet.song.168000.json','["小立東風紫翠顛，畫屏展盡一山川。", "非關眼界因高別，自是人心逐物遷。"]'),
