('323a8910-8375-449f-af6f-584d92c89a1a','非雪','何坦','宋','宋诗','song-poetry','','[]','鄒子當年吹玉律，解令寒谷暖生春。',32,'全唐诗/poet.song.169000.json','["鄒子當年吹玉律，解令寒谷暖生春。", "豈知此有馮夷宅，六月飛花冷撲人。"]'),
('70655771-c48b-4909-9f48-03868ebde83a','蜂兒榧  其一','何坦','宋','宋诗','song-poetry','','[]','味甘宣郡蜂雛蜜，韻勝雍城駱乳酥。',32,'全唐诗/poet.song.169000.json','["味甘宣郡蜂雛蜜，韻勝雍城駱乳酥。", "一點生春流齒頰，十年飛夢遶江湖。"]'),
('1fd64e27-7087-4bbc-afe9-2ada9e610c4e','蜂兒榧  其二','何坦','宋','宋诗','song-poetry','','[]','銀甲彈開香粉墜，金盤堆起乳花圓。',32,'全唐诗/poet.song.169000.json','["銀甲彈開香粉墜，金盤堆起乳花圓。", "乞君東閣長生供，壽我北堂難老仙。"]'),
('ab82c4bb-1150-40cb-99b3-3ea759c7e198','次張友使吳令君遊石洞韻','何坦','宋','宋诗','song-poetry','','[]','二雋行阡得勝遊，清詩傳播氣橫秋。',64,'全唐诗/poet.song.169000.json','["二雋行阡得勝遊，清詩傳播氣橫秋。", "定知餘子漫千首，竟使老夫低一頭。", "山是玉壺天裏到，水從銀漢罅中流。", "被渠吟作驚人句，壓倒乾坤日夜浮。"]'),
('0795d1a1-215f-4737-9095-54e54fcdad9b','乞釀于郭伯瞻','何坦','宋','宋诗','song-poetry','','[]','洗醆試邀從事醵，卧罍忽報步兵厨。',64,'全唐诗/poet.song.169000.json','["洗醆試邀從事醵，卧罍忽報步兵厨。", "良辰不與清樽共，今夜儻羞明日無。", "未論一缸分雪乳，已拚千日醉雲腴。", "宜黄漫尉今狂甚，聽我酣歌入五湖。"]'),
('569afdea-97b8-4698-9e40-a4e3a64cca3f','集君山','吳竽','宋','宋诗','song-poetry','','[]','生平豪氣老難降，南北中分歎此江。',64,'全唐诗/poet.song.169000.json','["生平豪氣老難降，南北中分歎此江。", "多病能消山屐幾，清游幸尾使旌雙。", "天連遠水碧千里，雲護夕陽紅半窗。", "繾綣主人留客意，船頭昏鼓又逢逢。"]'),
('dea9a903-51e6-45b0-a6ad-1b2e76c859c5','挽通議叔祖呂碩人','熊以寧','宋','宋诗','song-poetry','','[]','旅殯胡塵裏，凄凉七十春。',48,'全唐诗/poet.song.169000.json','["旅殯胡塵裏，凄凉七十春。", "望雲長在念，對食幾傷神。", "烏哺追思切，鰲峯卜□□。", "西風悲楚些，誰不淚沾巾。"]'),
('7c953fcd-2273-4b5d-a0b3-e3a9949304ac','挽伯父二首  其一','熊以寧','宋','宋诗','song-poetry','','[]','白髮兒隨母，蒼顔弟對兄。',48,'全唐诗/poet.song.169000.json','["白髮兒隨母，蒼顔弟對兄。", "四休元亦足，一笑更何營。", "論事絲弦直，存心鏡面平。", "德人今已矣，唯與嗣鄉評。"]'),
('9aba6cfc-3ce5-4184-8fa8-a53795fbeeed','挽伯父二首  其二','熊以寧','宋','宋诗','song-poetry','','[]','憶昨行邊別，相期到鶴州。',48,'全唐诗/poet.song.169000.json','["憶昨行邊別，相期到鶴州。", "秋風驚過眼，落日懶回頭。", "華屋空遺憾，佳城足遠謀。", "無從扶柩哭，揮淚寄江流。"]'),
('3af59b80-370b-4a02-9776-95d63b6b64e2','挽叔父二首  其一','熊以寧','宋','宋诗','song-poetry','','[]','道義時推重，功名志泊如。',48,'全唐诗/poet.song.169000.json','["道義時推重，功名志泊如。", "肯荒元亮徑，堅卧孔明廬。", "樂事千鍾酒，生涯萬卷書。", "騎箕天上去，斜月照塞墟。"]'),
('80e0d30d-854b-4bd1-86b1-b6891d3b1a64','挽叔父二首  其二','熊以寧','宋','宋诗','song-poetry','','[]','耄歲顔偏好，清談眼倍明。',48,'全唐诗/poet.song.169000.json','["耄歲顔偏好，清談眼倍明。", "一經雖取效，五鼎未終榮。", "柏隴承先志，蘭陔慘故情。", "西風吹淚眼，愁聽薤歌聲。"]'),
('5789bfba-5bbb-43ba-acf2-a6d71413fff7','題朱晦菴先生古樟書院壁','熊以寧','宋','宋诗','song-poetry','','[]','楊柳陰陰一徑苔，先生曾是手親栽。',32,'全唐诗/poet.song.169000.json','["楊柳陰陰一徑苔，先生曾是手親栽。", "幾年杖屨追隨樂，今日翻成夢裏來。"]'),
('56bc3a60-f356-48c8-98ff-9aa88a7adcaa','壽史滄洲','熊以寧','宋','宋诗','song-poetry','','[]','梯旻一何高，其勢如龍蟠。',228,'全唐诗/poet.song.169000.json','["梯旻一何高，其勢如龍蟠。", "下直湖萬頃，襟抱滄洲灣。", "潭居占其勝，縹緲雲濤間。", "海邦形勢地，秀偉此爲尊。", "諸湖如附庸，有水俱來環。", "元氣昔孕此，停蓄固有存。", "挺生賢哲人，象服仍貂冠。", "道大久乃見，景好人亦閑。", "堂堂八座貴，袖手樂其天。", "龍飛御宸極，廊廟須公還。", "湖山雖爾佳，政恐思謝安。", "下客有侯喜，素仰斗與山。", "摳衣荷延納，不棄蒯與菅。", "憐我塵土姿，欲使餌金丹。", "祗愧坐斤骨，蛻形良獨難。", "恭惟我公賢，崔嵬不可攀。", "茲遇垂弧旦，競賦崧高篇。", "南極正耿耿，三台輝紫垣。", "趣起對鈞秉，永輔基圖綿。"]'),
('c0c90a24-a82e-464f-b430-0a2bf11f59f6','送陳伯宏歸天台','安丙','宋','宋诗','song-poetry','','[]','平生江湖興，欲住元無由。',216,'全唐诗/poet.song.169000.json','["平生江湖興，欲住元無由。", "一朝忽復來，飄然泛扁舟。", "相將東南去，子獨從之游。", "傾蓋荷相與，琖斝頻勸酬。", "危坐每長歎，經營出奇謀。", "浩然天地間，憤氣衝斗牛。", "追陪文字飲，酣歌大開喉。", "與君結深交，交朋情欲周。", "會合元有時，妄意追陶劉。", "每恨不久住，共此敝馬裘。", "西風彫梧桐，忽忽春復秋。", "嗟余客中都，中夜懷百憂。", "區區爲貧仕，坐此徒窮愁。", "我恨各南北，公乃遂所求。", "天台亙雁蕩，今爲故鄉游。", "忽焉又分襟，涼風已颼颼。", "可憐煙水闊，坐見群山幽。", "音書有可寄，還解顧我不。"]'),
('c0dc5cb2-1d91-46c8-9e4a-93ead02d3bc6','游石門','安丙','宋','宋诗','song-poetry','','[]','凌晨走馬過花後，先玩玉盆次石門。',32,'全唐诗/poet.song.169000.json','["凌晨走馬過花後，先玩玉盆次石門。", "細想張良燒斷處，巖間佇立欲銷魂。"]'),
('f73f18ed-2a08-4bcc-b6c4-bf342ff99da9','煉丹臺','吳通','宋','宋诗','song-poetry','','[]','我尋陶隠居，山中多古蹟。',120,'全唐诗/poet.song.169000.json','["我尋陶隠居，山中多古蹟。", "青障撫清泉，白雲抱蒼壁。", "入經碎玉橋，便是幽人宅。", "仙人昔煉丹，嶙嶒一卷石。", "俯視直千尋，凌空高百尺。", "兩水落滄洲，滔滔渺無極。", "拂石坐片時，萬籟俱寥寂。", "但聽松風聲，耳邊生淅淅。", "長嘯白雲飛，山雨催詩亟。", "詩成寄阿誰，賞識惟貞白。"]'),
('1ca06809-1953-4318-840a-83c2345a06ca','聽松樓落成','吳禮','宋','宋诗','song-poetry','','[]','仙人自昔好樓居，黄鶴而今成故墟。',64,'全唐诗/poet.song.169000.json','["仙人自昔好樓居，黄鶴而今成故墟。", "高架數椽懸碧落，歘聽萬樹響空除。", "白雲伴向松窗宿，翠虯摩將石壁書。", "長日怡然還自得，却疑有夢到華胥。"]'),
('7ee4f01a-573f-4f4a-85b0-6f7b17fe9a26','華蓋仙山院','徐自明','宋','宋诗','song-poetry','','[]','萬當不如一，十發却休九。',120,'全唐诗/poet.song.169000.json','["萬當不如一，十發却休九。", "乃知多言累，寧謹三緘口。", "寂中洊雷震，悟處獅子吼。", "百物自四時，六鑿通九有。", "風松靜度曲，山花相與友。", "心遠境更幽，先生室無垢。", "茶鼎蒼蠅鳴，香几黄金紐。", "澄神天籟息，見性籓籬剖。", "對語彼上人，一笑開戶牖。", "自愧逐喧塵，成佛靈運後。"]'),
('963341aa-4fa9-47fb-828a-aaf3df45c2c1','遊浯溪','徐自明','宋','宋诗','song-poetry','','[]','□□□□□□奇，金石輝輝萬古垂。',64,'全唐诗/poet.song.169000.json','["□□□□□□奇，金石輝輝萬古垂。", "論定固知名貴正，時危更識禮從宜。", "溪山不老刊長在，天地重開繼者誰。", "多少艤舟咸有紀，况予畢戍可無詩。"]'),
('959cd433-b854-4a1f-95f5-58caf349e523','題節庵','李寅仲','宋','宋诗','song-poetry','','[]','花木新栽一徑長，小庵如款贊公房。',64,'全唐诗/poet.song.169000.json','["花木新栽一徑長，小庵如款贊公房。", "心清要省鈴齋訟，公退空凝燕寢香。", "已約芳菲供几案，不妨真率釂壺觴。", "年豐頓覺民和樂，老子從渠兩鬢蒼。"]'),
('42d0424d-dd5c-4c76-b317-438f722b562d','遊先神童讀書巖','李寅仲','宋','宋诗','song-poetry','','[]','古洞閎深勢崛盤，雲連十丈地平寬。',64,'全唐诗/poet.song.169000.json','["古洞閎深勢崛盤，雲連十丈地平寬。", "水簾紛若排珠琲，石闕依然聳翠巒。", "綠樹成陰期勿剪，清溪當暑不勝寒。", "數椽儻遂諧幽隠，應有高人咏釣盤。"]'),
('f9e4380b-aff3-4c94-abb1-64fc55d50905','鵝翎山','甘同叔','宋','宋诗','song-poetry','','[]','俗謂鵝翎未必然，娥英恐是古時傳。',32,'全唐诗/poet.song.169000.json','["俗謂鵝翎未必然，娥英恐是古時傳。", "溪聲流盡蒼梧淚，斑竹林中聞杜鵑。"]'),
('0195eb7b-aff1-4161-b5b5-0a990de0fc81','題昌山聖姥廟','甘同叔','宋','宋诗','song-poetry','','[]','分宜古縣環清溪，重岡複嶺如奔馳。',336,'全唐诗/poet.song.169000.json','["分宜古縣環清溪，重岡複嶺如奔馳。", "行逢山斷水流處，閲城廟枕山之西。", "我來落日在前嶺，摩挲一讀盧肇碑。", "嗟唐去今亦巳久，尚餘文字光陸離。", "云昔秦人有天下，鏖戰六國愚黔黎。", "碭山雲氣望不見，神物乃降江之嫠。", "雷轟電合助光怪，蜿蜒墮地偕羣兒。", "赤鱣王鮪奉鼎俎，追逐甘旨憐姥慈。", "姥先仙去環佩冷，安能蟠蟄從兒嬉。", "劉累不出浮俗隘，況肯委質嬴與斯。", "珠宮貝闕世所希，銅環十二白玉扉。", "紉蘭作佩香披披，招摇手掉芙蓉旗。", "哀彈清瑟和宓妃，大川擊鼓勞馮夷。", "巨魚踴躍黿鼉隨，蝦蟹瑣細不得追。", "廟門開闔風颸颸，千年萬載龍居之。", "野巫偵伺薦酒巵，簫鼓坎坎來宮祠。", "五彩不辨虺與螭，聊以幻化驚羣迷。", "嗟我四海久望霓，無復空抱明月輝。", "好施膏澤雨六合，豈止但慰袁人思。", "歷階酌水致此辭，退以遺誼傳于詩。", "才慳語纇論甚卑，龍兮謹勿相訶譏。"]'),
('169cd08e-ea29-463f-b3c5-cdc16b0b14f5','盛氏銜翠軒','葉三錫','宋','宋诗','song-poetry','','[]','平生丘壑心，漫浪不覊束。',120,'全唐诗/poet.song.169000.json','["平生丘壑心，漫浪不覊束。", "青山亦解意，四時共追逐。", "朝翠空濛時，北窗夢清熟。", "晝寂庭戶涼，坐課黄卷讀。", "此心與山違，對面若掩目。", "孱顔儼如故，心境兩不觸。", "宴坐收萬象，剖璞出蒼玉。", "木末流夕暉，窗戶影摇綠。", "相對兩青眼，悠然一笑足。", "此意陶潛知，不然問玉局。"]'),
('ee72a520-8c24-48f1-b4b3-5a94fd25a27a','雲安龍脊灘','楊濟','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭老龍時出沒，萬斛舟航皆辟易。',96,'全唐诗/poet.song.169000.json','["洞庭老龍時出沒，萬斛舟航皆辟易。", "此龍脊背已鐵石，肯逐時好作人日。", "我呼邦人來踏磧，恍然如見河圖出。", "大巫雞卜占云吉，小巫竹枝歌轉激。", "飄石揚沙障江色，塵埃何處不相襲。", "摩挲石刻聊偃息，恐有老人來橫笛。"]'),
('7fe657df-6fac-4503-aa3e-eb40a0d2742e','多景樓','趙汝伋','宋','宋诗','song-poetry','','[]','壯觀東南二百州，景於多處更多愁。',64,'全唐诗/poet.song.169000.json','["壯觀東南二百州，景於多處更多愁。", "江流千古英雄淚，山掩諸公富貴羞。", "北府如今惟有酒，中原在望忍登樓。", "西風戰艦今何在，且辦年年使客舟。"]'),
('8dee4ac0-8e52-4d4a-8638-bc2a32ec3aa5','中秋月','趙汝鏏','宋','宋诗','song-poetry','','[]','坐待銀盤出海波，光華此夕看還多。',64,'全唐诗/poet.song.169000.json','["坐待銀盤出海波，光華此夕看還多。", "娟娟丰骨清如洗，皓皓冰姿玉就磨。", "庾老登樓饒逸興，李仙把盞發狂歌。", "醉來欲舞尊前影，飛上寒宮伴素娥。"]'),
('2ba88395-b395-4aaf-bf4c-5c3519ded573','句','黄樵仲','宋','宋诗','song-poetry','','[]','俸薄儉亦足，官卑清自尊。',12,'全唐诗/poet.song.169000.json','["俸薄儉亦足，官卑清自尊。"]'),
('5bd5dce7-1fa9-459b-8f90-be183226ff50','岑公洞','范仲黼','宋','宋诗','song-poetry','','[]','石壁虛涵雲氣深，水簾簌簌墮璆琳。',32,'全唐诗/poet.song.169000.json','["石壁虛涵雲氣深，水簾簌簌墮璆琳。", "客來但愛幽棲好，誰識岑公萬古心。"]'),
('4934b332-21df-4110-b89d-48329cc1cd90','漁父','呂炎','宋','宋诗','song-poetry','','[]','萬頃江天一葉舟，桃花春水蓼花秋。',32,'全唐诗/poet.song.169000.json','["萬頃江天一葉舟，桃花春水蓼花秋。", "翛然白鳥蒼烟外，只有漁翁得自由。"]'),
('fd53caa2-2e72-45ed-91dc-7d6fe911e347','田園詞','呂炎','宋','宋诗','song-poetry','','[]','陰陰徑底忽抽葉，莫莫籬邊豆結花。',32,'全唐诗/poet.song.169000.json','["陰陰徑底忽抽葉，莫莫籬邊豆結花。", "唳鶴清愁牽犬恨，料應不到菜園家。"]'),
('f13ff431-0c4a-4d13-8a30-05e4b0ae8198','甘園','呂炎','宋','宋诗','song-poetry','','[]','曾入當年富貴家，東風幾度換年華。',32,'全唐诗/poet.song.169000.json','["曾入當年富貴家，東風幾度換年華。", "滿園桃李不知主，獨自開花自落花。"]'),
('e4689004-7515-4ed7-b4a0-9c092c546cf5','閨思','呂炎','宋','宋诗','song-poetry','','[]','夜久香銷翡翠匳，十分春恨上眉尖。',32,'全唐诗/poet.song.169000.json','["夜久香銷翡翠匳，十分春恨上眉尖。", "荼䕷謝了櫻桃過，人影參差月半簾。"]'),
('540b9b97-b31c-409b-af47-bdb2317f16e1','經略煥章先生寵賜千葉梅佳製似笑疏花太孤瘦故教密葉擁千層昔人所未經道真絕唱也褒不揆輒拾餘意申呈仰丐規削','劉褒','宋','宋诗','song-poetry','','[]','乾葉驚飛蹀躞輕，疎枝綽妁鬭酥凝。',64,'全唐诗/poet.song.169000.json','["乾葉驚飛蹀躞輕，疎枝綽妁鬭酥凝。", "正憐驛使來衝雪，却費詩翁巧斲冰。", "天女手高饒剪刻，玉環肌滿見稜層。", "何人醉作羅浮夢，花杪橫參撼未應。"]'),
('24aac8b3-3f44-4f90-9551-122a4a42c50e','題小槳','劉褒','宋','宋诗','song-poetry','','[]','去日春蠶吐素絲，歸時秋菊剝金衣。',32,'全唐诗/poet.song.169000.json','["去日春蠶吐素絲，歸時秋菊剝金衣。", "沙鷗不入鴛鴻侶，依舊滄浪遶釣磯。"]'),
('3e2348d5-f0d5-4c5c-b9b5-0dc5eeb6d3d6','句  其一','劉褒','宋','宋诗','song-poetry','','[]','客路雨連日。',6,'全唐诗/poet.song.169000.json','["客路雨連日。"]'),
('0bdb1f68-5765-469c-a8fd-de609386b9c0','句  其二','劉褒','宋','宋诗','song-poetry','','[]','誰向雲端著此亭。',8,'全唐诗/poet.song.169000.json','["誰向雲端著此亭。"]'),
('bd32ef98-aa1d-4406-af8b-fdc1afe609ef','句  其三','劉褒','宋','宋诗','song-poetry','','[]','憑欄一笑斜陽裏。',8,'全唐诗/poet.song.169000.json','["憑欄一笑斜陽裏。"]'),
('ffcd138c-c3ce-4579-a949-e8b90930f2cb','句  其四','劉褒','宋','宋诗','song-poetry','','[]','蘇堤一带柳陰長。',8,'全唐诗/poet.song.169000.json','["蘇堤一带柳陰長。"]'),
('0b0994ef-c438-4703-a967-f3c308125741','句  其五','劉褒','宋','宋诗','song-poetry','','[]','泉石膏肓鍼不得，半巖明月夜猿啼。',16,'全唐诗/poet.song.169000.json','["泉石膏肓鍼不得，半巖明月夜猿啼。"]'),
('dd4c60ef-21c6-4e2c-94bf-92c68bf4a147','噴玉磯','陳武','宋','宋诗','song-poetry','','[]','朝借仙巖遊，暮借仙巖宿。',24,'全唐诗/poet.song.169000.json','["朝借仙巖遊，暮借仙巖宿。", "一洐流不窮，長年看不足。"]'),
('bfc99131-70e6-4a9f-a9c9-90d87487b84a','羅隠題詩石','陳宋輔','宋','宋诗','song-poetry','','[]','詩名鼎鼎號三羅，藜杖經從石上過。',64,'全唐诗/poet.song.169000.json','["詩名鼎鼎號三羅，藜杖經從石上過。", "鐵畫銀鈎難辨認，雨霖日炙莫鎸磨。", "幽泉添硯潺湲響，明月生波感慨多。", "小立西風吹鬢髮，碧羅深處聽漁歌。"]'),
('2daaf3ed-d7d9-45d1-8c1e-1f5842df10aa','游王母岡','曾躍鱗','宋','宋诗','song-poetry','','[]','岡空雲散浄如銀，石磴層層接九宸。',64,'全唐诗/poet.song.169000.json','["岡空雲散浄如銀，石磴層層接九宸。", "翠竹影摇湘浦夜，碧桃香藹武陵春。", "但看此日燒丹竈，不見當年駕鶴人。", "遊徧瑶池歸去晚，一聲長嘯月華新。"]'),
('f4b00cc6-65d7-4df9-b3fa-bea901e4d6a8','聞西浦漁歌作','曾躍鱗','宋','宋诗','song-poetry','','[]','西浦鳴榔下釣磯，歌聲欵乃送斜暉。',64,'全唐诗/poet.song.169000.json','["西浦鳴榔下釣磯，歌聲欵乃送斜暉。", "扣舷互答驚鷗夢，拍手歡呼看鷺飛。", "山接素琴仙子過，洲連青草使君歸。", "海天空闊家長在，一任蘆花雪點衣。"]'),
('846b161e-9700-4213-8a6f-5f981b65bb0e','句','鄭瓚','宋','宋诗','song-poetry','','[]','一水玻璃似苕霅，群山俎豆勝方壺。',16,'全唐诗/poet.song.169000.json','["一水玻璃似苕霅，群山俎豆勝方壺。"]'),
('af28967c-9666-427f-ac1c-74ec307b5fa2','嘉泰癸亥夏陪縣尹雙湖唐仲謀飲寒亭','李大光','宋','宋诗','song-poetry','','[]','棧閣橫空杳靄間，登臨酒罷怯憑闌。',64,'全唐诗/poet.song.169000.json','["棧閣橫空杳靄間，登臨酒罷怯憑闌。", "露零萬瓦交光渥，月挂千峯倒影寒。", "谷煦如春居亦易，亭涼宜夏到乎難。", "垂簷星斗方爭席，好向天門刷羽翰。"]'),
('a2e3bc4d-77d5-4c13-b2a0-9b5840a8a592','新晴可喜同吳斗南登塔院','滕繼遠','宋','宋诗','song-poetry','','[]','一雨浹辰外，乍晴如酒醒。',48,'全唐诗/poet.song.169000.json','["一雨浹辰外，乍晴如酒醒。", "臨谿照浄綠，陟巘到高青。", "翠靄俯深樾，黄雲迷遠坰。", "超然信塵表，風袂襲泠泠。"]'),
('78d31cd1-8294-4777-a253-b2f005cc79d6','句','釋正一','宋','宋诗','song-poetry','','[]','一望和烟碧，悠悠去不回。',12,'全唐诗/poet.song.169000.json','["一望和烟碧，悠悠去不回。"]'),
('3d2ab5b9-fb93-4136-ade2-8c0f6a6d5f19','秋園咏物  其一','薛循祖','宋','宋诗','song-poetry','','[]','怪爾知時節，逢時輒自鳴。',48,'全唐诗/poet.song.169000.json','["怪爾知時節，逢時輒自鳴。", "空階一夜響，短榻幾人驚。", "唧唧催寒色，蕭蕭助葉聲。", "無人悲物意，徒語不堪情。"]'),
('30ee915a-c47a-4f23-9005-0b512d005755','秋園咏物  其二','薛循祖','宋','宋诗','song-poetry','','[]','風急翅紛紛，遥空自作羣。',48,'全唐诗/poet.song.169000.json','["風急翅紛紛，遥空自作羣。", "到來秋塞月，鳴入暮江雲。", "亂起千行字，俱飛一片文。", "高樓有思婦，嘹嚦豈堪聞。"]'),
('ab832285-ceb1-4317-873f-264d06060030','題采藥圖','薛循祖','宋','宋诗','song-poetry','','[]','江山奇峯雨後多，千層飛瀑灑青蘿。',32,'全唐诗/poet.song.169000.json','["江山奇峯雨後多，千層飛瀑灑青蘿。", "扶筇亦覺溪橋滑，尚有幽人采藥過。"]'),
('1b7d493f-b27a-4488-9007-9d6eba35c2b1','贈曹延','陳文叔','宋','宋诗','song-poetry','','[]','混然天性本天成，何必拘泥守意城。',32,'全唐诗/poet.song.169000.json','["混然天性本天成，何必拘泥守意城。", "識破鳶飛魚躍事，自知萬物不離誠。"]'),
('bd5ad562-b496-4d31-997c-eababa5e5366','龍巖山','周明仲','宋','宋诗','song-poetry','','[]','靈河直欲貫蒼崖，神力摩挲石島開。',32,'全唐诗/poet.song.169000.json','["靈河直欲貫蒼崖，神力摩挲石島開。", "冰玉滿懷雲滿袂，分明天上泛槎來。"]'),
('dfac9115-d4be-42d2-8383-368f930cc237','白蓮花','釋善月','宋','宋诗','song-poetry','','[]','天開地闢詎云賒，異草靈苗特一家。',64,'全唐诗/poet.song.169000.json','["天開地闢詎云賒，異草靈苗特一家。", "不有岡頭三女粲，爭敷處子六郎花。", "英雄有種凜生氣，白玉微根不受瑕。", "他時若補芬陀傳，端與優曇定等差。"]'),
('761c08dd-806d-4ffc-9b94-9bcb2268d740','感秋詩  其一','許琮','宋','宋诗','song-poetry','','[]','風動蘋起，雲光在水。',40,'全唐诗/poet.song.169000.json','["風動蘋起，雲光在水。", "荇藻有心，清我眸子。", "白露在衣，秋心易微。", "冠兮佩兮，君子當饑。"]'),
('55ba6f4f-0b77-44ad-b053-09d113def40d','感秋詩  其二','許琮','宋','宋诗','song-poetry','','[]','小草在砌，顔色常好。',40,'全唐诗/poet.song.169000.json','["小草在砌，顔色常好。", "豈無嚴霜，先彼長栲。", "寄言青松，斧斤自從。", "子不在山，真節安庸。"]'),
('54c59a4f-7b4a-4b9e-83a4-e12a618a0115','感秋詩  其三','許琮','宋','宋诗','song-poetry','','[]','風起木非，菀焉者歇。',60,'全唐诗/poet.song.169000.json','["風起木非，菀焉者歇。", "故鄉在念，何以視月。", "衆念思歸，鳥情望碧。", "嗷嗷鳴雁，集彼中澤。", "我獨伊何，羅此網羅。", "父兮母兮，生我實多。"]'),
('456c2418-9a52-450e-ad4b-2e36494b97cd','淥水詞','許琮','宋','宋诗','song-poetry','','[]','綠草迴波漾青草，鷓鴣聲緊連枝老。',96,'全唐诗/poet.song.169000.json','["綠草迴波漾青草，鷓鴣聲緊連枝老。", "苔陰欲上簾影低，鳥語催人天未曉。", "曉起輕寒奈薄羅，風前縷带不勝波。", "練裙香動竹葉小，玉燕斜簪霧色多。", "霧色花光鏡裏過，年年歌吹復如何。", "妾身不及桃花葉，猶逐輕風渡隔河。"]'),
('cad5078a-dba9-4687-941f-d078a34abc92','憶遠曲','許琮','宋','宋诗','song-poetry','','[]','露下花寒香不起，單羅輕薄如秋水。',96,'全唐诗/poet.song.169000.json','["露下花寒香不起，單羅輕薄如秋水。", "梧桐聲定金鋪關，長看對月青天閑。", "淚眼看春不知處，楊花化作浮萍去。", "可憐環珮參差光，采蓮獨自艷南塘。", "菖薄如劍南塘曲，亂割波文碎空綠。", "今夜音書欲寄君，莫教疑殺鯉魚羣。"]'),
('238f46c4-2645-411f-aa82-4169039e0bc8','山中懷故人','許琮','宋','宋诗','song-poetry','','[]','歡多清景略，會數別離輕。',48,'全唐诗/poet.song.169000.json','["歡多清景略，會數別離輕。", "病骨無人問，空山正月明。", "落花懷舊韻，鳴鳥感新晴。", "再看思君處，流泉石上平。"]'),
('33b0c29a-48e9-4e5c-afa7-5e191ffda031','連雨有感  其一','許琮','宋','宋诗','song-poetry','','[]','酒醒雨聲至，新歡不可尋。',48,'全唐诗/poet.song.169000.json','["酒醒雨聲至，新歡不可尋。", "美人惟草色，故國聽歌聲。", "日月何處盡，荆榛連夜深。", "開門謝天末，從此罷登臨。"]'),
('e6db0529-9b3e-4506-ac8a-2b0a13e0b391','連雨有感  其二','許琮','宋','宋诗','song-poetry','','[]','草長城南地，愁人看自深。',48,'全唐诗/poet.song.169000.json','["草長城南地，愁人看自深。", "白雲偏向淚，青鬢獨驚心。", "久病畏陰濕，家中厭苦吟。", "今宵酒不盡，應有杜鵑聲。"]'),
('14df1dfb-71a0-4a51-b824-eb9801fddf27','江上對月','許琮','宋','宋诗','song-poetry','','[]','今夜江邊月，光輝分外明。',48,'全唐诗/poet.song.169000.json','["今夜江邊月，光輝分外明。", "一輪懸碧漢，百里見山城。", "岸岸花添白，層層浪轉青。", "遥憐閨閣裏，相對重離情。"]'),
('f797f83d-c845-4b26-a3aa-79d327b91934','夜宿祥符寺曉鐘有感','許琮','宋','宋诗','song-poetry','','[]','一枕松風入夜寒，曉窗殘月隔簾看。',64,'全唐诗/poet.song.169000.json','["一枕松風入夜寒，曉窗殘月隔簾看。", "夢回竹榻聞鐘後，悵絕浮生出世難。", "還念將軍能捨宅，何妨陶令未之官。", "此身合向山中住，丘壑由來號易安。"]'),
('6741d3ae-e0e3-4a56-99fa-3929d59c0e46','阻風渡頭見楊柳','許琮','宋','宋诗','song-poetry','','[]','古渡疎楊數樹青，孤村細草凍還醒。',64,'全唐诗/poet.song.169000.json','["古渡疎楊數樹青，孤村細草凍還醒。", "風光直欲催頭白，樽酒何人肯放停。", "小院腰肢今寂寂，天涯魂夢幾冥冥。", "閨中莫道長相憶，客路悲風徹夜聽。"]'),
('e6fd73cf-ded3-44f1-b3bc-b615a00d05de','雲山閣','許琮','宋','宋诗','song-poetry','','[]','雲山依舊接清秋，高閣荒榛悵舊遊。',32,'全唐诗/poet.song.169000.json','["雲山依舊接清秋，高閣荒榛悵舊遊。", "二十四橋何處所，西風吹盡白蘋洲。"]'),
('65e343e8-2e06-4c05-bce1-2179373030b9','隋堤用羅昭諫韻','許琮','宋','宋诗','song-poetry','','[]','萬樹青青入望遥，行人猶自說隋朝。',32,'全唐诗/poet.song.169000.json','["萬樹青青入望遥，行人猶自說隋朝。", "啼鶑不管繁華歇，還带春風上柳條。"]'),
('da14d104-a42c-4ec5-a475-eb55cc1189bb','感舊  其一','許琮','宋','宋诗','song-poetry','','[]','捲簾新月在簾鈎，花氣同風過小樓。',32,'全唐诗/poet.song.169000.json','["捲簾新月在簾鈎，花氣同風過小樓。", "爲憶昨宵燈下事，不將紅燭照梳頭。"]'),
('f063e830-57ed-4fcc-945a-885b9374d9b1','感舊  其二','許琮','宋','宋诗','song-poetry','','[]','閑窗落葉掛蟲絲，坐久還疑是舊時。',32,'全唐诗/poet.song.169000.json','["閑窗落葉掛蟲絲，坐久還疑是舊時。", "記得欄桿垂手處，梅花明月第三枝。"]'),
('257b5a68-3770-4aaf-9152-30a5f2725fa6','棲霞寺','趙伯晟','宋','宋诗','song-poetry','','[]','棲霞境界何清壯，嶽立五峰如列障。',64,'全唐诗/poet.song.169000.json','["棲霞境界何清壯，嶽立五峰如列障。", "三徵不復見高人，千刻尚能瞻寶相。", "摩空老木韻秋聲，雲屋天巖滿意行。", "夜闌風定月將午，門外呦呦聞鹿鳴。"]'),
('158fe01b-48dc-4d3d-a7a5-89cba0d5cb4a','和陳正言讜題尊賢堂二首  其一','譚景先','宋','宋诗','song-poetry','','[]','孰識東坡第一仙，謫來儋耳久悠然。',64,'全唐诗/poet.song.169000.json','["孰識東坡第一仙，謫來儋耳久悠然。", "潛心學易忘憂患，築屋閑居度歲年。", "興遣不爲哀屈事，情高嘗見和陶篇。", "拜公遺像渾如在，曾與鄉人恭敬賢。"]'),
('5c9dc5de-e83a-4dc7-b0e0-beb312aae6b0','和陳正言讜題尊賢堂二首  其二','譚景先','宋','宋诗','song-poetry','','[]','公已歸爲玉局仙，茂林喬木自蒼然。',64,'全唐诗/poet.song.169000.json','["公已歸爲玉局仙，茂林喬木自蒼然。", "鄉時寓客共千載，今日新堂恰百年。", "鐵畫銀鈎三大字，金章玉局一佳篇。", "遠煩幾似真雙美，後世應知兩並賢。"]'),
('a12a10da-912d-4ea1-979c-79337893a4ed','白馬井','譚景先','宋','宋诗','song-poetry','','[]','玉踠神跑井，崇祠漢伏波。',48,'全唐诗/poet.song.169000.json','["玉踠神跑井，崇祠漢伏波。", "海濤如許近，地脈不同科。", "德澤甘泉美，人資惠利多。", "靈蹤傳萬古，蒼石有誰磨。"]'),
('bb002b15-285e-4d1c-a4db-2fae5c61aa42','汀州','陳曄','宋','宋诗','song-poetry','','[]','嘗聞元豐間，元輿守茲土。',36,'全唐诗/poet.song.169000.json','["嘗聞元豐間，元輿守茲土。", "別乘果爲誰，青山郭功甫。", "二公德望尊，聲名播今古。"]'),
('45e86d00-e25f-4bd9-8515-b688a8799e33','我愛淳安好  其一','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，於民兩盡誠。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，於民兩盡誠。", "明倫喜知勸，有社敬皆生。", "開學群材進，繙經衆說平。", "嗟予不如昔，徒爾景恢宏。"]'),
('0a91fd6d-34bb-4cd7-9255-b97f3e88755c','我愛淳安好  其二','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，群心息險姦。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，群心息險姦。", "封郊廣申畫，車轍略周環。", "漏刻辰無爽，亭崇詔肅頒。", "恭思民易虐，退食敢言閑。"]'),
('e64ea20f-6f25-4a20-a7ce-703b989d6996','我愛淳安好  其三','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，溪山壯縣居。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，溪山壯縣居。", "錦文光璀璨，雉羽泄輕徐。", "比屋興弦誦，多田力耨耡。", "廓然無一事，林下自詩書。"]'),
('45ac3ce3-4df7-4e18-933e-99d162ec7d71','我愛淳安好  其四','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，精能樂衆工。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，精能樂衆工。", "群羊亡飲豫，大武護功隆。", "推此心俱善，貤生石可礱。", "浮游博六子，裒手亦從風。"]'),
('9749fede-ac32-4651-b6ec-98c89fcc57f2','我愛淳安好  其五','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，憂民缺致盈。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，憂民缺致盈。", "渠通廬避濕，灘鑿浪難生。", "利涉津梁固，安行道路平。", "夙宵雖黽勉，終愧漢公卿。"]'),
('4be72c46-ca42-4d3a-ace1-b0ff46892ec3','我愛淳安好  其六','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，能知義命方。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，能知義命方。", "育遺存後裔，刳腹奉高堂。", "隠節推承詔，儒官教有庠。", "胡爲得祠奉，退省更徊徨。"]'),
('c884e52b-2394-4a08-9776-5034b4be4c8d','我愛淳安好  其七','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，先庚矢伏房。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，先庚矢伏房。", "春秋武常閲，鐘皷今惟詳。", "在在空三穴，家家保萬箱。", "歡呼徧田里，既醉樂時康。"]'),
('10205d60-c321-4bde-ac89-e62cb6ae6019','我愛淳安好  其八','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，流芳踵昔人。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，流芳踵昔人。", "興賢多上第，安老切憐貧。", "更荷雨暘若，再還風俗淳。", "燕毛過百歲，錫類奉君親。"]'),
('9f567a5e-9c00-40be-a9c3-4f058102f2ca','我愛淳安好  其九','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，薰陶聖治馨。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，薰陶聖治馨。", "執呼民聽命，期縱草生囹。", "欄柵虛長廡，桁楊卧一庭。", "國家仁澤厚，今日可無刑。"]'),
('a92a776f-9614-43e2-b361-88f8ed93b8a3','我愛淳安好  其一○','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，百方民力寬。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，百方民力寬。", "役胥遵大義，訟牒上狂瀾。", "公賦爭先入，窮閻可奠安。", "從今滋向化，爲政不因難。"]'),
('2746fdbb-ce1a-4216-8031-0649c4a2c4ef','我愛淳安好  其一一','陳曄','宋','宋诗','song-poetry','','[]','我愛淳安好，都捐文墨拘。',48,'全唐诗/poet.song.169000.json','["我愛淳安好，都捐文墨拘。", "幽禽縱林藪，露匶掩荒蕪。", "每積空餐媿，曾求實惠無。", "安車幸虞侍，南極近星弧。"]'),
('07858283-22f0-460c-a6c6-3fadd482a69b','句  其一','陳曄','宋','宋诗','song-poetry','','[]','朝看碧溪初騰日，暮對青山淡抹雲。',16,'全唐诗/poet.song.169000.json','["朝看碧溪初騰日，暮對青山淡抹雲。"]'),
('03abf4d5-e97a-46a9-b6de-56bc310985e8','句  其二','陳曄','宋','宋诗','song-poetry','','[]','古驛森慈竹，蓮城挺義松。',12,'全唐诗/poet.song.169000.json','["古驛森慈竹，蓮城挺義松。"]'),
('2832f9bf-d89e-4dc9-a0d4-0acc867902c6','三井潭報雨','唐仲溫','宋','宋诗','song-poetry','','[]','夜宿精藍百慮清，晨移祠下勺涵亭。',32,'全唐诗/poet.song.169000.json','["夜宿精藍百慮清，晨移祠下勺涵亭。", "須臾水府收溫刺，始信神龍果有靈。"]'),
('7f27a809-ee07-4970-bec0-a20660f0b55a','水月洞絕句','張埏','宋','宋诗','song-poetry','','[]','明月出天山，月明秋水寒。',24,'全唐诗/poet.song.169000.json','["明月出天山，月明秋水寒。", "觀心同水月，鑷白坐相看。"]'),
('6914f050-23cf-4144-b5e5-b47fc45f9d7c','龍隠洞','張埏','宋','宋诗','song-poetry','','[]','幾年鱗甲蟄清淵，一旦飛騰石自穿。',32,'全唐诗/poet.song.169000.json','["幾年鱗甲蟄清淵，一旦飛騰石自穿。", "遺跡謾存離舊隠，定應銜雨去朝天。"]'),
('99698376-7505-4dda-aa3e-f5674f411ed1','龍隠巖','張埏','宋','宋诗','song-poetry','','[]','洞口巖高著數椽，湫靈聽法護金仙。',32,'全唐诗/poet.song.169000.json','["洞口巖高著數椽，湫靈聽法護金仙。", "騰身一躍天池後，雲霧于今尚滃然。"]'),
('243af6db-e481-44e8-9938-1aa3767bce63','白帝廟','楊安誠','宋','宋诗','song-poetry','','[]','蜀江萬壑俱東奔，瞿唐喧豗爭一門。',256,'全唐诗/poet.song.169000.json','["蜀江萬壑俱東奔，瞿唐喧豗爭一門。", "驚濤駭浪建瓴下，顛崖仆谷相吐吞。", "朋妖窟宅恃幽阻，正晝噴薄陰霾昏。", "靈宮奕奕鎮地險，衆瀆稟令川祇尊。", "赤甲後聳黄熊躍，灧澦前峙青猿蹲。", "舳艫銜尾下吳楚，約束蛟鰐如雞豚。", "舊傳鼓角致雨雹，裹篙不觸撐舟痕。", "綜理脈絡盡西徼，帝假之柄攸司存。", "子陽祚國十年近，此地未省東其轅。", "聯江列炬鐵鎖斷，戎滿奔北無留屯。", "江關回首盡漢幟，遺黎何自知公孫。", "血食漢代定不爾，但有故壘山之樊。", "子美誤信齊東語，感慨勇略招英魂。", "山川之靈載望秩，僭僞詎可同時論。", "向來名實久淆溷，薦祼無乃瀆俎膰。", "請從酈元爲考證，神理昭昭斯可原。"]'),
('1f710587-7903-4e06-abdf-ee212b9c9016','句','楊安誠','宋','宋诗','song-poetry','','[]','扶摇天一握，培塿蜀千山。',12,'全唐诗/poet.song.169000.json','["扶摇天一握，培塿蜀千山。"]'),
('71e6ff43-63c5-4392-a6ce-91d9411c737c','清風亭','米恁','宋','宋诗','song-poetry','','[]','斷碑殘畫字昏朦，應是山高氣似虹。',32,'全唐诗/poet.song.169000.json','["斷碑殘畫字昏朦，應是山高氣似虹。", "我自筆頭如許澀，恨無好句傍清風。"]'),
('6d83f373-28a6-4dd7-b0bf-efae432830f6','古柟歌用嚴鄭公韵','趙善期','宋','宋诗','song-poetry','','[]','秀挹奇峰佳客對，凌空下視孤鴻背。',128,'全唐诗/poet.song.169000.json','["秀挹奇峰佳客對，凌空下視孤鴻背。", "夜□雲□起山根，老蛟飛出崖裂痕。", "高高不放行雲度，鳥語去來分曉暮。", "直疑種是萬年枝，定應葉漬三危露。", "班輸腰斧頻□頭，婆娑巖壑□□愁。", "□看世事了如夢，靜聽江聲知幾秋。", "巴南刺史儒林文，憐汝抱材開鑒賞。", "賡載長謠□更清，瓊鈎珠珮相聯響。"]'),
('3dcc6d7e-a698-4912-91d2-ff564e2c5b06','句','倪翼','宋','宋诗','song-poetry','','[]','三尺有關人命重，一官雖去我身輕。',16,'全唐诗/poet.song.169000.json','["三尺有關人命重，一官雖去我身輕。"]'),
('5dab8b16-7385-4bc8-bf75-3fa07772c708','太湖山','黄圭','宋','宋诗','song-poetry','','["\u592a\u6e56"]','一带迴環底處山，勢如飛楫下平川。',64,'全唐诗/poet.song.169000.json','["一带迴環底處山，勢如飛楫下平川。", "須知欲到菩提岸，好是常懸般若船。", "纜向龍湖宏利濟，撐從苦海度人天。", "當年普照如乘此，無復鬚巾撒向前。"]'),
('65e35101-59f1-4374-8e57-11c083bfbfa4','宿儀林寺','黄圭','宋','宋诗','song-poetry','','[]','探幽適興訪儀林，休聽春蛙說雨深。',64,'全唐诗/poet.song.169000.json','["探幽適興訪儀林，休聽春蛙說雨深。", "翠竹黄花新般若，青山綠水舊知音。", "禪盟蘇晉情相契，酒戀淵明醉且斟。", "此去雪峰應不遠，肯容杖履謾相尋。"]'),
('b009505b-1aea-4ed6-9be0-cdb55688af9f','瑞香花','蘇大璋','宋','宋诗','song-poetry','','[]','芳蕤何蒨絢，尤物真旖旎。',36,'全唐诗/poet.song.169000.json','["芳蕤何蒨絢，尤物真旖旎。", "五葉映雕闌，三椏駢粉蕊。", "妍分春月魂，香徹肌骨髓。"]'),
('4955dfde-2f34-4c19-ad52-a9257b1728e9','蘼蕪','蘇大璋','宋','宋诗','song-poetry','','[]','葉葉秋聲中，霏霏蚤英蔌。',60,'全唐诗/poet.song.169000.json','["葉葉秋聲中，霏霏蚤英蔌。", "分持有如松，繁華匪慚菊。", "勃蔚襲軒墀，薰沾滿衣服。", "情人擢纖指，拾蕊動盈掬。", "蘼蕪見離騷，苓藿入語錄。"]'),
('595b308b-3d7d-46ae-b8f4-35efa4374c02','鳳翀峰','蘇大璋','宋','宋诗','song-poetry','','[]','早起聯鑣上翠微，瞰虛歷級步嶔𡼭。',64,'全唐诗/poet.song.169000.json','["早起聯鑣上翠微，瞰虛歷級步嶔𡼭。", "昔聞華頂蓮生藕，今見南山菊滿籬。", "縱眼橫看天地闊，壯懷唯有鬼神知。", "安期引我丹霄路，十里雲煙特地披。"]'),
('0194299b-367e-4ad2-ae04-96cbf0e3b55f','同顧狀元玉文登瑞巖','張天翼','宋','宋诗','song-poetry','','[]','迢迢何處覓仙關，翠竹蒼崖夕照間。',64,'全唐诗/poet.song.169000.json','["迢迢何處覓仙關，翠竹蒼崖夕照間。", "倦鳥依依穿石磴，落花歷歷點苔斑。", "春殘幾負屑霄約，首白寧辭絕壁攀。", "乘興相携遥躡屐，一樽聊與賦青山。"]'),
('20a02902-7bf5-468e-8c81-bbfbf562351d','水簾洞','留筠','宋','宋诗','song-poetry','','[]','九天飛墜水晶垂，不著人間一點埃。',64,'全唐诗/poet.song.169000.json','["九天飛墜水晶垂，不著人間一點埃。", "六月驚蜚霜色皎，四時長作雨聲來。", "春晴野燕飛難入，月冷山風吹不開。", "我欲倚藤看空翠，憑誰掛向白雲堆。"]'),
('87ce8df4-db0a-4aa2-961d-685f18a1ed50','沖虛觀','留筠','宋','宋诗','song-poetry','','[]','金闕寥陽護九重，洞雲呼吸九霄通。',32,'全唐诗/poet.song.169000.json','["金闕寥陽護九重，洞雲呼吸九霄通。", "小臣近有祠官詔，欲問君王乞此宮。"]'),
('85e39eba-a6a1-4fa9-a857-825b59bb73ec','題澹山巖','留筠','宋','宋诗','song-poetry','','[]','起仰高山積有年，忽看巖窬鎖雲煙。',64,'全唐诗/poet.song.169000.json','["起仰高山積有年，忽看巖窬鎖雲煙。", "一塵不到非凡地，六月當知不暑天。", "昔有秦人嘗穴處，世從山谷始名傳。", "品題自古因人重，我謾邀僧煮石泉。"]'),
('d8dd4fca-e459-4f64-9579-b63a9c1f242a','題浯溪','留筠','宋','宋诗','song-poetry','','[]','天生一代老文詞，留得高名日月垂。',64,'全唐诗/poet.song.169000.json','["天生一代老文詞，留得高名日月垂。", "山□猶餘元氏族，溪痕幾□魯公碑。", "未論再造中興業，却羨三吾高卧時。", "崖石雖磨千古在，渡香橋下木空悲。"]'),
('bf146043-a8ad-44be-a18c-42e146109281','舟還浯溪再留二絕  其一','留筠','宋','宋诗','song-poetry','','[]','爲愛浯溪風景幽，重臨釣石繫歸舟。',32,'全唐诗/poet.song.169000.json','["爲愛浯溪風景幽，重臨釣石繫歸舟。", "不妨細讀豐碑下，墨本空看幾白頭。"]'),
('912c9910-59ec-4425-8fd0-404ad2d95349','舟還浯溪再留二絕  其二','留筠','宋','宋诗','song-poetry','','[]','自笑塵埃賦□忙，佳山招我莫徜徉。',32,'全唐诗/poet.song.169000.json','["自笑塵埃賦□忙，佳山招我莫徜徉。", "何當了却癡兒事，來伴高人枕碧湘。"]'),
('b71f46bb-1569-4a45-9073-39238bedf0b2','題清暉樓二首  其一','留碩','宋','宋诗','song-poetry','','[]','萬古龍濤山水窟，何人携向嶺邊州。',32,'全唐诗/poet.song.169000.json','["萬古龍濤山水窟，何人携向嶺邊州。", "朝來蜃氣連城白，幻作恩平第一樓。"]'),
('922ff8c0-07ee-49e0-92a7-507708dc9e3e','題清暉樓二首  其二','留碩','宋','宋诗','song-poetry','','[]','元龍高卧翠微中，碌碌諸人總下風。',32,'全唐诗/poet.song.169000.json','["元龍高卧翠微中，碌碌諸人總下風。", "眼底樸陳無盡藏，八窗還我自玲瓏。"]'),
('1bea5b6c-702e-46e2-8a11-a1529a871cce','勸農三首  其一','留碩','宋','宋诗','song-poetry','','[]','春風勾引出郊行，小隊迢迢草路平。',32,'全唐诗/poet.song.169000.json','["春風勾引出郊行，小隊迢迢草路平。", "自笑田蕪不歸去，三千里外勸人耕。"]'),
('37637b04-17d7-47bb-94d6-20acc8aed15e','勸農三首  其二','留碩','宋','宋诗','song-poetry','','[]','何處園林今有花，十分春事只桑麻。',32,'全唐诗/poet.song.169000.json','["何處園林今有花，十分春事只桑麻。", "不須惆悵窮途目，一飽生涯無歎嗟。"]'),
('1472d36d-f757-48c6-aa7b-f5148fcf6fdb','勸農三首  其三','留碩','宋','宋诗','song-poetry','','[]','長年城上望溪山，今日纔能一往還。',32,'全唐诗/poet.song.169000.json','["長年城上望溪山，今日纔能一往還。", "特地曉風吹雨斷，可應天意更予慳。"]'),
('04648c21-ab48-483b-83c9-aeefb4f436c8','寄高善勝','趙某','宋','宋诗','song-poetry','','[]','雨窗思昔日，不見半年餘。',48,'全唐诗/poet.song.169000.json','["雨窗思昔日，不見半年餘。", "別後幾回夢，中間三寄書。", "兵戈吾幸免，蹤跡爾何如。", "世事難如意，同心却異居。"]'),
('83bc840e-ebf0-4867-8049-12123316ee1c','清發軒','趙某','宋','宋诗','song-poetry','','[]','許多清意思，都在此鄉間。',48,'全唐诗/poet.song.169000.json','["許多清意思，都在此鄉間。", "有石半枕水，無窗不面山。", "侵衣青靄潤，擁釣白雲閒。", "未許嫌幽寂，古人曾閉關。"]'),
('401005fd-3fb5-4ec6-a9e8-46c506d91efc','眉峰水陸寺','趙某','宋','宋诗','song-poetry','','[]','貪觀眉嫵翠，艤棹碧雲間。',48,'全唐诗/poet.song.169000.json','["貪觀眉嫵翠，艤棹碧雲間。", "蕭寺前臨水，丁家舊住山。", "苔深僧跡靜，松冷鶴巢鰥。", "拜手先祠下，奔馳覺汗顔。"]'),
('15a04d79-618b-4044-9506-9bc94038d6d6','述懷','趙某','宋','宋诗','song-poetry','','[]','得鹿歸來一夢中，半生事業總成空。',64,'全唐诗/poet.song.169000.json','["得鹿歸來一夢中，半生事業總成空。", "飯牛豈意干西伯，尋馬何須訪北翁。", "趙既有辭難奪璧，楚將無事嘆忘弓。", "南薰正解吾民慍，且弄朱絃奏晚風。"]'),
('1ecbff2b-3166-41cd-a1dc-8d4dff5c2285','杏村聞其友謝昌元及二趙一家俱入翰苑','趙某','宋','宋诗','song-poetry','','[]','歸來白鹿巖邊屋，清得門庭冷似冰。',64,'全唐诗/poet.song.169000.json','["歸來白鹿巖邊屋，清得門庭冷似冰。", "公事中原雙短鬢，帝鄉孤夢一青燈。", "带烟鉏菊閒教僕，和月折梅時寄僧。", "見說道山應咫尺，同時俊彥盡先登。"]'),
('e4515559-5bfc-41ef-8824-87a08dcb0c68','休官','趙某','宋','宋诗','song-poetry','','[]','欲知趙子休官了，貧似扶風馬少游。',64,'全唐诗/poet.song.169000.json','["欲知趙子休官了，貧似扶風馬少游。", "借得琴樽留待月，從教簾幕不勝秋。", "自携僕出閒尋葯，因載書多却買舟。", "昨日老農來告我，萬千樂事在西疇。"]'),
('51c3c631-f15a-4dcc-8337-7c47224d4ad4','馮公嶺','葉適','宋','宋诗','song-poetry','','[]','馮公此山民，昔開此山居。',156,'全唐诗/poet.song.169000.json','["馮公此山民，昔開此山居。", "屈盤五十里，陟降皆林廬。", "公今去不存，耕鑿自有餘。", "風篁生谷隧，雨旆來岩虛。", "人隨亂雲入，咫尺聲相呼。", "四時草木香，異類果蔌腴。", "棌薪得崖花，結綴成襟裾。", "此亦佳窟宅，可對幽人娛。", "何必種桃源，始入仙者圖。", "甌閩兩邦士，洶洶日夜趨。", "辛勤起芒屩，邂逅乘輪車。", "山人老白首，名氏不見書。", "我獨何爲者，拊身念居諸。"]'),
('5189603d-ddb7-404f-a2a5-dbef674cf459','吳江華嚴塔院贈了洪講師','葉適','宋','宋诗','song-poetry','','[]','具區以爲潴，吳江以爲裨。',252,'全唐诗/poet.song.169000.json','["具區以爲潴，吳江以爲裨。", "自專一方浸，盡納海所遺。", "逝川無發歎，麗澤可求師。", "昔人會心地，今爲魚鳥資。", "飛者自無極，遊者自無涯。", "造物不諄諄，亦莫分何誰。", "此時余與子，相遇相諧嬉。", "曾觀烟雨外，未滿蒼茫思。", "復來秋風後，重有騷屑悲。", "不及日月入，爛焉墮輪規。", "尚見波濤驚，纍然擁丘坻。", "况彼瑣細者，蒲菼爭紛披。", "當年吳季子，德合無醇疵。", "范蠡之所矜，視之眇毫厘。", "末路張季鷹，適意亦見推。", "人才非一端，事近苦易移。", "常恐後生輩，風流日凌遲。", "縣憂公家迫，俗陋棟宇卑。", "子將跨大閣，對此連天瀰。", "英雄久銷歇，枯槁乃光輝。", "寘余一榻處，析理定興衰。"]'),
('290ffa32-8498-475f-a411-c69eec4154ea','送趙景明知江陵縣','葉適','宋','宋诗','song-poetry','','[]','吾友趙景明，材絕世不近。',144,'全唐诗/poet.song.169000.json','["吾友趙景明，材絕世不近。", "疏通無流連，豪俊有細謹。", "尤精人間事，照見肝膈隠。", "忽然奮鬚髯，萬事供指準。", "漢士興伐胡，唐軍業誅鎮。", "久已受褒封，誰能困嘲擯。", "四十七年前，時節憂患盡。", "去作江陵公，風雨結愁慍。", "昔稱長官貴，今歎服勞窘。", "夜光儻無因，早晦行自引。", "田園多遯夫，未必抱奇藴。", "勉發千鈞機，一射强虜殞。"]'),
('4c4a1376-7cc5-4461-b0dc-3cf0c2c27c46','送鄭景元','葉適','宋','宋诗','song-poetry','','["\u8861\u5c71"]','兄弟同升難，高材自摧角。',120,'全唐诗/poet.song.169000.json','["兄弟同升難，高材自摧角。", "官多復不記，四載禮南嶽。", "一朝盡室去，菲食遭歲惡。", "丈夫軒豁意，快緊出鷹鶚。", "忍事得無慚，信有古人學。", "建安雖閩壤，桂樹美可樂。", "合抱更連理，叢生蔭州郭。", "歲月歷悠長，根株見齦齶。", "終當作大厦，積功在雲壑。", "尚友如此君，蒼天未爲薄。"]'),
('b25d4a08-9355-4f61-8bbe-d08583b0d38f','題賈儼不忘室','葉適','宋','宋诗','song-poetry','','[]','賈子好脩士，躬耕鹿岩阿。',264,'全唐诗/poet.song.169000.json','["賈子好脩士，躬耕鹿岩阿。", "茂木俯青泉，幽處堪逶迤。", "有室凈棐几，圖史參前羅。", "獨能取我語，標榜相巍峩。", "我語不必記，子意故足多。", "物之徇外者，迅若橫流波。", "當其一念覺，胼胝駐崩渦。", "神丸起痿瘵，厚纊還暄和。", "倫類苟通明，軌轍寧舛訛。", "但憂所見弱，繚如附松蘿。", "輿薪豈不睹，奈此斤斧何。", "勿令學高山，所至纔獻坡。", "如於衆稊稗，收拾同穎禾。", "雖云善端在，坐悼良時過。", "子先發曹掾，仁義躬濯磨。", "活人不知數，一善禳衆瘥。", "每識飯牛下，有作甯戚歌。", "至今鄉里敬，墓柏垂霜柯。", "子質復粹美，藻火兼佩珂。", "中夜再三歎，警策自詆訶。", "未合者參辰，已逝者江河。", "所願天爵尊，非必貴决科。"]'),
('e6e749b7-0449-4db2-a8f3-a3f668a43728','陳同甫抱膝齋二首  其一','葉適','宋','宋诗','song-poetry','','[]','昔人但抱膝，將軍擁和鑾。',120,'全唐诗/poet.song.169000.json','["昔人但抱膝，將軍擁和鑾。", "徒知許國易，未信藏身難。", "功雖愆歲晚，譽已塞世間。", "今人但抱膝，流俗忌長歎。", "儒書所不傳，群士欲焚刪。", "譏訶致囚箠，一飯不得安。", "珠玉無先容，松柏有後艱。", "內窺深深息，仰視冥冥翰。", "勿要兩脾消，且令四體胖。", "徘徊重徘徊，夜雪埋前山。"]'),
('ab27e339-0b49-4c8c-aef1-c3b35be2315d','陳同甫抱膝齋二首  其二','葉適','宋','宋诗','song-poetry','','[]','音駭則難聽，問駭則難答。',108,'全唐诗/poet.song.169000.json','["音駭則難聽，問駭則難答。", "我欲終言之，復恐來蹲沓。", "培風鵬未高，弱水海不納。", "匹夫負獨志，經史考離合。", "手捩二千年，柔條起衰颯。", "念烈儻天回，意大須事匝。", "偶然不施用，甘盡齋中榻。", "寧爲楚人弓，亡矢任挽踏。", "莫作隋侯珠，彈射墜埃壒。"]'),
('27b7cbc7-4d6a-4efe-b2b6-a94dac703188','超然堂','葉適','宋','宋诗','song-poetry','','[]','晨興詣曹參使馹，傳呼趨庭頭頸屈。',192,'全唐诗/poet.song.169000.json','["晨興詣曹參使馹，傳呼趨庭頭頸屈。", "退歸闔戶胥吏玩，過門掉臂不入室。", "宅舍空荒轉頹漏，騶僕藍縷常寒乞。", "此堂豈可更超然，乍可鞅掌中怫鬰。", "每憐莊周齊物論，遣詞曠蕩違經律。", "獨稱松柏受正命，舜何人哉盡倫匹。", "萍實浮沉江漢遠，劍氣騰擲牛斗出。", "招徠鳳麟已悠緩，琢磨圭璧强堅密。", "檐擎自貴竭人力，起倒相因廢天質。", "古今問學滿天下，分寸毫厘難細詰。", "以茲凜凜觀萬事，口不敢言心自失。", "今朝幸續省倉米，且以糜煎飽時日。"]'),
('bd3fbb5c-51ef-47b5-80af-90d6f42f1883','再過吳江贈僧了洪','葉適','宋','宋诗','song-poetry','','[]','回飈掩夾浦，勢與黑樓頏。',120,'全唐诗/poet.song.169000.json','["回飈掩夾浦，勢與黑樓頏。", "連袂上長橋，身弱屢見扛。", "苟無傾覆憂，恣橫未易當。", "坐定互驚愕，師云乃其常。", "有時氣力雄，駕浪拍此邦。", "熟風無失舟，小艇來茫茫。", "始悟寡所諳，論改色據張。", "衒小以爲大，空令事難量。", "玩變不覩微，亦乖智之方。", "已矣勿復云，聞鐘過石塘。"]'),
('912e3c3d-e935-4b8e-98ca-638475a90073','靈巖','葉適','宋','宋诗','song-poetry','','[]','穹窿右俛眉，天平左垂鬢。',180,'全唐诗/poet.song.169000.json','["穹窿右俛眉，天平左垂鬢。", "吳人宅沮洳，茲山抑其鎮。", "陡起爲表著，突兀數尋仞。", "樛松頗堅瘦，立石乃榮潤。", "兼有千里陂，杳靄來遠韻。", "宜乎登椒丘，擺落思奮迅。", "亡王未亡時，絕色館孤峻。", "歌聲妙欵乃，俎品窮蛤蜃。", "援琴固停咎，解甲仍轉瞬。", "終歸寂寞人，破釜煮枯堇。", "陳迹不足吊，新締何勞問。", "三年姑蘇驛，空望此塔近。", "適當熟食節，暖氣無已吝。", "豪風增春愁，異雪損花信。", "聊以壯遊衍，歸受兒女囅。"]'),
('4b3737d9-3e5a-473a-82a2-bf92e153bc03','葑門','葉適','宋','宋诗','song-poetry','','[]','遺墨固藏神，希聖非立我。',144,'全唐诗/poet.song.169000.json','["遺墨固藏神，希聖非立我。", "斷後輒無前，實右即虛左。", "品定賦纖洪，義明分勇懦。", "端木語衛文，洙泗皆卿佐。", "孔子敘夷齊，後進尚嵬瑣。", "從來一大事，幾作鴻毛荷。", "知非言所及，結網魚受課。", "誰持空空質，放縱無不可。", "茲門小精廬，荒寂衆萬過。", "欣余二三子，拙力守饑卧。", "楊花安得攬，飛去天隅唾。", "唯有露垂垂，滿畦紅藥墮。"]'),
('16e60f2e-9038-4ab6-8a90-75b5d1268f3c','還華賢良九經說賢良進卷語林等','葉適','宋','宋诗','song-poetry','','[]','華君官五世，人物樸而重。',144,'全唐诗/poet.song.169000.json','["華君官五世，人物樸而重。", "窮經不辭難，著論何其勇。", "編排過百帙，裝庋高一冢。", "見聞頗驚訕，吟玩自欣悚。", "余本空疎人，盛刺勤遠捧。", "津般俾之讀，涉岸滄溟洶。", "惟知畏浩博，敢復議煩冗。", "芄蘭恨柔蔓，櫟社嫌擁腫。", "誰令獨管吹，而爲衆竽恐。", "楊墨岐路迷，服鄭丘林拱。", "西鄰黄策子，簡要獲天寵。", "君兮幸持歸，卧看雲生壠。"]'),
('f552b631-d361-4113-88e6-1dd8e2d9f0b4','齊雲樓','葉適','宋','宋诗','song-poetry','','[]','天下雄諸侯，蘇州數一二。',288,'全唐诗/poet.song.169000.json','["天下雄諸侯，蘇州數一二。", "都會自昔稱，陪京今也貴。", "奕奕撰重樓，岧岧立平地。", "虛景混空蒼，囂聲收遠肆。", "闉闍雖散闊，欄檻皆堪記。", "向非土木力，焉能快高視。", "湖山西南維，江海東北塈。", "舒緩未爲愚，疏達終多智。", "窮民一宵燈，細巧雜紋織。", "豪士三春卉，妖麗亂名字。", "侈甚見精誠，富餘輊講肄。", "先朝豐豫日，應奉稽古義。", "花綱飛入汴，石林鬼浮泗。", "天然造生活，始者行賑施。", "王公占上腴，邸觀角奇致。", "是邦聚璀璨，四顧盡憔悴。", "狂胡誤濡足，遺爇等交臂。", "艱難屢省方，薄遽虧頓置。", "因循墮和好，俛仰銷年歲。", "翻憐井邑盛，又使編氓匱。", "頗云魚蝦微，亦已困征稅。", "人生賤苟免，所尚剛强氣。", "呼鷹飽何待，暴虎怒斯易。", "吁嗟久悒悒，胡爲長惴惴。"]'),
('0667690f-04ee-44e6-9882-69f63679b71a','虎丘','葉適','宋','宋诗','song-poetry','','[]','虎丘之名歲二千，虎丘之丘何渺然。',128,'全唐诗/poet.song.169000.json','["虎丘之名歲二千，虎丘之丘何渺然。", "衆山爭高隠日月，笑此拳石埋平田。", "雖然培塿疑異物，劃開陰崖十丈懸。", "冢中有恨索遺劍，亭上無語傳枯禪。", "偏是吳人愛山急，逐面分方誇凭立。", "屋承隋唐良穩稱，墨題熙豐尚新濕。", "松梢莫遣風雨橫，石盤自添苔蘚澀。", "春來春去吳人游，足繭層巔踣應泣。"]'),
('2de4eba1-e275-442c-8715-5a3f9be5d521','北齋  其一','葉適','宋','宋诗','song-poetry','','[]','頻年寄全吳，廨宇雜營保。',180,'全唐诗/poet.song.169000.json','["頻年寄全吳，廨宇雜營保。", "前廳久傾壓，後舍岌欹倒。", "常因霖雨後，壁壞不容掃。", "跳蛙浴漏潴，野穀媚穿杲。", "以茲違色養，先還媿親老。", "低頭謾商歌，瞪視豁愁抱。", "當身良易足，遺後非長道。", "幸今脩整畢，楹桷正完好。", "晴窗閑晝永，夜榻初凉早。", "友朋坐雍雍，燕雀鳴草草。", "居室君子後，蓽門固爲寶。", "矧伊澤國士，敗棟威塗潦。", "繆充使者屬，職思振枯槁。", "人之所歆羨，未必天能造。", "卷藏姑罷歸，蠹簡說剛浩。"]'),
('f01d3276-ee15-48b1-97de-d36a7e082382','北齋  其二','葉適','宋','宋诗','song-poetry','','[]','人情無終極，匪陋則求佳。',180,'全唐诗/poet.song.169000.json','["人情無終極，匪陋則求佳。", "寢處既少安，游燕豈不懷。", "惟思舊酒務，糟酵茺榛埋。", "破瓶聚隆垤，新甃連長階。", "種竹夾超然，移花遶北齋。", "及爾風露清，忽感意象諧。", "幽深容浪蕊，潤澤長芳荄。", "亭亭兩高梧，買自婁門街。", "俟以歲屢寒，窅若萬仞崖。", "吾留能幾日，齪齪强安排。", "方嫌樹影瘦，復慮地勢𠇗。", "世間香味悅，每與腥羶偕。", "雅故使鄭淆，法語仍進徘。", "俯同侏儒笑，但恐好惡乖。", "莫窮有限物，徇此未腐骸。"]'),
('246e95a6-2466-49aa-bbf8-ddaede7cf0f8','題椿桂堂','葉適','宋','宋诗','song-poetry','','[]','九官八士古之良，靈椿丹桂後騰芳。',128,'全唐诗/poet.song.169000.json','["九官八士古之良，靈椿丹桂後騰芳。", "馮公詩意雖短陋，閭里傳誦終難忘。", "君家同生五兄弟，短檠伴夜東方啟。", "黄旗兩記張慶闈，紵袍三號趨文陛。", "辭華標角人力能，科名均齊天所興。", "作堂不須棟梁好，但種此木高千層。", "透日垂陰香未歇，滿庭車騎同時列。", "更將磊砢替團團，留與北風觀壯節。"]'),
('70386eb2-a5bf-4a32-a628-0a44f3c11560','贈訥相','葉適','宋','宋诗','song-poetry','','[]','柯山訥相醜形模，以相獲妍如子都。',128,'全唐诗/poet.song.169000.json','["柯山訥相醜形模，以相獲妍如子都。", "每將氣色較官簿，初若搏影終探符。", "劉公實，陞提刑。", "丘宗卿，加龍圖。", "就中兩說最稱驗，余耳所逮非人誣。", "汎言心事依勸戒，多假名器煩邀呼。", "君門九重遠萬里，求者爭道分榮枯。", "一身暫寄百骸聚，楦彼朱紫誰頭顱。", "子其惜術無浪許，恐負西山之饑夫。"]'),
('c74da662-1f1a-4409-9b90-6e30eed4b605','送鄭虞任赴京西檢法官','葉適','宋','宋诗','song-poetry','','[]','春風逝無涯，夏潦生未已。',120,'全唐诗/poet.song.169000.json','["春風逝無涯，夏潦生未已。", "思君遡江漢，行銳業難止。", "事繁絲唾亂，神靜魚鱗理。", "前年浙東幕，借助獲專美。", "邊頭值閑暇，人物盛儲歭。", "荒村魚米場，孤戍花藥市。", "雅知足禪味，翫世失憂喜。", "但疑柳上白，時雜髯間紫。", "豈非久不遇，感歎妨隠几。", "回首舊隆中，畦壠長薿薿。"]'),
('8a91a434-bc9f-4ea8-bc84-f79b18707a26','張氏東園送王恭父得殿字','葉適','宋','宋诗','song-poetry','','[]','燕鴻不相須，進趣自求便。',192,'全唐诗/poet.song.169000.json','["燕鴻不相須，進趣自求便。", "余來君其館，乃復當我餞。", "一春三月雨，亭樹鬰霧澱。", "絮重厄飛楊，花蔫堆紫茜。", "縱有百壺清，何能一笑遣。", "爲郎昔同甲，四海初會面。", "凜然抱英特，霜宇摶溫霰。", "雄辭推落筆，一語不可選。", "重來更純粹，玉琢金就鍊。", "漢家闡道術，四達詔群彥。", "談經石渠觀，會議白虎殿。", "通方要歸宿，立異豈夸衒。", "子行若微罪，天意委深眷。", "以其今固辭，可信非始戀。", "楚熱宜縐絺，峽漲難短牽。", "回舟泊書林，及此未掩卷。"]'),
('1aa65cf4-23d0-42b8-b783-7aefc9d9e199','奉賦德修西充大夫成都新園詠歸堂二首  其一','葉適','宋','宋诗','song-poetry','','[]','浣花炫春澨，濯錦絢晴浦。',144,'全唐诗/poet.song.169000.json','["浣花炫春澨，濯錦絢晴浦。", "成都信繁會，此水工媚嫵。", "豈無濠上亭，蹙步難仰俯。", "誓言違市朝，卜宅近幽阻。", "沃沃葵莧畦，焰焰棠杏塢。", "朝曦濕淺瀨，暮色生遠渚。", "循涯詠未厭，引流絡其圃。", "蘋荇依籬樊，鳧鴈宿庭戶。", "長松百里外，物象爭渺莽。", "時平乏隠淪，簑笠自歌舞。", "岷江志東向，激射走吳楚。", "胡爲滯淫之，習坎聖所許。"]'),
('f454350d-a481-43ad-bda9-ee9ebdb56730','奉賦德修西充大夫成都新園詠歸堂二首  其二','葉適','宋','宋诗','song-poetry','','[]','我生海旁州，古言江來鋪。',144,'全唐诗/poet.song.169000.json','["我生海旁州，古言江來鋪。", "力浮萬頃盡，坐識一溜初。", "之子酌彼源，紺潔玉斗𣂏。", "雅韻舒煩憂，逸駕陵趦趄。", "詠歸有何意，豈亦歌風乎。", "湛湛遊無梁，滔滔濟無桴。", "縱橫洄伏中，暮齒將焉需。", "三間始開闢，十畝終耘鋤。", "東西兩莊舍，兄弟相譍呼。", "緬哉趨前規，更作却後圖。", "顧思曲肱樂，一身匪求餘。", "我獨無家歸，羨子鎸自迂。"]'),
('ed7c9815-aaa0-4923-8b1e-758d4e70b368','送馮傳之','葉適','宋','宋诗','song-poetry','','[]','我乞來荆州，足未曾出門。',240,'全唐诗/poet.song.169000.json','["我乞來荆州，足未曾出門。", "明明楚漢迹，莽莽風塵昏。", "茲復罷著書，梵譯專討論。", "頹然對白法，諸有不得存。", "傳之京口別，歲暮始窮源。", "帆張飛動勢，纜繫棲泊痕。", "相顧舉杯酒，醉極沮漳翻。", "儒生慕傑氣，赤手誅鯨鯤。", "將軍建實壘，寸甓宜自攢。", "于時雪五尺，遣卒問江干。", "答言屈大夫，橫肆羣魚吞。", "豈如衛甯蘧，舒卷常溫溫。", "聞此重嗟嘆，恐墮禍福觀。", "榮禳用國寶，誰能免沉燔。", "要令德性脩，仍挽江海渾。", "我今材力盡，拙計東南坤。", "尚餘春秋志，欲執左袵奔。", "念子獨奈何，葺屋補牆藩。", "梅花一兩坼，春意到草根。", "倘見南枝榮，折寄隨驚湍。"]'),
('e18adaf3-34d9-4fdd-8623-7ebda437531b','送李郛','葉適','宋','宋诗','song-poetry','','[]','蓋代才難看獨手，衆參聞見其來久。',128,'全唐诗/poet.song.169000.json','["蓋代才難看獨手，衆參聞見其來久。", "流風莫盛元祐時，崛起誰當紹興後。", "嗟君探討窮一生，心通文字難力爭。", "雀啄雪籬閣筆坐，蟲吟露草繙書行。", "已輕富貴須臾爾，萬一姓名傳野史。", "只愁垂老絕知音，自送青編滿朝市。", "余之視君尚少年，題玉爲珉何所賢。", "期君更盡未死日，舉世不信方知天。"]'),
('3d5e831f-ec85-4d93-a31c-7d4e5692d437','送喻太丞知處州','葉適','宋','宋诗','song-poetry','','[]','喻公策名自先朝，奉常冬官始見招。',64,'全唐诗/poet.song.169000.json','["喻公策名自先朝，奉常冬官始見招。", "何因歛退爲泉石，可惜垂欲排雲霄。", "處州不城山作堵，百嶂千峰自翔舞。", "孤高上頭天一柱，中有秀句須公取。"]'),
('10767294-0f71-4cd6-91dc-7f37eb8b32e0','送劉德修','葉適','宋','宋诗','song-poetry','','[]','羣航弭安流，未脫孤帆厄。',168,'全唐诗/poet.song.169000.json','["羣航弭安流，未脫孤帆厄。", "獨板亂橫潰，始負衆舟責。", "蟄雷正須時，春雨宜滿澤。", "勇夫攻堅退，智士倒戈獲。", "去年北關路，永歎出處隔。", "俄掀鳳儀雅，緩彼梟搏磔。", "發覆洗塗糊，召和開褊迫。", "一日期萬年，倏眒展長策。", "居然西州道，千仞斂歸翮。", "鬢髮何用青，肝膽元自白。", "古聖豈不勞，築此英俊宅。", "誰令閉榛莽，回曲用蠻貊。", "天門昳蕩蕩，瑶實連蔓摘。", "種玉如有方，從今空櫝索。"]'),
('e724377d-0fd3-4c48-ac2d-12c819d09068','題李君亮義槩堂','葉適','宋','宋诗','song-poetry','','[]','分飧人所能，多至踰萬億。',168,'全唐诗/poet.song.169000.json','["分飧人所能，多至踰萬億。", "一朝可趣具，寒暑三十易。", "古之轑釜者，其始蓋未惜。", "懷哉西方士，義重見寡特。", "招呼幾州氓，歲歲青黄食。", "雷聲匕筯動，雲湧床座窄。", "昔我手行粥，今也愆膂力。", "憶汝身自孩，又抱兒子喫。", "豈有不足歎，幸無嗟來色。", "天爲産厥孫，文射最高策。", "勞君太史令，乞彼峨眉伯。", "出處善知時，教訓陶美澤。", "築堂事遺像，雅頌鎸衆墨。", "我歌則後矣，猗歟綴周什。"]'),
('a2c2e034-bab7-43bc-977b-d5fdd0430653','醫工歎重贈柳山人','葉適','宋','宋诗','song-poetry','','[]','柳生洲居濠北邊，繇辭質野誰所傳。',264,'全唐诗/poet.song.169000.json','["柳生洲居濠北邊，繇辭質野誰所傳。", "不曾入城行賣卜，有問災福須呼船。", "歎我奇疾何頻年，其初過清肌凜然，已忽腹拒遭拘攣。", "一身盡異形質變，恍若土木徒人言。", "蚤知定性不生滅，今安得爾庸非天。", "醫工刃人死無律，妄談標本從何出。", "補勞護弱轉凝聚，排寒盪濕加淫鬰。", "挾風上行關膈失，迸肉糜皮併爲一，猶云無傷乃餘疾。", "生雖憐我謬時命，豈悟顛倒緣此物。", "彼蒼應有司殺者，授柄於工無乃悖。", "我勞萬事明當休，自古零落歸山丘。", "但疑未死復不活，熟視重爲諸醫羞。", "餘聰殘明不可留，治命已乖妻子謀，執訊空貽友朋憂。", "柳生聽罷掉頸笑，既有主對非吾尤。", "山歌靜夜聲宛轉，更著此曲歌中流。"]'),
('1773917d-4c79-4fca-b307-49b2b573301e','宿石門','葉適','宋','宋诗','song-poetry','','[]','好溪瀉百壑，南北傾萬峰。',240,'全唐诗/poet.song.169000.json','["好溪瀉百壑，南北傾萬峰。", "山凡堆阜俗，映岸羞爲容。", "石門忽秀出，老幹蔭渟洪。", "捨舟從口入，便已離塵中。", "衆芳拱窟宅，環岡獻奇穠。", "藤蘿異態度，尺寸疑施功。", "錦茵翠織成，照耀無春冬。", "水行千丈高，噴薄不可窮。", "更有洗頭盆，雲深霧常封。", "昔年謝康樂，築居待其終。", "繼作者丘裴，語言亦稱雄。", "邈然百世後，未忝騷人風。", "栖栖三羽衣，日晏齋厨空。", "云子歇過槳，蹔洗氛埃胸。", "自歎苦淹留，寂寞不易供。", "嗟我老無用，佞山久成翁。", "結廬會昌側，勢落魚蝦叢。", "種竹似束葦，栽松如斷蓬。", "小兒餖盆盂，何時至周公。", "會當同此住，代輸助之舂。"]'),
('8dc4be25-3c68-4fec-8b57-772c813ba10f','月谷','葉適','宋','宋诗','song-poetry','','[]','昔從東萊呂太史，秋夜共住明招山。',48,'全唐诗/poet.song.169000.json','["昔從東萊呂太史，秋夜共住明招山。", "正見谷中孤月出，倒影挼碎長林間。", "憑師記此無盡意，滿掃一方相並閑。"]'),
('8a4170bf-a093-4a05-8940-c7c6a395cf67','禱雨題張王廟','葉適','宋','宋诗','song-poetry','','[]','夏至老秧含寸荑，平田回回不敢犁。',128,'全唐诗/poet.song.169000.json','["夏至老秧含寸荑，平田回回不敢犁。", "羣農無計相聚泣，欲將淚點和乾泥。", "祠山今古同一敬，籤卦分明指休證。", "傳言杯珓三日期，注綆翻車連曉暝。", "龍神波后何慘愴，昔睡今醒喜蕭爽。", "人云天上行水曹，取此化權如反掌。", "浙河以東盡淮壖，哀哉震澤幾爲原。", "願王頓首玉帝前，請賜此雨周無偏。"]'),
('5bf6e76a-d56f-4a34-bb4b-e775ec4dec62','寄黄文叔謝送真日鑄','葉適','宋','宋诗','song-poetry','','[]','建溪疑雪白，日鑄勝蘭芳。',48,'全唐诗/poet.song.169000.json','["建溪疑雪白，日鑄勝蘭芳。", "誰知真苦澀，黯淡發幽光。", "騎省可正論，農卿今則亡。", "懷人坐太息，泉竭鼎無湯。"]'),
('19000230-57a9-4a9b-a0d9-3d9f4e33f2b6','送黄竑','葉適','宋','宋诗','song-poetry','','[]','有客家住寶劍窟，將身自比夜明簾。',128,'全唐诗/poet.song.169000.json','["有客家住寶劍窟，將身自比夜明簾。", "見我立談盡肝膈，駭視世俗徒沾沾。", "千年豪傑供指使，笑撻胡虜如奴鉗。", "嗟予病衰絕少韻，只欲炙背依茅簷。", "勸子持難復居易，呂梁之舟先歷試。", "焦桐邂逅爨下薪，良玉磋磨廟中器。", "誰言怒海鯤鯨惡，別有晴川鷗鳥戲。", "心亨習坎行自孚，安流儻寄相思字。"]'),
('b503cae1-cfd9-4ae0-9bb6-5c3ceee6f3f7','浄光松風閣','葉適','宋','宋诗','song-poetry','','[]','城中雲日如火催，凈光行食聲轉雷。',64,'全唐诗/poet.song.169000.json','["城中雲日如火催，凈光行食聲轉雷。", "不知何處白蘋起，便有滿坐清風來。", "莫言作樓非急務，翁當運斤兒執鋸。", "待得三間著此風，病叟扶携上樓去。"]'),
('806847e2-ed6b-4e0a-aa4f-4ab68cc4f44a','送蔡夢得','葉適','宋','宋诗','song-poetry','','[]','寸步旱黏楫，千里脂染輪。',52,'全唐诗/poet.song.169000.json','["寸步旱黏楫，千里脂染輪。", "四國嚴諸侯，江沙渺無津。", "翁令去何之，綠樹羞鬢銀。", "惟應苦吟徹龍室，報以頷珠光比日。"]'),
('b16ae789-d264-4b21-91b1-8359936cb941','和答錢廣文蘭松有剛折之歎','葉適','宋','宋诗','song-poetry','','[]','蘭居地之陰，藹藹含華滋。',72,'全唐诗/poet.song.169000.json','["蘭居地之陰，藹藹含華滋。", "此本不以剛，而爲剛者師。", "松無棟梁具，何用稼冰雪。", "終風撓長林，常恐浪摧折。", "願子比令德，一薰容衆蒿。", "笑我非實材，千載空獨高。"]'),
('08d3fa88-53cb-4bc6-9a66-0ba6920e9d72','趙振文傳借琉璃燈鋪寫山水人物一燭發明百巧呈露畫師精妙者不能過也','葉適','宋','宋诗','song-poetry','','[]','古稱浄琉璃，物現我常寂。',48,'全唐诗/poet.song.169000.json','["古稱浄琉璃，物現我常寂。", "胡爲自爭妍，照耀出痕迹。", "坐有求心客，駭目不忍看。", "願息終歲勞，留作袖手安。"]'),
('bf96048a-3f52-405c-849e-4fa486d4e6ed','和答徐斯遠兼簡趙昌甫韓仲正','葉適','宋','宋诗','song-poetry','','[]','江東文士稱數人，寶冠霞珮朝靈君。',64,'全唐诗/poet.song.169000.json','["江東文士稱數人，寶冠霞珮朝靈君。", "盧敖善游指天去，呂望應招離海濱。", "有書不止問無恙，平生懷抱陳案上。", "會看作意鳴朝陽，陰狐夜短空惆悵。"]'),
('74f1ffa9-feec-4150-8279-b74378496153','徐仁父先大夫詩卷指其改補鍋八句曰願有請因疏下方','葉適','宋','宋诗','song-poetry','','[]','江南隠君子，琢語冰段清。',48,'全唐诗/poet.song.169000.json','["江南隠君子，琢語冰段清。", "彼美補鍋篇，義遠有勸懲。", "烹飪一餉止，操持千載成。", "未須誇染指，歲晏期曲肱。"]'),
('825cdd58-3663-47d2-a097-0ddd79013e47','題孫季蕃詩','葉適','宋','宋诗','song-poetry','','[]','子美太白常住世，佳人栩栩夢魂通。',64,'全唐诗/poet.song.169000.json','["子美太白常住世，佳人栩栩夢魂通。", "瀉落天河澆汝舌，移來不周盪汝胸。", "千家錦機一手織，萬古戰場兩峰直。", "孰南孰雅喚莫前，虛簫浪管吹寒烟。"]'),
('5724548d-d237-4727-a971-fff009e7fa77','石經春秋一代奇寶王氏爲熙豐學廢不用瑞安沈彬老蠟而有之後世孫體仁閣以庋焉余爲名曰深明','葉適','宋','宋诗','song-poetry','','[]','喟昔洛門初上石，未久翻遭禁書厄。',64,'全唐诗/poet.song.169000.json','["喟昔洛門初上石，未久翻遭禁書厄。", "沈公祕藏百載餘，高閣突兀共堆積。", "萬物散聚常橫陳，汀花岸草從紛紜。", "海雲化雨龍正起，想象向來悲獲麟。"]'),
('81563cf1-f742-4ea0-8c6c-86208cd19833','贈二葛友','葉適','宋','宋诗','song-poetry','','[]','飛飛下荒村，渺渺集蕪城。',48,'全唐诗/poet.song.169000.json','["飛飛下荒村，渺渺集蕪城。", "振衣出虹蜺，覆簣超丘陵。", "魯衛百世腴，夷齊萬年清。", "翻然捨我去，東風初渙冰。"]'),
('337e00aa-0c06-486d-8559-e86ef2095f11','呂子陽辭蘭谷家園却就石泉精舍','葉適','宋','宋诗','song-poetry','','[]','子陽意高希古人，文如行空無定雲。',128,'全唐诗/poet.song.169000.json','["子陽意高希古人，文如行空無定雲。", "清明未容詩酒污，放曠自許漁樵親。", "故園好木日夜長，友逝兄淪不同賞。", "改綠移紅自若何，躡磴捫蘿心獨往。", "我昔迷津經上呂，鬭出飛亭壓行路。", "石影參差研匣寒，花陰回薄書奩暮。", "離家十里山轉深，琅玕滿地芝成林。", "竹鷄睡去月當午，閑聽孫登長嘯音。"]'),
('539c2235-8ff0-4f31-aade-9879223d72fd','永嘉端午行','葉適','宋','宋诗','song-poetry','','[]','行春橋東峙巖北，大舫移家住無隙。',128,'全唐诗/poet.song.169000.json','["行春橋東峙巖北，大舫移家住無隙。", "立瓶叵羅銀價踴，冰衫雪袴胭脂勒。", "使君勸客親付標，兩朋予奪懸分毫。", "起身齊看船勢側，橈安不動濤頭高。", "古來崢水鬭勝負，湖邊常贏豈其數。", "岸騰波沸相隨流，回廟長歌謝神助。", "只今索莫何能爲，敗鼓攪壕觀者稀。", "千年風土去不返，醉裏冤讎空展轉。"]'),
('8f40e6e5-2bdd-4807-94fd-6766690f9afe','題掃心圖','葉適','宋','宋诗','song-poetry','','[]','大心覺也無虧成，小心漚也隨滅生。',64,'全唐诗/poet.song.169000.json','["大心覺也無虧成，小心漚也隨滅生。", "道人常與箒柄行，遇其欻起須掃清。", "世間亦有無根樹，又言朗月當空住。", "劫塵顛倒不自由，只笑本來無掃處。"]'),
('d3724e71-a92b-4fd4-b286-4954f67f17dd','後端午行','葉適','宋','宋诗','song-poetry','','[]','一村一船遍一邦，處處旗脚爭飛揚。',64,'全唐诗/poet.song.169000.json','["一村一船遍一邦，處處旗脚爭飛揚。", "祈年賽願從其俗，禁斷無益反爲酷。", "喜公與民還舊觀，樓前一笑滄波遠。", "日昏停棹各自歸，黄瓜苦菜誇甘肥。"]'),
('889650ce-79bc-4724-9d52-87b1fe73dfc8','贈朱承務','葉適','宋','宋诗','song-poetry','','[]','顛倒八八卦，流轉三百六。',48,'全唐诗/poet.song.169000.json','["顛倒八八卦，流轉三百六。", "前民此何神，占險空屢瀆。", "以病既當止，以年自當休。", "春泥不補裂，莫謾任虛舟。"]'),
('51e762d7-4725-47bc-b3a4-104e607d414d','尼童何了詵從道一長老六年一忽捨去莫知所之或云在天目山也詵甚喜將薙落從之可少助乎','葉適','宋','宋诗','song-poetry','','[]','一師今何去，天目萬丈雲。',24,'全唐诗/poet.song.169000.json','["一師今何去，天目萬丈雲。", "著我粗袈裟，對住大茅君。"]'),
('8f9d3b4a-b64e-42e7-beaa-72382e093047','著存亭','葉適','宋','宋诗','song-poetry','','[]','馴烏得食常好鳴，靈茅無種還自生。',64,'全唐诗/poet.song.169000.json','["馴烏得食常好鳴，靈茅無種還自生。", "魂浮魄散莽何極，耿若有見悲難平。", "山脈迢迢繡峰住，墓氣騰騰縷雲去。", "鮫人抱寶夜出游，指點今來著亭處。"]'),
('10b222dd-bdbf-46b9-92e2-259ce01811c1','寄題運使方公祠堂','葉適','宋','宋诗','song-poetry','','[]','投村宿店破鞍韉，乞鹽放酒心拳拳。',128,'全唐诗/poet.song.169000.json','["投村宿店破鞍韉，乞鹽放酒心拳拳。", "南荒走遍得痟渴，玉井無藕何由痊。", "令子名高壓蘇武，蹔來重靚經行處。", "追思往事空泫然，榜墨尚新牆壁護。", "佛幢五丈留衣冠，大書刻記詞辛酸。", "神來正值荔枝熟，神去還愁桂子寒。", "吁嗟嶺民未知禮，因君始拜令顙泚。", "從今簫鼓祭春秋，福我如生首長稽。"]'),
('b94bc37a-9d0b-4815-90eb-45aaf8f2582d','鄱陽董季興往游懷玉山捐田入寺爲民禱雨君既道其本末又示山中五章請余賦之然比來霖潦淹月種爛乃未秧也方幸數日晴霽爾','葉適','宋','宋诗','song-poetry','','[]','懷玉湫龍懶心性，六月困眠祈未醒。',64,'全唐诗/poet.song.169000.json','["懷玉湫龍懶心性，六月困眠祈未醒。", "廣文偶來亦同病，買田施食慇懃請。", "誰知領縣春風邊，嗔蛟怒鰐腥熏天。", "須君一念晴雨若，遮莫雇僧輸俸錢。"]'),
('b5520c28-7be2-4118-91bb-ff47faa4a66c','改東門出二首  其一','葉適','宋','宋诗','song-poetry','','[]','百步鑿新徑，千年開舊池。',72,'全唐诗/poet.song.169000.json','["百步鑿新徑，千年開舊池。", "值此盈月雨，川流漭溟瀰。", "蕪深草色碧，雜卉華衆枝。", "魴潛警夜躍，鷺起衝晨飛。", "我老皮骨銷，扶行歎逶遲。", "安得有遠志，畢願藏郊扉。"]'),
('2d939d28-d8b2-42ae-82c5-d0dd67950e95','改東門出二首  其二','葉適','宋','宋诗','song-poetry','','[]','左方擁崇岡，昔也重嶙峋。',72,'全唐诗/poet.song.169000.json','["左方擁崇岡，昔也重嶙峋。", "自我護樵牧，林光稍敷紛。", "與菊明疎秋，墮桃照穠春。", "本求平野立，八荒辨燕秦。", "終限分寸珠，僧磬通比隣。", "面牆雖養蒙，意生豈名身。"]'),
('01f1fbf7-76c4-4e17-a82a-99eb7d57a1d9','中塘梅林天下之盛也聊伸鄙述啟好游者','葉適','宋','宋诗','song-poetry','','[]','幽花表窮臈，病叟行村墟。',228,'全唐诗/poet.song.169000.json','["幽花表窮臈，病叟行村墟。", "所欣一蕊吐，安得百萬株。", "上下三塘間，縈带十里餘。", "荒茨各尊貴，野徑爭扶疎。", "愁雲忽返旆，急霰仍回車。", "蒼然歲將晚，陡覺大象舒。", "羣帝胥命游，衆仙儼相趨。", "龍鸞變化異，笙笛音製殊。", "物有據其會，感召驚堪輿。", "妙看撤真境，態色疑虛無。", "問誰始種此，豈自開闢初。", "至今闕勝賞，浩劫隨榮枯。", "兒童候黄墮，捧拾紛筐盂。", "熏蒸雜煙煤，縛賣傾江湖。", "臙脂蘸羅縠，絳艷生裙襦。", "和羹事則已，甘老山中臞。", "以茲媚婦女，又可爲嗟吁。", "夜闌燭燼短，月淡意躊躇。", "林逋與何遜，賦詠徒區區。"]'),
('176f3e15-2535-4df9-95cd-b9ad5b4deae9','王氏讀書吟堂','葉適','宋','宋诗','song-poetry','','[]','誰能採桑談，誰能带經鋤。',96,'全唐诗/poet.song.169000.json','["誰能採桑談，誰能带經鋤。", "古人讀書地，妙理出窮閭。", "矧今治華室，山翠湧前除。", "風烟聚景趣，花竹成畫圖。", "主人烏紗帢，子弟繡羅襦。", "新裝繭紙印，上記開闢初。", "展卷忽有得，欣如奏齊竽。", "勉哉造其微，勿逐皮毛粗。"]'),
('27ba9549-9ac3-42f1-bc5f-7ed5051fa9a2','王簡卿侍郎以詩贈王孟同王成叟之姪也輒亦繼作','葉適','宋','宋诗','song-poetry','','[]','季父昔從我，寒燈聽微更。',132,'全唐诗/poet.song.169000.json','["季父昔從我，寒燈聽微更。", "强扶瘖聾和，誤策蹇跛行。", "坐令兩銷落，無復一崢嶸。", "宜汝逝不留，出門訪咸英。", "大溪逢侍郎，拆洗心胸清。", "新詩發妙意，說盡文字情。", "侍郎蓋代豪，平蠻蚤垂名。", "覽書五行下，援筆千人驚。", "點化謝琱刻，涵濡透晶熒。", "林黄橘柚重，渚白蒹葭輕。", "褰裳念數往，歲晏霜雪零。"]'),
('812f8334-21ca-4c41-bc2f-b43e193bce25','余頃爲中塘梅林詩他日來游復作','葉適','宋','宋诗','song-poetry','','[]','側聞中塘好，曾賦勸游篇。',216,'全唐诗/poet.song.169000.json','["側聞中塘好，曾賦勸游篇。", "凌江入枉浦，聊復信所傳。", "化工何作强，耿耿不自憐。", "山山高相映，塢塢曲相穿。", "林光百道合，花氣十村連。", "風迎亂駊騀，日送交嬋媛。", "天回徂陰後，地轉升陽前。", "初如別逃秦，疏附恥獨賢。", "又疑未興周，掩擁欣俱全。", "惜哉見之晚，重尋畏彫年。", "一省三嘆息，十步九折旋。", "詩家詫梅事，槁乾陋肥鮮。", "常於寒角曉，愛彼明冰懸。", "疎枝澀冷艷，小窗露孤妍。", "吟悲炙留嗛，句喜珠離淵。", "忽茲過衆甫，欲彀羞斷弦。", "無以寄美人，千室炊暮烟。", "明朝指行處，霧雨空迷田。"]'),
('17e26f39-8cca-444b-b379-3ef2b6c40f1f','送葛元城','葉適','宋','宋诗','song-poetry','','[]','數年之留能浩浩，一日之別還草草。',64,'全唐诗/poet.song.169000.json','["數年之留能浩浩，一日之別還草草。", "念子身名兩未遂，令我衰病無一好。", "古人探道從妙年，今人重耳輕目前。", "不愁好龍龍不下，只愁愛玉酬石價。"]'),
('9043c5a8-ca94-46ad-87c7-d5c177e660d8','送白酆還蜀','葉適','宋','宋诗','song-poetry','','[]','翻翻文若秋江生，幽幽詩如寒澗鳴。',64,'全唐诗/poet.song.169000.json','["翻翻文若秋江生，幽幽詩如寒澗鳴。", "前歲淹徊下巴峽，今年憔悴出京城。", "憑問天邊五色羽，何事飛來復飛去。", "昔人但苦樊籠悲，豈知此日籠無處。"]'),
('2bca669d-4fdd-4da2-9bf3-7d2dfa14468b','朱娘曲','葉適','宋','宋诗','song-poetry','','[]','憶昔剪茅長橋濱，朱娘酒店相爲鄰。',128,'全唐诗/poet.song.169000.json','["憶昔剪茅長橋濱，朱娘酒店相爲鄰。", "自言三世充拍戶，官拋萬斛嗟長貧。", "母年七十兒亦老，有孫更與當壚否。", "後街新買雙白泥，準擬設媒傳歸好。", "由來世事隨空花，成家不了翻破家。", "城中酒徒猶夜出，驚歎落月西南斜。", "橋水東流終到海，百年糟丘一朝改。", "無復歡歌撩汝翁，回首尚疑帘影在。"]'),
('691e196b-25dd-4e75-b3d6-bbab4947dc1c','翁誠之挽詞','葉適','宋','宋诗','song-poetry','','[]','西方之人美無度，眷此南邑朝陽鳴。',64,'全唐诗/poet.song.169000.json','["西方之人美無度，眷此南邑朝陽鳴。", "如錐出囊擬砭國，似璞有價空連城。", "三仕郎官老將及，一去郴州喚不譍。", "朔風吹潮沒復湧，渡口野梅飛碎瓊。"]'),
('97ec3961-3a1a-4adb-afc7-3416fddd474d','送曹器遠','葉適','宋','宋诗','song-poetry','','[]','曹子苦心懷百憂，古人遠矣思同流。',64,'全唐诗/poet.song.169000.json','["曹子苦心懷百憂，古人遠矣思同流。", "平生未得雄豪力，今日便肯卑微休。", "麻源洞裏瓊葉雨，南草市上蘆花秋。", "十年老語爲誰了，西望滄江空白頭。"]'),
('73c557b9-f636-4b8a-871b-e4dbb67b7a39','送丁子植','葉適','宋','宋诗','song-poetry','','[]','婉孌好少年，憶昨十五餘。',72,'全唐诗/poet.song.169000.json','["婉孌好少年，憶昨十五餘。", "割慈避父母，遜志親師儒。", "已上破荒第，猶勤未見書。", "平生烟雨外，秋浦荷菼初。", "屬官號高士，議政關慘舒。", "吟情且勿放，民隠諒少攄。"]'),
('de07deab-31c9-4c5f-a56a-708e1a30a2c6','送方書記兼簡府主','葉適','宋','宋诗','song-poetry','','[]','我昔防江之下流，獨許蔡子專軍謀。',96,'全唐诗/poet.song.169000.json','["我昔防江之下流，獨許蔡子專軍謀。", "未能奏效累絲髮，已復負謗叢山丘。", "小范兵精思慮遠，片言坐折群疑滿。", "幕僚無過只論功，登秩薦賢來衮衮。", "上流蜀接更吳通，桑麻滿里炊烟同。", "鸚鵡洲前長笛晚，黄哀蘄怨何時終。"]'),
('d45f136e-c40e-4bef-849f-e833f40df527','偉叔蔡兄來永嘉屢辱投贈於其歸也輒奉俚歌爲謝兼敘離索','葉適','宋','宋诗','song-poetry','','[]','慶曆故家忠惠後，性酷喜文疎嗜酒。',96,'全唐诗/poet.song.169000.json','["慶曆故家忠惠後，性酷喜文疎嗜酒。", "飄風聚雨蛙蚓寂，草玄獻頌龍蛇走。", "古人道大何不容，回空賜殖同升堂。", "若遇韓門親指畫，豈有不在籍湜行。", "水心可憐地如掌，讀罷君詩一惆悵。", "文星今直正莆中，去覓掀天無底浪。"]'),
('7db100d9-9ef8-4553-b491-33a2f54304c9','送戴料院','葉適','宋','宋诗','song-poetry','','[]','質如金石堅，文比錦繡新。',96,'全唐诗/poet.song.169000.json','["質如金石堅，文比錦繡新。", "利錐亦穎透，大樸終還淳。", "憶昨慨其離，早合儀朝紳。", "于今悄復去，奈何猶選人。", "西風管摇落，黄菊別有春。", "茫茫九衢內，白汗沾紅塵。", "誰拋連城富，却買徑寸珍。", "世路豈云極，念子行李頻。"]'),
('445cdbcd-dc9d-4e5e-b3e5-d02c89a69d52','幽賞','葉適','宋','宋诗','song-poetry','','[]','禪房裹花窠，靜與水石會。',36,'全唐诗/poet.song.169000.json','["禪房裹花窠，靜與水石會。", "春禽更語默，夏日遞明晦。", "紛然衆竅殊，趺坐凜無對。"]'),
('14ec7d26-30ba-4129-9e7e-2923f15cec04','梁父吟','葉適','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','依大麓之遺址兮，儲后土之神靈。',372,'全唐诗/poet.song.169000.json','["依大麓之遺址兮，儲后土之神靈。", "樂天地之休嘉兮，皇涓潔而薦誠。", "集后土之雍容兮，刺百聖之禮文。", "却大輅而御蒲秸兮，惟儉德之是崇。", "端一心而燔燎兮，卜仁義乎永年。", "刻玉檢而請命兮，何事秘而弗傳。", "嘉梁父之草木兮，被赫然之寵榮。", "咨梁父之遺老兮，悲忽不睹乎穆清。", "維千乘萬騎之雜沓婐婉兮，猶彷徨其行聲。", "夫天運之適合兮，雖聖其猶莫知。", "彼河之洋洋兮，雖美而不濟。", "泰山之椒既風雨又艱險兮，乃登封以類告。", "豈其不可一兮，伊所遇之獨異也。", "雖伊周之輔世兮，曾何足以自喜。", "喟余生之孔棘兮，邈不及夫七十二君。", "日月幽而不明兮，遭玄夜之方長。", "競鈇鉞而日弊兮，逐亡鹿而裂其脾肩。", "漢氏之爲的兮，而不遺其餘民。", "余既朴陋而不能謀兮，又怯耎而畏兵。", "搢珽琄於盜賊兮，何不朽之可幾。", "曾死亡之幾何兮，苟亂世以自免。", "幸此土之平樂兮，依鎮南之不遠。", "余耕兮隆中，地沃衍兮宜稑種。", "相原隰而下上兮，町厥壤之百畝。"]'),
('18d4518b-2f28-4b26-a393-9d4e867cbb7b','剡谿舟中','葉適','宋','宋诗','song-poetry','','[]','浙江大浪如履空，鏡湖挾天雨復風。',192,'全唐诗/poet.song.169000.json','["浙江大浪如履空，鏡湖挾天雨復風。", "我行獨到勾踐國，寒溪一溜蜿蜓通。", "蟄龍已卧潭谷底，濕螢不照蒲葦叢。", "山林卑陋無栝柏，霸氣埋沒惟蒿蓬。", "是時初冬未凝沍，天地蒼莽日常暮。", "涉江芙蓉不復採，緣道野菊誰能顧。", "饑烏遠鴈長追隨，夜聞悲鳴朝見飛。", "前村鷄犬護籬落，此復何苦號其栖。", "自傷憔悴少筋骨，半生逆旅長太息。", "王家少年未省事，扁舟往來何所自。", "百年有意存禮樂，一飽未足謀通塞。", "且能對酒長酣歌，聖賢有命可若何。"]'),
('d90a7a14-550c-4ef0-8dd7-9de28a242872','新移瑞香舊曾作文忘之因今追憶云','葉適','宋','宋诗','song-poetry','','[]','一株當三春，名花不易得。',132,'全唐诗/poet.song.169000.json','["一株當三春，名花不易得。", "百年等尋丈，不博千乘國。", "野人三十本，强賣青銅百。", "應憐跗蘤具，苦爲薪米迫。", "移栽向明陽，妃媛儼行列。", "土膏合根性，功用成宿昔。", "除香出淺紫，泣露輕脈脈。", "含愁欲誰訴，折去情更惜。", "方求蔽芾陰，未受搔擢厄。", "嗟余自羈旅，何以慰新客。", "慇勤深夜來，少待山月白。"]'),
('133b6fd8-87fa-4573-866e-71c50f93014d','送薛子長','葉適','宋','宋诗','song-poetry','','[]','藏冰待炎威，織裘禦冬霰。',120,'全唐诗/poet.song.169000.json','["藏冰待炎威，織裘禦冬霰。", "彼此互有適，用舍空屢變。", "蘭菊倚戶出，松柏參天見。", "美質不必同，偉幹非世便。", "薛生靜而敏，器宇絕幼愿。", "能文乃天姿，脫穎酬始願。", "衆技逐高卑，雜學徒貫穿。", "趨聖由一途，任重工自勸。", "古人文已立，後世皎難衒。", "媿余莫負荷，期子幸無倦。"]'),
('90b5a611-5c2d-4c8e-a726-05ed7e6f1964','送陳彥羣','葉適','宋','宋诗','song-poetry','','[]','雨洗蝗蝻餘，凉生癘瘧後。',144,'全唐诗/poet.song.169000.json','["雨洗蝗蝻餘，凉生癘瘧後。", "今朝江上峰，浄失棼霧垢。", "舉觴忻有屬，餞我同年友。", "平居多契闊，遠別方嗟咎。", "大郡得師儒，高文興孝秀。", "雍容入儒雅，磨錯見瓊玖。", "衆儒治六學，厥志存不朽。", "量空計尋丈，汲海論升斗。", "因之入簪組，併欲垂篆籀。", "公才賦超卓，傑立氣愈厚。", "火宿無餘煙，果實甘衆口。", "書來幸細評，副此頻矯首。"]'),
('ed1d8ad9-11ee-44c5-a2d4-c4de29428fac','題人扇','葉適','宋','宋诗','song-poetry','','[]','外德欲晦，面目自蔽。',40,'全唐诗/poet.song.169000.json','["外德欲晦，面目自蔽。", "內德欲耀，肝膽畢照。", "二法相除，我則有餘。", "穆如清風，用之不窮。"]'),
('2e09d196-b5a1-4d89-bda6-eed86da7e694','與英上人游紫霄觀戲述短歌','葉適','宋','宋诗','song-poetry','','[]','野水隨路曲，東風得木鳴。',180,'全唐诗/poet.song.169000.json','["野水隨路曲，東風得木鳴。", "景物已和柔，川原倍敷榮。", "茂桑高既條，細草亦叢生。", "眷言雲外士，及此塵中行。", "南臨大陂出，波面與心平。", "道旁古精廬，黄茅間荆榛。", "會集傾遠村，裳衣自鮮明。", "銀釵插山丹，歌笑喧嚶嚀。", "何以勞比鄰，粔籹雜餦餳。", "去年谷不飽，白骨今縱橫。", "等爲造化役，未究悲忻情。", "歸來日已夕，舊徑成溝坑。", "大車者誰子，不寐方宵行。", "死魂未滿眉，擿埴將安程。", "感此良自哂，抱谷非鸝鶊。"]'),
('40decf80-f42d-4fd5-8300-1cd07172fa41','白紵詞','葉適','宋','宋诗','song-poetry','','[]','有美一人兮表獨處，陟彼南山兮伐寒紵。',66,'全唐诗/poet.song.169000.json','["有美一人兮表獨處，陟彼南山兮伐寒紵。", "挑燈細緝抽苦心，冰花織成雪爲縷。", "不憂絕技無人學，只愁不堪嫁時著。", "鄭僑吳札今悠悠，爭看買笑錦纏頭。"]'),
('0ad8aa78-ad00-411f-8536-605bce26c1d2','王木叔祕監挽詞','葉適','宋','宋诗','song-poetry','','[]','美人昔來芙蓉傍，山爲發靈水吐芒。',64,'全唐诗/poet.song.169000.json','["美人昔來芙蓉傍，山爲發靈水吐芒。", "美人今歸在何處，簫哀鼓悲葬前岡。", "我欲從之似雲出，友風子雨游四方。", "夢魂無憑不可挽，坐攬衰涕終摧藏。"]'),
('e34fea89-1fad-422e-ba56-f59d59a7d8a1','月波樓','葉適','宋','宋诗','song-poetry','','[]','下林百果春自花，屋藏汀陰泉著沙。',128,'全唐诗/poet.song.169000.json','["下林百果春自花，屋藏汀陰泉著沙。", "光風膩雪誰汝惜，繁紅蜜翠空欹斜。", "愛君樓高出江上，百里江山開四向。", "峻屏森聳遠更寒，紋練縈回靜猶浪。", "孤潮夜卷西頭來，海門推出冰崔嵬。", "豈知星河遭映奪，只使鸛雀常驚猜。", "此村風俗淳且魯，接樹移花今復古。", "勸君種學化兒孫，不須貯妓呈歌舞。"]'),
('843e16bf-a77c-4bbb-976b-87dd0f0956d6','送陳子雲通判  其一','葉適','宋','宋诗','song-poetry','','[]','周子也復可憐人，憂民憂世語轉新。',32,'全唐诗/poet.song.169000.json','["周子也復可憐人，憂民憂世語轉新。", "每妬吾州何巨福，通判乃得陳子雲。"]'),
('10746fa9-42b6-489f-a720-fd8a3bd7511b','送陳子雲通判  其二','葉適','宋','宋诗','song-poetry','','[]','臨餐吐食嗟無餘，幽情慘鬰時一舒。',32,'全唐诗/poet.song.169000.json','["臨餐吐食嗟無餘，幽情慘鬰時一舒。", "感君善意過於令，周子之語良非虛。"]'),
('5f899c47-c8cc-4481-80af-c0e3173a9537','送陳子雲通判  其三','葉適','宋','宋诗','song-poetry','','[]','三月召龍頻鼓鑼，喜作小雨恨不多。',32,'全唐诗/poet.song.169000.json','["三月召龍頻鼓鑼，喜作小雨恨不多。", "移苗未了君已去，更借後福書歸禾。"]'),
('eb2eeaca-f3cd-41b9-99df-5ff3f2ce0d26','賦董季興玩書巖','葉適','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','玩書巖裏刻成真，水簾花鬘春復春。',64,'全唐诗/poet.song.169000.json','["玩書巖裏刻成真，水簾花鬘春復春。", "一朝斂策去何所，來者對之如古人。", "美哉骨清神亦爽，西瞻匡廬東雁蕩。", "滿車圖畫常載行，到處名山留塑像。"]'),
('72bfdae9-2b19-4310-ba16-e59be4d7f539','送林孔英','葉適','宋','宋诗','song-poetry','','[]','東堂質疑匙啟鑰，西廂坐講水赴壑。',64,'全唐诗/poet.song.169000.json','["東堂質疑匙啟鑰，西廂坐講水赴壑。", "本朝合選經博士，萬里那投郡文學。", "東風吹散石門冰，吳人送去蜀人迎。", "雪山峩峩大江滿，柁樓過之清又清。"]'),
('2ac1621c-50ce-4073-983d-c642dc47b8b2','贈巖電隠士','葉適','宋','宋诗','song-poetry','','[]','近時術人多莽蕩，要把虛名隨妄想。',64,'全唐诗/poet.song.169000.json','["近時術人多莽蕩，要把虛名隨妄想。", "神王雖去形不拘，尺直須防尋有枉。", "從來鐘鼎無山林，老去豈復少年心。", "若言部位許虧闕，已早騰踏非埋沉。"]'),
('13358b05-8c9c-49a5-91ad-253464b84b67','送謝學賓','葉適','宋','宋诗','song-poetry','','[]','衰年嬾看客，十卧適一起。',104,'全唐诗/poet.song.169000.json','["衰年嬾看客，十卧適一起。", "謝子何許來，我屐屢折齒。", "貌閑神又肅，論事靜而理。", "紛然嘲哳際，莞爾諧宮徵。", "麟獲無怒角，鳳去愁遯尾。", "正應晚聞道，不受血氣使。", "山頭蕨芽老未鎌，庭中桂枝春已添。", "巢由亦有藏身地，小厭聲名傍屋簷。"]'),
('531bcf07-0d75-49ce-8128-4401117fef80','何倫秀才親喪不能舉冀其親戚故人有知之者','葉適','宋','宋诗','song-poetry','','[]','兩母久未葬，魂冷常夜嘶。',48,'全唐诗/poet.song.169000.json','["兩母久未葬，魂冷常夜嘶。", "病婦槌心號，血盡身爲泥。", "我死不息惜，少忍賦有甓。", "何當深九仞，更與崇四尺。"]'),
('07038d85-0d76-4e4d-9f47-01d9529d9ce5','蜂兒榧歌','葉適','宋','宋诗','song-poetry','','[]','平林常榧啖俚蠻，玉山之産升金盤。',128,'全唐诗/poet.song.169000.json','["平林常榧啖俚蠻，玉山之産升金盤。", "其中一樹斷崖立，石乳蔭根多歲寒。", "形嫌蜂兒尚粗率，味嫌蜂兒少標律。", "昔人取急欲高比，今我細論翻下匹。", "世間異物難並兼，百年不許贏栽添。", "餘甘何爲滿地澀，荔子正復漫天甜。", "浮雲變化嗟俯仰，靈芝醴泉成獨往。", "後來空向玉山求，坐對蜂兒還想象。"]'),
('6c174a62-8c40-4511-bdcb-0ffcd839e801','趙子容任溫州司法終日看冊子而事自理又新廩儲糧功利可傳也爲賦讀書行率諸友同作','葉適','宋','宋诗','song-poetry','','[]','法曹冗散人不管，聞道自要紛華損。',64,'全唐诗/poet.song.169000.json','["法曹冗散人不管，聞道自要紛華損。", "常平築敖米山積，讀書豈知米塵滿。", "歸來依舊茅蓋亭，焉得捨學干時卿。", "不然天上讀書去，蓬島瀛洲無限清。"]'),
('6dfa3687-0361-4176-a318-13107f72f336','登北務後江亭贈郭希呂','葉適','宋','宋诗','song-poetry','','[]','壁上陋室銘，門外剪茅亭。',108,'全唐诗/poet.song.169000.json','["壁上陋室銘，門外剪茅亭。", "小市魚蝦散寂寂，大江風浪來冥冥。", "郭翁雖老猶貌澤，腹貯今古心和平。", "只應獨將笏拄頰，清坐都不掛毫髮。", "何必隨逐欄頭奴，日招稅錢三萬億。", "前靈運，後延年，桑麻舊國常宛然。", "城頹路闕總令好，不知於人安穩否。"]'),
('5d3410d4-bb94-486f-bff7-95799268695e','送程傳叟','葉適','宋','宋诗','song-poetry','','[]','茂苑臺高春日明，君顔如花楊柳青。',96,'全唐诗/poet.song.169000.json','["茂苑臺高春日明，君顔如花楊柳青。", "蕭條別離風雨外，楊柳自青君貌改。", "誰知仰天愬天公，三辰五星在心中。", "老作海頭新主簿，蜃氣錯雜迷西東。", "去年無禾雖種菽，乞命只指今年熟。", "家人未可便喜歡，少待上司催結局。"]'),
('566e5b49-820c-4fbb-af21-dacbc56a84c0','送徐景大','葉適','宋','宋诗','song-poetry','','[]','桃湖避秦之遠孫，繞湖桃葉遮桃根。',96,'全唐诗/poet.song.169000.json','["桃湖避秦之遠孫，繞湖桃葉遮桃根。", "父子聲名動場屋，綠衫手板桃花村。", "相隨入南訪靈迹，九日山重海深碧。", "韓公文高大冊印，秦系詩清小磚刻。", "我已衰殘書不成，有語安能爲重輕。", "子今自出瓊瑰句，南伯南侯倒屐迎。"]'),
('0ab01ffc-490b-4a11-84ff-7b8456b1d45a','題五畏齋','葉適','宋','宋诗','song-poetry','','[]','曹滕亦據南面權，坐衙吏貼羣趨先。',131,'全唐诗/poet.song.169000.json','["曹滕亦據南面權，坐衙吏貼羣趨先。", "敢云威福自我出，下有赤子高蒼天。", "聖人迭興建皇極，付祝長官尤惻惻。", "前碑特立示銘誠，後榜七條垂訓釋。", "冰清王令來調琴，四事未畏先畏心。", "常將方寸勤管攝，不與外物相虧侵。", "情防驕粗意防滿，萬事須還畏爲本。", "君不見匹夫膽大氣如山，風浪只在須臾間。"]'),
('135a165c-1ca8-4665-b92f-ae76d2ca6d2e','懷遠堂','葉適','宋','宋诗','song-poetry','','[]','祖后昔尊御，忠邪初混茫。',288,'全唐诗/poet.song.169000.json','["祖后昔尊御，忠邪初混茫。", "詖行揚于庭，直詞招自旁。", "盡鉏新法穢，還拯疲民康。", "白頭失路者，冠服煇以煌。", "尤工抑外家，減官卑輪箱。", "纍然兩孤姪，賦祿上團防。", "賜書課熟讀，斂衽常敬莊。", "盤筵化蒲莧，歌舞諱姬姜。", "堂開瞰遠野，惟見條山蒼。", "不知天何意，反掌異存亡。", "何人致顛覆，使我同披猖。", "胡雲半點黑，汴水千里黄。", "飄蕭離宮殿，零落趁傖荒。", "三吳通葦岸，中禁隔龍光。", "曾孫更寂寞，泥裏弄耕桑。", "風掀炊饁竈，雨爛曬禾場。", "稍復卓墟墅，漸能滿囷倉。", "舊居重回首，欲詣川無梁。", "哀哉血腥涴，狐兔久埋藏。", "想其屢易主，指說故侯王。", "時運從代謝，形神終慘傷。", "翁今垂八十，健悍嗔扶將。", "句中青玉案，壁上烏絲行。", "細抄四簷動，繞看三伏凉。"]'),
('6b3e2702-2fd0-4664-82e7-862338bef1de','報德庵','葉適','宋','宋诗','song-poetry','','[]','王孫生長安仁宅，親見宣仁靖家國。',64,'全唐诗/poet.song.169000.json','["王孫生長安仁宅，親見宣仁靖家國。", "艱難身後苕水頭，舉目湖山非舊識。", "孩兒負土成新阡，手種拱把皆參天。", "皇天報德無窮年，蟠根翳葉藏雲煙。"]'),
('30d02dbf-1a8f-475e-aba6-4b0cebbb2366','露星亭','葉適','宋','宋诗','song-poetry','','[]','斗杓點翠爲此城，四郊環拱來遥青。',64,'全唐诗/poet.song.169000.json','["斗杓點翠爲此城，四郊環拱來遥青。", "知君欲覽衆山小，取磚磨就天上亭。", "身心合於高處著，萬象不語森湊泊。", "古今月色遞淺深，志士可惜虛光陰。"]'),
('559fbe83-d625-41b8-9480-8a462a4f090f','送高仲發','葉適','宋','宋诗','song-poetry','','[]','細君吁久寂，季弟猶長貧。',48,'全唐诗/poet.song.169000.json','["細君吁久寂，季弟猶長貧。", "棄我涉遠道，策策傷心神。", "舍西三畝畬，作急老自耘。", "稻熟曾未割，歸趁秋風新。"]'),
('ec8c65df-566c-41ae-98f5-68ce50ba00a2','明覺寺','葉適','宋','宋诗','song-poetry','','[]','雲山尖頭海潮湧，九月天雪山葉重。',66,'全唐诗/poet.song.169000.json','["雲山尖頭海潮湧，九月天雪山葉重。", "道人高絕但危坐，山魈野虎皆趨拱。", "住山三載兩遭荒，侍者餓損扶參堂。", "沿村索米未爲恥，莫令木魚化龍鍾透水。"]'),
('70a9868c-e64d-4184-8741-d2f5106763a8','送蔣少韓','葉適','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','昔子岳陽去，我病不能吟。',104,'全唐诗/poet.song.169000.json','["昔子岳陽去，我病不能吟。", "久拋風煙句，永結江湖心。", "子今岳陽歸，惠我過始覿。", "日月無蔽虧，空水互摧激。", "濯足洞庭浦，晞髮君山顛。", "誰驚瘦到骨，所要清爲天。", "蔀家豐屋永新縣，象牀金簟春風轉。", "提壺未許勸人留，求言待上茅茨殿。"]'),
('12826487-412c-465b-93d1-52f3afb89b9d','寄題鍾秀才詠歸堂','葉適','宋','宋诗','song-poetry','','[]','鍾君文武隨所求，馬上檄草兼詞頭。',128,'全唐诗/poet.song.169000.json','["鍾君文武隨所求，馬上檄草兼詞頭。", "五兵鑄就殺氣動，却寫三賦祥光流。", "左踰陰山右絕漠，漢地自厭胡沙惡。", "聖門歷歷宮牆深，風乎不知詠歸樂。", "作常雖窄海浪寬，沂水何止八九吞。", "當年曾點見真趣，推琴難挽由求論。", "課兒讀易夜參五，香燼銷沉燈莽鹵。", "東家夢熟幾時知，還有漁人歎良苦。"]'),
('99a50cbe-2b97-4ceb-866b-c4a6cc52a6df','鹿鳴宴詩','葉適','宋','宋诗','song-poetry','','[]','鹿鳴著周雅，取士各惟時。',120,'全唐诗/poet.song.169000.json','["鹿鳴著周雅，取士各惟時。", "永嘉近千載，文物盛於斯。", "賢侯奉明指，薦棘鎖秋扉。", "希寶難聚識，獨鑒防群嗤。", "誠云得之慰，重爲失者悲。", "鄙夫素寡學，已老謾將知。", "仰欣多材聚，俯愧隻影踦。", "晴霜萬里肅，威鳳正高飛。", "朝陽羽翽翽，春梧綠蕤蕤。", "新榮忌輕覓，苦節誓終期。"]'),
('0b901e34-000b-4f17-b7a0-bc30b3871dbd','潘廣度','葉適','宋','宋诗','song-poetry','','[]','秦聲鳴嗚何處村，楚些行欹愁斷魂。',64,'全唐诗/poet.song.169000.json','["秦聲鳴嗚何處村，楚些行欹愁斷魂。", "光風自汎靈草碧，朗月豈受頑雲吞。", "坐具平鋪佛叉手，空劫以前人總有。", "一文全捨絕乘除，得福便過崑崙渠。"]'),
('82be22f1-516f-4490-96d0-d055d62d722d','送楊通判','葉適','宋','宋诗','song-poetry','','[]','花稀讓林稠，苗疎與田遠。',96,'全唐诗/poet.song.169000.json','["花稀讓林稠，苗疎與田遠。", "共欣永日寬，更笑餘寒褊。", "窮閻多樂事，粲粲翠幄展。", "惜君盍少假，忽泛江流緬。", "三年綱紀地，一意圭玉琬。", "臞儒道義深，傲吏威稜淺。", "山鞋蠟已就，畫筆枯未吮。", "不上鴈蕩峰，何由寄高蹇。"]'),
('d08db96c-4c8f-4761-b899-7bac869f8845','哀鞏仲至','葉適','宋','宋诗','song-poetry','','[]','老衰哭無淚，行歎復坐嗟。',252,'全唐诗/poet.song.169000.json','["老衰哭無淚，行歎復坐嗟。", "荒凉鶴嗚村，尚友初萌芽。", "當時各年少，涉世迷驪騧。", "中天懸明月，爭欲伸手拏。", "朝語日再昃，夜談更五檛。", "君文蚤貴重，蜀錦載胡車。", "離離三千首，雅正排淫哇。", "石碑富規製，玉策垂芬葩。", "簡牘尤妙美，一字不可加。", "笑我自山野，悲君混泥沙。", "古稱騷人窮，留與後代誇。", "昨誰寄音信，已受南臺衙。", "俄然被彈射，翻燎北塢畬。", "季也守大玉，千里畦稻麻。", "請登小芙蓉，萬仞凌煙霞。", "茲遊隠者事，亦乃期屢差。", "書來病良慰，誓言指春華。", "秉我烏臼燭，瀹以蔣富茶。", "那知是絕筆，楊柳空白花。", "頗疑魂氣升，彷彿天之涯。", "多生註周易，遥認草玄家。"]'),
('6d84e9d7-4dc4-43fc-80bc-ef46b8793d44','送王通判','葉適','宋','宋诗','song-poetry','','[]','左原冢孫産巴東，山靈地秀兼長雄。',64,'全唐诗/poet.song.169000.json','["左原冢孫産巴東，山靈地秀兼長雄。", "自小赤心天與通，可惜五十方治中。", "北風吹沙暗中渡，不合吹君落南去。", "水有子魚山荔枝，借我箸食前籌之。"]'),
('a1d37598-8871-4551-8c83-e9b061d67024','贈林秀才','葉適','宋','宋诗','song-poetry','','[]','乃翁掩親醵州里，自云先世曾如此。',64,'全唐诗/poet.song.169000.json','["乃翁掩親醵州里，自云先世曾如此。", "汝今謀葬無置錐，况有滿族喪纍纍。", "春風未回萬山赤，秋霜忽至凋寸碧。", "鴟鳶利觜魄凜然，聞者應垂最後憐。"]'),
('2dc05815-54f1-469a-8f04-b0ae738bcee5','送徐洞清秀才入道','葉適','宋','宋诗','song-poetry','','[]','方老昔爲儒，仁義自愁煎。',120,'全唐诗/poet.song.169000.json','["方老昔爲儒，仁義自愁煎。", "决策從道士，擺落科場緣。", "神仙事茫昧，良得日高眠。", "徐生嗣其風，永謝負郭田。", "白襴已回施，黄氅猶索錢。", "書籍棄塵案，笙磬來鈞天。", "看鏡胡獨難，超俗諒非少。", "異花改林秀，孤翮移漢矯。", "月華滿庭蕪，闃沉霜宇峭。", "親交生離絕，空歎真游杳。"]'),
('7ce16fab-4b3b-4ae4-9c27-be14c3347694','自羅浮行田宿華嚴寺','葉適','宋','宋诗','song-poetry','','[]','浮山昔飛至，與羅合其巔。',132,'全唐诗/poet.song.169000.json','["浮山昔飛至，與羅合其巔。", "嚴冬樹色改，青松耀紅鵑。", "不種自生植，屢伐常蒼然。", "我病不暇耕，行復觀我田。", "呼扶偃蹇後，倩護龍鍾先。", "僮客四面集，畦畽相勾連。", "敢云歲晏休，翻犁趁晴暄。", "民政今古殊，憂樂豈異源。", "收身卧荒剎，朗月前夜圓。", "鵲懶附枝靜，鼯饑嗅床穿。", "爲農悔不早，時發棹歌旋。"]'),
('dcaf7038-3c76-4c31-83d5-5c776ffa6cd5','送鞏仲同','葉適','宋','宋诗','song-poetry','','[]','花溪初逢日苦短，橘洲重尋意更長。',64,'全唐诗/poet.song.169000.json','["花溪初逢日苦短，橘洲重尋意更長。", "天催鶺鴒玉樓去，潄流不並龍洲旁。", "春風忽高行旆起，酒盡何如添野水。", "古來交契看老時，與公安得輕別離。"]'),
('c3dfec66-adbf-414a-b322-c8c3fb80c59a','送林退思四川分司茶馬幹官','葉適','宋','宋诗','song-poetry','','[]','棄繻詆關吏，廣殿射高名。',120,'全唐诗/poet.song.169000.json','["棄繻詆關吏，廣殿射高名。", "方從媚子引，豈料讒夫傾。", "京師恩暮降，蜀道險朝升。", "執手郭西門，惻愴難爲情。", "有山擎空雪，有谷匝底冰。", "烏樂謾後噪，猿孤定先鳴。", "漢中王霸地，從古鋒鏑爭。", "崩摧韓信壇，闕落張魯營。", "感子奮衣去，客猛意自輕。", "笑我老何怯，萬里今橫行。"]'),
('81b9af4c-2c80-4334-b789-647ca34da031','送周明叔王成叟併上昌甫仲止二兄','葉適','宋','宋诗','song-poetry','','[]','成叟自成身，明叔志明時。',120,'全唐诗/poet.song.169000.json','["成叟自成身，明叔志明時。", "二士湗村下，飲醇棄糟醨。", "湗村去綿邈，二士天所遺。", "琢琱而佩環，染夏爲裳衣。", "高岡無長松，結根空兔絲。", "渚行枉又直，帆掛昂復低。", "飯彼章泉菽，羹以南澗葵。", "沐浴明月珠，簸弄芙蓉旂。", "兩邦意氣合，一唯萬論微。", "羌余抱茲獨，安得往從之。"]'),
('896d8d31-2325-4649-9c94-d33da6ede842','陳伯明建讀書堂於仙都巖蓋縉雲最勝特處市書名田役大費巨當用衆力一家不能專也余爲作仙都行以堅其成','葉適','宋','宋诗','song-poetry','','[]','東萊龍川師道起，一時話言猶在耳。',131,'全唐诗/poet.song.169000.json','["東萊龍川師道起，一時話言猶在耳。", "我輩勤苦常刳心，後生懶惰自迷己。", "聞君相取黄帝鄉，石簡中間穩上梁。", "搜翹索楚尋舊學，關雎師摯聲洋洋。", "書惟見多參互解，食要良田宜廣買。", "俚翁有語人未知，醤裏投鹽事終在。", "君不見衡廬嶽麓天與靈，達士必垂千載名。", "山高海深産奇物，他年古文屋壁出。"]'),
('e7279c51-5218-4a84-b188-9902eea435e8','送龔叔虎','葉適','宋','宋诗','song-poetry','','[]','寺暗莓苔深，歲潦雷雹粗。',120,'全唐诗/poet.song.169000.json','["寺暗莓苔深，歲潦雷雹粗。", "問胡旅窮舍，鑽燧煮萊蕪。", "答云自孩童，蚤識竈下梧。", "逡巡四十載，翻著火上爐。", "今昔豈異能，聞見終殊途。", "德衰嗟教薄，筆退憐詞枯。", "何以充我求，往衆歸裝孤。", "子文如繡鞶，子行如冰壺。", "世惟春華翫，爾用秋實餔。", "去從孔鸞翔，勿受斥鷃呼。"]'),
('adc30d11-8b23-49aa-8437-ebc36508aaf4','贈趙季清縣丞','葉適','宋','宋诗','song-poetry','','[]','多生有奇姿，名已在仙籍。',48,'全唐诗/poet.song.169000.json','["多生有奇姿，名已在仙籍。", "朝遊風后館，暮返旌陽宅。", "五月凉如秋，照夜干將白。", "養之鋒鋩餘，參魯柴亦愚。"]'),
('2b193351-9bc9-4104-aa8b-b187500a6e3a','趙成父築亭上饒即用東里舊圃榜曰魚計','葉適','宋','宋诗','song-poetry','','[]','秦僑洛寓隨南公，新條復欲無開封。',64,'全唐诗/poet.song.169000.json','["秦僑洛寓隨南公，新條復欲無開封。", "亭名若有土斷法，鄭圃豈在章泉中。", "舊魚遥應化龍去，今魚且復波間住。", "人爲魚計魚未知，今樂莫忘昔日悲。"]'),
('6abe9a63-4ad2-4bf2-b54b-f29c423fd72d','孔復君架樓貯書疏池累石花藥環列','葉適','宋','宋诗','song-poetry','','[]','老夫一編未得妙，頗以書多爲世笑。',96,'全唐诗/poet.song.169000.json','["老夫一編未得妙，頗以書多爲世笑。", "舊友從余不復疑，樓藏萬卷猶嫌少。", "書中之理甚周徧，可惜有眼何時見。", "管葛褊陋空礙塞，周孔深微常運轉。", "樓東兼水更兼山，四時紅翠交飛翻。", "付與兒孫好門戶，光芒應射斗牛間。"]'),
('2226ce29-e565-49ab-9a2e-9e095605f825','送蔡子重','葉適','宋','宋诗','song-poetry','','[]','憐子昔參江上僚，前功如日鬢蕭蕭。',64,'全唐诗/poet.song.169000.json','["憐子昔參江上僚，前功如日鬢蕭蕭。", "莫輕小縣深谷裏，續絲運軫琴方調。", "薄冰未隨野梅結，和風已催山杏發。", "廋文露巧衆術同，一心之純天與通。"]'),
('d088d044-0240-4824-aa99-3350964c6a16','許敬之用余言作松山草堂然游山之意猶未已也申以爲箴','葉適','宋','宋诗','song-poetry','','[]','許子家住松山邊，門開路闢登山巔。',96,'全唐诗/poet.song.169000.json','["許子家住松山邊，門開路闢登山巔。", "千年茂樹不改葉，百尺甘井常流泉。", "堂中悄然人境絕，時有剝啄延臞仙。", "天下之山皆若此，捨而外求徒喪己。", "卑能藴高而爲謙，高能生明是爲賁。", "芒鞋價長今安之，撰屨欠伸吾老矣。"]'),
('e5ea9e1e-1324-4cb0-aa0e-510179c1ed9b','送蔡子壽','葉適','宋','宋诗','song-poetry','','[]','彼羙蔡氏子，任也堪將相。',96,'全唐诗/poet.song.169000.json','["彼羙蔡氏子，任也堪將相。", "唯儔亦異材，朗立萬人上。", "吾嘗扣其微，事詣理亦暢。", "雨露待堅成，風波豈凋喪。", "醯鷄發淺覆，鹽虎背新樣。", "侵尋墮老醜，闟茸屢監當。", "繁霜生野色，行李正悽愴。", "恐子復未平，因書寄無恙。"]'),
('6605e7e7-36bd-40f6-9471-ad5060a52253','寄柳祕校','葉適','宋','宋诗','song-poetry','','[]','頗聾早謝葛亮辟，少吃善著楊雄書。',64,'全唐诗/poet.song.169000.json','["頗聾早謝葛亮辟，少吃善著楊雄書。", "籬風索索苦瓠晚，山雨重重甘菊疎。", "今人相輕多匿笑，古人自許堪同調。", "咀芹嚼藻泮有宮，先生手提終化龍。"]'),
('65f12086-5914-43a5-bf76-a3ee53069b6b','魏華甫鶴山書院','葉適','宋','宋诗','song-poetry','','[]','蒼崖有頂我爲廬，日君月妃崖下趨。',272,'全唐诗/poet.song.169000.json','["蒼崖有頂我爲廬，日君月妃崖下趨。", "梳風洗雨耳目醒，玉帝詔許瞻宸居。", "周公仲尼在左右，勘點六籍開凡愚。", "曾經秦禍多散闕，鄭箋毛傳悲紛如。", "精神感通若親授，損益殷夏還其初。", "憶君低回校天祿，高論自遣陳言鋤。", "况今卓絕離人境，妙悟豈可常情拘。", "飄零每疑夢魂到，戃慌忽墮西南書。", "韓呂之相以類聚，程張之師以道俱。", "業調甘酸嗜秦炙，肯逐象罔迷玄珠。", "分明憤發貫篇首，端的鏤寫傳吾徒。", "乃知山中新所得，慢簡閑編皆棄餘。", "脩林遠嶺秋映蔽，濃花近院春扶疎。", "彫胡已饋豆籩靜，黄獨未斸筐籃孤。", "垂竿桐江笑短弱，負鼎莘野嫌豪粗。", "岷峨崔嵬留後拒，灧澦突兀催前驅。", "莫嗔猿鶴不解事，與民由之誠丈夫。"]'),
('e197bf5c-50c1-4a16-a5a0-4dd4f5fb8607','寄李季章參政','葉適','宋','宋诗','song-poetry','','[]','衮衮入蜀者，借公兄弟名。',120,'全唐诗/poet.song.169000.json','["衮衮入蜀者，借公兄弟名。", "每求歸載滿，預屏去橐傾。", "鷃飛雖地控，龍卧常天升。", "借哉坐時運，久鬰時士情。", "文章何崛奇，冬雷夏增冰。", "德業又宏濟，雉登應牛鳴。", "已著鼎飪利，不共水火爭。", "我窮未得死，破釜斗粟營。", "誤蒙兼金重，自視一羽輕。", "唯當刮老眼，雲雨看施行。"]'),
('e99b895b-1a77-485a-bbcd-5b5b7080e205','送陳壽老','葉適','宋','宋诗','song-poetry','','[]','天台鴈蕩車接軫，青田又促半潮近。',160,'全唐诗/poet.song.169000.json','["天台鴈蕩車接軫，青田又促半潮近。", "冠巖带壑無俗情，秋幹春荑競時盡。", "老窮望絕華軒過，其誰幽尋穿薜蘿。", "更抽奇筆向雲射，破的疊中千鴐鵝。", "古今文人不多出，元祐惟四建安七。", "性與天道亦得聞，伊洛尋源未爲失。", "閬風招手游太玄，麻頭制尾中興年。", "黄金鑄印肯輕佩，定把堯舜陳王前。", "我家罄懸仰見斗，簸君紅旗魑魅走。", "密房焰短夜苦長，雪高冰深去無鄉。"]'),
('0775a06a-7241-4c3d-97ba-ac3986d9a176','題鄭大惠詩卷','葉適','宋','宋诗','song-poetry','','[]','憶從草廬赴鄰炊，澀雪攪筵糟涌糜。',96,'全唐诗/poet.song.169000.json','["憶從草廬赴鄰炊，澀雪攪筵糟涌糜。", "要當醺酣活膚腠，不許雕刻妨肝脾。", "何年兒孫錦䙀裂，金塗門扉玉爲切。", "吟中得眼萬象通，浪吹狂歌總休歇。", "兩家至今住連牆，讀書聞鷄夜相將。", "經明先入韋平室，句好還升李杜堂。"]'),
('e520b17c-66b6-4320-b356-30cf8a68cc70','送孫偉夫','葉適','宋','宋诗','song-poetry','','[]','我友睎顔人，造道最勇决。',144,'全唐诗/poet.song.169000.json','["我友睎顔人，造道最勇决。", "智校一驛敏，書贏萬籤閲。", "吐詞春嶽麗，景行寒泉潔。", "良工制瑚簋，本爲郊廟設。", "便留刊字正，稍上裨衮闕。", "遠尋豐城劍，虛負歷山月。", "發嫌梅柳催，到恨桃杏歇。", "親年過八袠，輿致經九折。", "紙迷版簿內，稅役半緣絕。", "云此新進士，銓限凜難越。", "廳荒茅壓項，饌惡芹縮舌。", "哿矣無情游，自傷垂老別。"]'),
('b303700c-2002-455e-b0bb-165786d814af','端午思遠樓小集','葉適','宋','宋诗','song-poetry','','[]','憑高難爲觀，樓居勢盡傾。',96,'全唐诗/poet.song.169000.json','["憑高難爲觀，樓居勢盡傾。", "思遠地不遠，空復生遐情。", "上惟山遶圍，下惟溪環縈。", "此實擅清境，豈以曠朗名。", "土俗喜操檝，五月飛駭鯨。", "鼓聲沉沉來，起走如狂酲。", "不知逐臣悲，但恃勇氣盈。", "衰翁繭帳卧，南風吹作稜。"]'),
('bcfb0a86-4966-4f90-8332-05dc9943276f','孔鍊士話龍虎山之勝於其行因以送之','葉適','宋','宋诗','song-poetry','','[]','羣嶂倚天傍四環，中峰受拱低伏蹲。',96,'全唐诗/poet.song.169000.json','["羣嶂倚天傍四環，中峰受拱低伏蹲。", "雲錦交流紫團外，却注彭蠡如傾奔。", "道陵已去丹竈冷，今代符行妖鬼靜。", "孔師何事亦逃儒，爲愛冰林雪蒙頂。", "我居無山冬不雪，只受虛空滿輪月。", "子能作意肯重來，更待牆東笋堪掘。"]'),
('220dea6e-a634-41eb-8785-f0515432d3cf','會昌觀小集呈坐上諸文友','葉適','宋','宋诗','song-poetry','','[]','茲邦異氣侯，十月陽屢暴。',144,'全唐诗/poet.song.169000.json','["茲邦異氣侯，十月陽屢暴。", "清霜云幾何，累日困袢燠。", "病羸諳冷暖，衣屨迷單複。", "上印自懸車，來諗蒙擊轂。", "東池屬草創，斤斧聲未縮。", "野蔓翳前庭，中函數株菊。", "呼鋤不受柄，善惡憂兩覆。", "賓筵煨苦蕷，憐我歲不熟。", "諸豪藹時彥，靈美競龜玉。", "學山留一塵，到海空百瀆。", "慙無歌舞伴，漫有鍼石勗。", "意闌各東西，微月耿疎木。"]'),
('3a59daf7-a16c-4b6c-bbb7-7d33c0fc8a16','送胡衍道','葉適','宋','宋诗','song-poetry','','[]','庭松雪外青，檻梅冰裏白。',168,'全唐诗/poet.song.169000.json','["庭松雪外青，檻梅冰裏白。", "正堪頻把玩，何忍驟離拆。", "我老如蛻蟬，隨葉飄重泉。", "欣君整佩出，直上穹穹天。", "卓茂冠天下，王祥歌海沂。", "奉璋承大糦，籲俊迪深知。", "情胡萬難齊，理或一未貫。", "中道不及伸，偏質徒受亂。", "同人當同羣，不止同其門。", "衆金鑪鞴合，一匠杗桶分。", "惜民當惜農，不止惜其傭。", "客主兩無怨，政刑會時雍。", "三年心所親，臨別語甚的。", "已去寧再逢，懷哉展其力。"]'),
('2293147a-7307-4dd3-a271-9e0c7ca13844','送呂子陽自永康携所解老子訪余留未久其家報以細民艱食急歸發廩賬之','葉適','宋','宋诗','song-poetry','','[]','收纓古蜜浦，抱袂生薑門。',192,'全唐诗/poet.song.169000.json','["收纓古蜜浦，抱袂生薑門。", "九九書自註，邀余綴篇端。", "久衰余學廢，彌隠子道尊。", "時維冬雷數，雲雪常晝昏。", "火把起夜色，丁鞋明齒痕。", "小邦肥羜闕，蝦蛤濫充盤。", "椒橙失滋味，糝絮勞傾吞。", "詰朝報家問，剪書徵阿孫。", "苦陳鄉人饑，采蕨啖其根。", "倉封井花滿，淘米安得渾。", "覓翁如覓父，願假東飛翰。", "念之不遑處，喟焉整歸鞍。", "我老澹百慮，身世兩莫存。", "欲私一壠潤，豈救大地乾。", "西城柳遥遥，北寺江漫漫。", "勿令嗟來死，以慰行路難。"]'),
('90bfcf88-e740-402f-8396-e3a44bb05591','送葉任道教授之官靜江','葉適','宋','宋诗','song-poetry','','[]','太學奏文夸第一，國子先生裏行立。',64,'全唐诗/poet.song.169000.json','["太學奏文夸第一，國子先生裏行立。", "嶺南梅花太枯澀，花豈喚人人底急。", "爐亭雪深叫孤鴻，傳書爲愬明光宮。", "雲翻雨覆古來有，不如堂堂金石守。"]'),
('e7e448af-fbcc-4f40-90eb-21afcd0486aa','送趙季清兼謝所惠詩','葉適','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','纍珠貫冰絲，耿光發沉淵。',72,'全唐诗/poet.song.169000.json','["纍珠貫冰絲，耿光發沉淵。", "二千八百字，字字合管絃。", "想攢風前眉，應聳雪後肩。", "又言謫匡山，五老煙霞鮮。", "著書滿破篋，官冗鹽未煎。", "少遲了上信，別用綵繩聯。"]'),
('0290b0d5-6873-44b1-a392-6f194df570dc','送陳漫翁','葉適','宋','宋诗','song-poetry','','[]','笠澤老龜蒙，蛹卧絲自裹。',144,'全唐诗/poet.song.169000.json','["笠澤老龜蒙，蛹卧絲自裹。", "君從蓮葉畔，親領末後語。", "憐我未得聞，獨繭授長緒。", "因茲服英悟，鬰鬰副奇許。", "士於淪胥中，搏手架欄柱。", "一瓦不漂零，百世保風雨。", "轉圜信無難，滅木猶有懼。", "高翔要深泳，厚積堪重負。", "狂波浸三伏，回壑萬流阻。", "旅情方夷猶，霽色待舒吐。", "樵峰濃黑散，蓼岸微紅聚。", "進舟石門灘，小泊看佳處。"]'),
('db65dfb6-d85a-4f89-af15-fab3ee872e6f','送戴漢老','葉適','宋','宋诗','song-poetry','','[]','隠侯之郡成公宅，辭流屈注回理窟。',64,'全唐诗/poet.song.169000.json','["隠侯之郡成公宅，辭流屈注回理窟。", "前輩淵騫晚凋謝，後進由求蚤超絕。", "聖朝論士皆公卿，千乘何足留高名。", "春風無痕萬情化，盡付雙溪舞雩下。"]'),
('37575c2e-cd05-4fd1-a151-ab402f512a00','孫祖佑解元世友堂','葉適','宋','宋诗','song-poetry','','[]','雀尋屋角穿，燕繞簾櫳窺。',144,'全唐诗/poet.song.169000.json','["雀尋屋角穿，燕繞簾櫳窺。", "共賀新宇就，生物欣有依。", "含德厚乃祖，義完嗟利隳。", "最憐常熟令，櫝韞不盡施。", "溫恭化羣從，遜悌流深規。", "一絲必同袍，粒黍無異炊。", "感零天上露，潤浹園中葵。", "魚蟹雖芳鮮，不如此菜肥。", "凉風送佳音，桂林自生枝。", "借子赤霄羽，登君文石墀。", "樸斲吁已勤，礱密審所宜。", "諒爲前峰近，長映客星垂。"]'),
('e6847f74-c7f0-47d1-87e8-b3ce8b72b1e3','丁氏東嶼書房','葉適','宋','宋诗','song-poetry','','[]','朝納櫺上光，千帙亂抽翻。',192,'全唐诗/poet.song.169000.json','["朝納櫺上光，千帙亂抽翻。", "夜挑窗下明，一字究本源。", "舊師蚤傳習，新友晚聞見。", "隣里疎聚頭，江海勤會面。", "勿愛好鳥羽，勿玩芳樹林。", "書亦且置之，獨自觀此心。", "茫茫未生前，寂寂已死後。", "萬變隨雲浮，朗月住中彀。", "何物粲陳列，所從定何時。", "孔顔雖去遠，聞道命如絲。", "白屋無怨難，朱門不驕易。", "每留先人樸，不忝素士志。", "鴈蕩裊長麓，南北峙兩門。", "委和被多稼，永祚延餘昆。", "紅綠脩岸容，冰雪浄空界。", "蕙轉蘭亦回，誰賦書房外。"]'),
('542f42c3-2974-41ec-90c8-0364c20aa08d','端午行','葉適','宋','宋诗','song-poetry','','[]','仙門諸水會，流下瓦窯溝。',48,'全唐诗/poet.song.169000.json','["仙門諸水會，流下瓦窯溝。", "中有吊湘客，西城南北樓。", "旗翻稻花風，棹澀梅子雨。", "夜邏無騷音，絳紗蒙首去。"]'),
('4c79cae7-9b4c-457e-b38b-74e5b1ff525e','虎長老修雙峰','葉適','宋','宋诗','song-poetry','','[]','九州大麓標山經，早與天地同垂名。',160,'全唐诗/poet.song.169000.json','["九州大麓標山經，早與天地同垂名。", "鴈蕩初傳晚唐世，掩抑衆嶽夸神靈。", "豈非龍伯所播遷，海水枯竭久乃成。", "窮鎪石怪呈萬巧，宛取物似羅千形。", "陰湫陽嶺何恍惚，紫光碧焰長磨縈。", "夜隨王喬玉簫發，曉答矩那金磬清。", "聞者未到意已傾，往往夢想驅風霆。", "胡僧猶嫌憇寂寞，便房曲檻頻招迎。", "强扶墜閣接雲漢，却補壞壁回丹青。", "來車去馬謾孔總，亭主自住誰爲情。"]'),
('85df2f3e-f649-4f35-bffb-57c020ae830b','毛希元隠居廬山卧龍瀑','葉適','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','毛子駡吳曦，蜀山眇孤墳。',120,'全唐诗/poet.song.169000.json','["毛子駡吳曦，蜀山眇孤墳。", "五老急招聘，延留如大賓。", "龍分自眠地，蕙帳饒珠蠙。", "巖花開恨晚，谷鳥鳴先春。", "吊古一沉思，千載多逸民。", "登高一長望，萬里皆積雲。", "子勇書印曆，憂憤著彌綸。", "曷不草露布，從容靜風塵。", "低頭汲澗曲，煮豆萁爲薪。", "沮溺上之恥，昔賢終賤貧。"]'),
('9f12b02c-c28b-49bc-aaea-01574bfe82f1','趙振文在城北廂兩月無日不游馬塍作歌美之請知振文者同賦','葉適','宋','宋诗','song-poetry','','[]','馬塍東西花百里，錦雲繡霧參差起。',193,'全唐诗/poet.song.169000.json','["馬塍東西花百里，錦雲繡霧參差起。", "長安大車喧廣陌，問以馬塍云未識。", "酴醿縛籬金沙牆，薜荔樓閣山茶房。", "高花何啻千金直，著價不到宜深藏。", "青鞋翩翩烏鶴袖，嚴勞引首金蔣後。", "隨園摘蕊煎凍酥，小分移床獻春酒。", "陳通苗傅昔弄兵，此地寂寞狐狸行。", "聖人有道賁草木，我輩裁花樂太平。", "知君已於苕水住，盡日艣聲摇上渚。", "無際滄波蓼自分，有情碧落鷗偏聚。", "追逐風光天漫許，拋擲身世人應怒。", "君不見南宮載寶回，何如趙子穿花去。"]'),
('84fb611f-a735-4ecc-aa7a-9c98079fab1a','周純臣子去病淑慧而短折賦以哀之','葉適','宋','宋诗','song-poetry','','[]','周子百未遇，有兒慰眼前。',180,'全唐诗/poet.song.169000.json','["周子百未遇，有兒慰眼前。", "敢誇材調別，自喜稟賦全。", "其守過老蒼，其行通變權。", "共看成蚤歲，何意夭初年。", "汝昔透胞絡，衝風著筋攣。", "和丹和乳嚥，煨附加鹽煎。", "所投烈藥盡，始獲奇痾痊。", "隋和絕代寶，氣命百分憐。", "問汝今何之，幻影來無緣。", "不許爺執捉，壞滅同埃煙。", "此悲信無益，此愛倍難捐。", "不見趙幾道，泣淚迸幽泉。", "不見孟良甫，叫吻聒穹天。", "汝爺自爲銘，志欲金石傳。", "兼求我詩去，刻在墓門邊。"]'),
('4908c9f8-37db-4e18-9f26-94b4c3889925','送盧簡夫','葉適','宋','宋诗','song-poetry','','["\u897f\u6e56"]','子昔葦間從我游，未曾一語相報酬。',64,'全唐诗/poet.song.169000.json','["子昔葦間從我游，未曾一語相報酬。", "文杏將非廟廊具，澗蘋况是王公羞。", "子今欻往西湖上，靈雨綵雲供筆仗。", "深思直道佐明君，蟄雷震空天下聞。"]'),
('d0226b20-e75c-430e-bb56-d8a2bff1b0d0','贈祈雨妙闍黎','葉適','宋','宋诗','song-poetry','','[]','雨慳水澀從季秋，倏忽春半河斷流。',128,'全唐诗/poet.song.169000.json','["雨慳水澀從季秋，倏忽春半河斷流。", "有僧了妙能禱祈，直云天閟非人求。", "朝誦呪，夜安禪，十陰九暗來纖纖。", "呪光禪寂轉相發，潤澤徐乃通幽潜。", "我老拜請良獨難，香烟鬰薄重霄間。", "旁搜潭洞攪龍蟄，鞭雷走電開天關。", "天意豈令一犁緩，人心正待百渠滿。", "補天不及人未知，禪心况寂嗟爾爲。"]'),
('d270202f-f1bc-4700-869b-ba6ca0dc5be1','寄題朝宗新樓','葉適','宋','宋诗','song-poetry','','[]','昔時師友尚草創，憶子諸父勤磨礱。',64,'全唐诗/poet.song.169000.json','["昔時師友尚草創，憶子諸父勤磨礱。", "春臺自令車馬絕，桂樹未厭鈴旗重。", "侵雲切月絳一炬，擁坐排簷青幾峰。", "莫云空洞豈無物，讀徧五車江水東。"]'),
('a147794c-f416-4b12-8edc-53cf3dd7618d','和汪提刑祈雨','葉適','宋','宋诗','song-poetry','','[]','感格誰知汪仲舉，步虛未了龍來語。',64,'全唐诗/poet.song.169000.json','["感格誰知汪仲舉，步虛未了龍來語。", "會稽秦望都洗清，越人喚作提刑雨。", "我慙老惰無精勤，累月喚龍龍不聞。", "水南早禾貪結實，一夕爛死爲泥塵。"]'),
('4d9b2fd2-98e1-48ad-89be-99e72f028dfc','蔡尚書挽詞二首  其一','葉適','宋','宋诗','song-poetry','','[]','總角都鼇頭，老生甘伏膺。',48,'全唐诗/poet.song.169000.json','["總角都鼇頭，老生甘伏膺。", "白首參豹尾，後出夸先登。", "東流看到海，北風忽成冰。", "茫茫落簷花，窮巷猶短檠。"]'),
('e6799dfc-8d4b-43a1-ad1a-24313ef1f9d0','蔡尚書挽詞二首  其二','葉適','宋','宋诗','song-poetry','','[]','撥沙得黄金，百鍊寫光影。',48,'全唐诗/poet.song.169000.json','["撥沙得黄金，百鍊寫光影。", "飛行日月上，瑩徹肝膽醒。", "空山慘馬鬣，何意重爲鑛。", "余哀不浪施，留寄長夜炯。"]'),
('f7dd0343-cc8a-4580-9642-9e5340219a04','題處州翔峰閣','葉適','宋','宋诗','song-poetry','','[]','九盤在州中，萬山來四遠。',120,'全唐诗/poet.song.169000.json','["九盤在州中，萬山來四遠。", "納於牀笫近，尋丈未爲褊。", "日光既熙麗，風氣亦清展。", "悠然不離席，所得甚宏闡。", "隠峰招伏岫，騰躍俱赴眼。", "下視田中禾，藁粒猶可見。", "臨觀要親切，亦復貴眇緬。", "峽山絲線窄，嶽極瀛海眩。", "君看齊雲上，往往無際限。", "何當躡蓬萊，一汎五湖淺。"]'),
('b8e262f1-4eea-4a43-a024-16daa2caf874','讀王德甫文卷因送省試','葉適','宋','宋诗','song-poetry','','[]','瞢頭文之病，敖脚最所患。',120,'全唐诗/poet.song.169000.json','["瞢頭文之病，敖脚最所患。", "軒其奮勇果，榻復墮衰懦。", "伊人殆天力，卓地挺脩幹。", "欻入巖雲幽，倏出星極爛。", "儼如姑射女，娣姒俱整粲。", "皎如珊瑚樹，塵垢拭杯案。", "昔夸新龍首，伏呂較蚤晏。", "又推舊菑川，耄老終佐漢。", "况今未六十，急用豈爲晚。", "行當奏苦疏，朗壓諸儒冠。"]'),
('af7f8d91-5247-4452-a337-e2b889e92806','王宗卿答春堂','葉適','宋','宋诗','song-poetry','','[]','春以喻母慈，慈深春不如。',104,'全唐诗/poet.song.169000.json','["春以喻母慈，慈深春不如。", "兒欲答母恩，恩重答無餘。", "華堂頓有雲嶺隔，夢裏分明與親劇。", "阿連進奉新批敕，翠裘黄簡緣兄得。", "朝騰巽章乞祠官，願身暮歸怡母顔。", "老農邀君勿輕去，萬紅千紫扶春住。", "雨田自種晴田收，好是天留答春處。"]'),
('392034cd-886d-4745-9fe6-8c409fc1e5f4','送葉路分','葉適','宋','宋诗','song-poetry','','["\u8861\u5c71"]','猺啾獠唧聞鳴琴，十指如玉無哀音。',64,'全唐诗/poet.song.169000.json','["猺啾獠唧聞鳴琴，十指如玉無哀音。", "應憐聽者未洗耳，衡山高兮湘水深。", "君今幅巾鵷鷺行，切勿著带貔虎傍。", "軟荷刺少離棹短，柝桐花多班露長。"]'),
('f820df7a-da2e-4761-b2a8-13e954fa41fa','答李制置','葉適','宋','宋诗','song-poetry','','[]','鼓槌恨不投淮流，復傳侯摯能校謀。',96,'全唐诗/poet.song.169000.json','["鼓槌恨不投淮流，復傳侯摯能校謀。", "西州卧龍出長算，朝汎清洛暮營丘。", "禹跡芒芒草萊遠，實邊正在耕耘滿。", "中庭雅歌自有節，豈效夷聲催煞衮。", "北平漸車淖不通，白檀可越時未同。", "待公刻就燕然頌，我亦嚴駕期無終。"]'),
('fb104a16-7862-4937-b64c-57fc792c729f','林叔和見訪道舊感歎因以爲贈','葉適','宋','宋诗','song-poetry','','[]','與子異州壤，取友四十年。',240,'全唐诗/poet.song.169000.json','["與子異州壤，取友四十年。", "狂心蚤探索，出語乾道前。", "向來朱建安，拊手笑淵源。", "小心承父昆，刻意睎回騫。", "不求壠斷登，有路直如絃。", "計其所不爲，敵富逾百千。", "衆駿跨險遠，獨鵠超眇綿。", "謂當共驂服，可以爭聯翩。", "誰知竟大謬，寸影孤雲邊。", "南省無姓名，俛眉自愁煎。", "家蔬僅掩豆，野蝗來蔽天。", "過我城西偶，相視各華顛。", "寒菊已收花，枯井未回泉。", "人生寓地上，蟻垤交折旋。", "中間較得失，區區等浮烟。", "喜君佳兒姪，放筆追奔川。", "許身若卧龍，斬蛟透重淵。", "所虞氣力豪，未受規矩鎸。", "過翁非止肖，奕世始稱賢。", "從今掩蓬蓽，同賦歸來篇。"]'),
('18ee3d3b-9e51-417b-bb6a-50770e4e1223','上灘','葉適','宋','宋诗','song-poetry','','[]','篙師上灘時，面作石皤樣。',84,'全唐诗/poet.song.169000.json','["篙師上灘時，面作石皤樣。", "及其進尺寸，乃在一偃仰。", "神禹不到地，狂流終播蕩。", "逆順本天力，人謀不相讓。", "苦戰排三軍，勢壓票姚將。", "身在亂石中，傾覆堪指掌。", "誰云荷天衢，鼠徑斷還往。"]'),
('50a59037-dd95-4a0e-a452-ceb1a03a86a7','高宗皇帝挽詞二首  其一','葉適','宋','宋诗','song-poetry','','[]','何止超前代，功隆道更尊。',48,'全唐诗/poet.song.169000.json','["何止超前代，功隆道更尊。", "幾同造區夏，還復外乾坤。", "黄屋堯年度，青山禹穴昏。", "遺民猶望幸，淚血洒中原。"]'),
('e6e7e1e7-e901-4743-a364-21f4b39d4141','高宗皇帝挽詞二首  其二','葉適','宋','宋诗','song-poetry','','[]','河濟初開府，江淮晚視師。',48,'全唐诗/poet.song.169000.json','["河濟初開府，江淮晚視師。", "纘戎由子聖，永命獨天知。", "鶴唳空虛警，雲生仗自移。", "上哀何以稱，卒代繼周時。"]'),
('e24273c7-7cf3-4ad5-8e42-c61e85572090','孝宗皇帝挽詞二首  其一','葉適','宋','宋诗','song-poetry','','[]','儉德加文景，雄才自武宣。',48,'全唐诗/poet.song.169000.json','["儉德加文景，雄才自武宣。", "道終遺萬乘，喪制盡三年。", "暫乞狂胡命，常持復漢權。", "全將一孝字，高謚百王前。"]'),
('cf3b46c7-21e6-4724-81b4-1158dd7ebe1e','孝宗皇帝挽詞二首  其二','葉適','宋','宋诗','song-poetry','','[]','昔年叨上殿，歎息動宸襟。',48,'全唐诗/poet.song.169000.json','["昔年叨上殿，歎息動宸襟。", "豈不人思奮，其如天意深。", "帝王猶遇合，南北限升沉。", "尚有登遐日，諸軍特賜金。"]'),
('56ceb81b-c510-4237-a03e-54e32564c704','吉州刺史蔡直之挽詞二首  其一','葉適','宋','宋诗','song-poetry','','[]','領閤號親貴，光宗始用儒。',48,'全唐诗/poet.song.169000.json','["領閤號親貴，光宗始用儒。", "諒惟醫國手，果驗活人書。", "負郭可稅駕，行田宜蹇馿。", "相看滿川月，無計遣長鬚。"]'),
('c741a48b-dc59-4b97-9a24-059357c960c5','吉州刺史蔡直之挽詞二首  其二','葉適','宋','宋诗','song-poetry','','[]','能事實偉甚，謙終猶罕聞。',48,'全唐诗/poet.song.169000.json','["能事實偉甚，謙終猶罕聞。", "忘身賓出日，歛手避浮雲。", "天欲消胡運，人誰靖楚氛。", "未刊千字誄，長掩一丘墳。"]'),
('3d7f3a9e-2066-4019-9c51-a552e7714aff','陽復','葉適','宋','宋诗','song-poetry','','[]','陽復冰潜動，雲衰日界明。',48,'全唐诗/poet.song.169000.json','["陽復冰潜動，雲衰日界明。", "近傳新詔綍，重起舊簪纓。", "斗極回東指，軍容直北營。", "龍蛇多變化，旋日看超昇。"]'),
('b519d661-0b17-4ed1-a294-4cef01b6ca2a','送鄭丈赴建寧五首  其一','葉適','宋','宋诗','song-poetry','','[]','過家鄉里敬，將母士夫榮。',48,'全唐诗/poet.song.169000.json','["過家鄉里敬，將母士夫榮。", "得失從人論，行藏獨自明。", "百年中古少，一笑萬金輕。", "廉士吾何敢，新茶可擷英。"]'),
('6bf45eab-2c12-42c7-a1a9-c422a76db284','送鄭丈赴建寧五首  其二','葉適','宋','宋诗','song-poetry','','[]','有志雖身健，開心在歲寒。',48,'全唐诗/poet.song.169000.json','["有志雖身健，開心在歲寒。", "一時諸老盡，多見大名難。", "湖海方連旱，甌閩適少寬。", "爲州人不乏，千萬强加餐。"]'),
('c40adc78-568e-49a8-8b0e-9fdfd655df1f','送鄭丈赴建寧五首  其三','葉適','宋','宋诗','song-poetry','','[]','清廟圖書寶，熙朝雅頌音。',48,'全唐诗/poet.song.169000.json','["清廟圖書寶，熙朝雅頌音。", "頻繁三節召，荏苒二毛侵。", "衣飲家纔足，丘園意亦深。", "卧聽床下士，時作武侯吟。"]'),
('e1fb87d8-4128-47ba-9484-8e560fcc5b23','送鄭丈赴建寧五首  其四','葉適','宋','宋诗','song-poetry','','[]','海內言華萼，功名動搢紳。',48,'全唐诗/poet.song.169000.json','["海內言華萼，功名動搢紳。", "十年長隠吏，一語必驚人。", "酒量新來減，交情老更親。", "公餘如促膝，剩把古書陳。"]'),
('966b0a1e-80c9-49c8-b229-3456264fe737','送鄭丈赴建寧五首  其五','葉適','宋','宋诗','song-poetry','','[]','屏棄誠愚分，牢愁更索居。',48,'全唐诗/poet.song.169000.json','["屏棄誠愚分，牢愁更索居。", "若逢知已問，猶解課兒書。", "地僻門長閉，年饑菜自鋤。", "相望無一事，不是故情疎。"]'),
('599882f1-382a-4376-9ec0-b19513b2dcb9','哭鄭丈四首  其一','葉適','宋','宋诗','song-poetry','','[]','道義秦城重，聲名冀馬空。',48,'全唐诗/poet.song.169000.json','["道義秦城重，聲名冀馬空。", "河汾談聖制，鄒魯振儒風。", "有學堪經世，無官可效忠。", "浮雲公豈計，吾道自憐窮。"]'),
('485cd644-e68a-4345-bbc6-2ed24525f701','哭鄭丈四首  其二','葉適','宋','宋诗','song-poetry','','[]','誰謂居今世，無由見古人。',48,'全唐诗/poet.song.169000.json','["誰謂居今世，無由見古人。", "事新曾閔上，遊世葛懷民。", "德盛天爲侶，慈薰物與春。", "清風如尚想，猶足洗囂塵。"]'),
('5707c871-1b28-43a1-bd82-bf986fd533fe','哭鄭丈四首  其三','葉適','宋','宋诗','song-poetry','','[]','插架軸三萬，撐腸卷五千。',48,'全唐诗/poet.song.169000.json','["插架軸三萬，撐腸卷五千。", "京都通百郡，溟渤滙群川。", "深淺人隨汲，東西意各便。", "後生無復見，媚學謾躚躚。"]'),
('4dbf47d5-1785-4fad-a1a0-a4afc6e61d54','哭鄭丈四首  其四','葉適','宋','宋诗','song-poetry','','[]','憶在諸生列，曾窺太史書。',48,'全唐诗/poet.song.169000.json','["憶在諸生列，曾窺太史書。", "泉蒙煩濬達，槁質費吹噓。", "外宅寧成相，生芻早吊閭。", "臨風兩行淚，愁絕向輀車。"]'),
('329a205b-cd54-43b8-b2ba-3230fac1fd86','何參政挽歌  其一','葉適','宋','宋诗','song-poetry','','[]','退食勤稽古，當朝動引經。',48,'全唐诗/poet.song.169000.json','["退食勤稽古，當朝動引經。", "人心喜偏側，國脈要勻亭。", "二府早聞政，三孤晚告靈。", "羔裘惜光彩，不肯到頭廳。"]'),
('4d07c571-61c2-49c1-a1c9-2983e1ec7c86','何參政挽歌  其二','葉適','宋','宋诗','song-poetry','','[]','晞髮滄浪上，灘聲近廣騷。',48,'全唐诗/poet.song.169000.json','["晞髮滄浪上，灘聲近廣騷。", "綠圍齊長柳，紅糝半含桃。", "欲寡堪增壽，閑多更養高。", "佳哉鳳凰壠，悲甚付烏號。"]'),
('aa15a3cc-5e81-4fcd-a506-f45e56bc3569','何參政挽歌  其三','葉適','宋','宋诗','song-poetry','','[]','宿昔叨殊眷，尋常款直廬。',48,'全唐诗/poet.song.169000.json','["宿昔叨殊眷，尋常款直廬。", "聽鷄催謁駕，立馬待紬書。", "零落誰存者，追尋昨夢餘。", "何曾嗔石介，韓愈自狂疎。"]'),
('7b4d0045-6f78-4a12-9128-51bb06bb3135','送陳糧料','葉適','宋','宋诗','song-poetry','','[]','萬里渥洼出，行天絕比倫。',48,'全唐诗/poet.song.169000.json','["萬里渥洼出，行天絕比倫。", "能參大關鍵，莫用小精神。", "鍾鼎身雖貴，簞瓢道未貧。", "梅情兼雪意，留住恰芳春。"]'),
('39da67b0-fbdc-4df4-a9f5-2f69dc3fa78f','題費肅校書遺事','葉適','宋','宋诗','song-poetry','','[]','欲識隠居者，當年費懿恭。',48,'全唐诗/poet.song.169000.json','["欲識隠居者，當年費懿恭。", "却辭金馬直，歸卧錫山峰。", "兩詔終不起，一瓢長自從。", "兒孫盡登第，勿剪舊栽松。"]'),
('08abf4fe-c5c9-4766-beb0-65cdad98c96f','送鄧諫從制幹','葉適','宋','宋诗','song-poetry','','[]','援引亦未力，聲名空復傳。',48,'全唐诗/poet.song.169000.json','["援引亦未力，聲名空復傳。", "終携太平策，還上蜀江船。", "帆色掛曉月，艣音穿夕烟。", "滄波不盡興，收拾浣花邊。"]'),
('3c1c9b31-b2e9-42d8-869f-5b425866509f','題柳山人壁二首  其一','葉適','宋','宋诗','song-poetry','','[]','水北柳六一，家傳擲卦靈。',48,'全唐诗/poet.song.169000.json','["水北柳六一，家傳擲卦靈。", "秋清演漁曲，春近著牛經。", "掩肆花竹秀，排門柑橘馨。", "應憐喜功者，虛要峴山銘。"]'),
('6dd03bb4-eab2-4e56-bdeb-94623f1726c3','題柳山人壁二首  其二','葉適','宋','宋诗','song-poetry','','[]','我病屢穆卜，山人不面謾。',48,'全唐诗/poet.song.169000.json','["我病屢穆卜，山人不面謾。", "常言千日厄，未許一朝安。", "地上庸醫滿，天邊惡曜攢。", "歸根與復命，自笑此何難。"]'),
('0db572da-c56e-4088-8fc5-88d709926704','致政通直錢公挽歌詞','葉適','宋','宋诗','song-poetry','','[]','蕭瑟梅花壠，豪華不復還。',48,'全唐诗/poet.song.169000.json','["蕭瑟梅花壠，豪華不復還。", "好兒須萬石，廣厦剩千間。", "盡與詩書癖，勿令紈綺攀。", "傳家自翁始，留筆紀池山。"]'),
('9c946096-8ed7-4a2c-ac89-0bed5371f59b','亡友項子謙兄挽歌詞','葉適','宋','宋诗','song-poetry','','[]','疇昔省君病，小車隨酒壺。',48,'全唐诗/poet.song.169000.json','["疇昔省君病，小車隨酒壺。", "心惺賞文句，語謇困喑嗚。", "念子堪垂泣，纍然失壯圖。", "唯應看幼子，空手縛於菟。"]'),
('422dc41b-9769-4ed5-a910-98aa241b661b','待制中書舍人陳公之亡以山宅須利既遷殯而未葬也後五月乃克葬焉二首  其一','葉適','宋','宋诗','song-poetry','','[]','可怕陰陽惡，還驚日月遒。',48,'全唐诗/poet.song.169000.json','["可怕陰陽惡，還驚日月遒。", "終成埋璧去，不作坐禪留。", "雨洗一簞浄，風翻千橘愁。", "門前繫船橛，宿鳥漫啁啾。"]'),
('7fdc6620-2147-4079-a582-fa1cd81e116d','待制中書舍人陳公之亡以山宅須利既遷殯而未葬也後五月乃克葬焉二首  其二','葉適','宋','宋诗','song-poetry','','[]','嗟我與公同澹泊，一生一死又凄凉。',64,'全唐诗/poet.song.169000.json','["嗟我與公同澹泊，一生一死又凄凉。", "經綸傳世止於此，老病著身行自當。", "掛壁斷弦從別調，拂天野水渡新航。", "暮春未有風雩伴，且閤遺編住冢傍。"]'),
('46352b92-e180-4132-b596-2cc189fc310b','西山','葉適','宋','宋诗','song-poetry','','[]','對面吳橋港，西山第一家。',48,'全唐诗/poet.song.169000.json','["對面吳橋港，西山第一家。", "有林皆橘樹，無水不荷花。", "竹下晴垂釣，松間雨試茶。", "更瞻東掛綵，空翠雜朝霞。"]'),
('57f13c3e-877f-4e21-b5dd-e22944e0b8e5','看柑','葉適','宋','宋诗','song-poetry','','[]','窈窕隨塘曲，酸甜在橘中。',48,'全唐诗/poet.song.169000.json','["窈窕隨塘曲，酸甜在橘中。", "所欣黄一半，相逐樹無窮。", "習啖成真性，悲歌記土風。", "慙非美人贈，採摘恣村童。"]'),
('b0cb3461-86c1-4af1-bbc2-05328e8335f2','贈杜幼高','葉適','宋','宋诗','song-poetry','','[]','杜子五兄弟，詞林俱上頭。',48,'全唐诗/poet.song.169000.json','["杜子五兄弟，詞林俱上頭。", "規模古樂府，接續後春秋。", "奇崛令誰賞，羈棲浪自愁。", "故園如鏡水，日日抱村流。"]'),
('c52b44bd-0901-4b05-94ce-6da7a1ad42c0','待制湯公挽詞','葉適','宋','宋诗','song-poetry','','[]','繅藉知良玉，虀鹽是大儒。',48,'全唐诗/poet.song.169000.json','["繅藉知良玉，虀鹽是大儒。", "單傳合上相，小却但尚書。", "蠹簡同歸處，遺簪任翳如。", "西風好溪雨，漲淚濕塗芻。"]'),
('12cd9bc9-b978-49c0-b5c7-b6436f77284c','吳參議挽歌詞','葉適','宋','宋诗','song-poetry','','[]','冉冉試百巧，栖栖終一丘。',48,'全唐诗/poet.song.169000.json','["冉冉試百巧，栖栖終一丘。", "死期甘慟哭，時事不勝憂。", "貧只藏書在，恩將別業酬。", "看君用意絕，身後令名留。"]'),
('1331de65-3c54-4fb2-b6fd-b6116ccd02b7','沖佑大夫鮑公挽詞','葉適','宋','宋诗','song-poetry','','[]','幽人眇何在，高閣鎖重關。',48,'全唐诗/poet.song.169000.json','["幽人眇何在，高閣鎖重關。", "梅冷橋邊月，菊殘籬外山。", "可憐清絕地，長憶笑談間。", "寂寞私鹽港，漁樵自往還。"]'),
('9f11721a-2e53-439c-b6d9-6f7085639f30','雪後思遠樓曉望','葉適','宋','宋诗','song-poetry','','[]','臘盡凍初合，風花江欲平。',48,'全唐诗/poet.song.169000.json','["臘盡凍初合，風花江欲平。", "急從高處賞，已向歲前晴。", "莫與鬢爭白，試將身比清。", "樓頭接遠岫，歷歷正分明。"]'),
('d4d67b75-1ada-43bb-bbd7-0aae7461964f','宿覺庵','葉適','宋','宋诗','song-poetry','','[]','宿覺名未謝，殘山今尚存。',48,'全唐诗/poet.song.169000.json','["宿覺名未謝，殘山今尚存。", "暫開雲外宅，不閉雨中門。", "麥熟僧常餓，茶枯客謾吞。", "荒凉自有趣，衰病遣誰言。"]'),
('341fc351-c656-4d68-a16b-90d47ff43bf2','贈勝上人','葉適','宋','宋诗','song-poetry','','[]','近日能吟者，黄巖說勝師。',48,'全唐诗/poet.song.169000.json','["近日能吟者，黄巖說勝師。", "語生兼老筆，體重带幽姿。", "遣臘冰千筯，勾春柳一絲。", "方山最高頂，不擬到茅茨。"]'),
('cae3d461-ab36-46a8-9e4b-79a4e6e4a649','朱文昭母楊氏挽詞','葉適','宋','宋诗','song-poetry','','[]','文昭有賢母，白首教篇章。',48,'全唐诗/poet.song.169000.json','["文昭有賢母，白首教篇章。", "義並三遷峻，書成百卷長。", "古今歸石室，筆削紀萱堂。", "鹿擾烏馴處，森森宰樹蒼。"]'),
('2da35538-c79a-462f-871e-3ca5b7e13c78','沖佑安撫郎中張公挽詞','葉適','宋','宋诗','song-poetry','','[]','誰憐張太守，思職更憂邊。',48,'全唐诗/poet.song.169000.json','["誰憐張太守，思職更憂邊。", "濠水中間月，光山盡處天。", "人應迷往事，我獨採遺編。", "莽莽乾坤裏，冥知想慨然。"]'),
('19595e47-8aeb-439c-aefd-58b766c4bfee','縣尉林公挽詞','葉適','宋','宋诗','song-poetry','','[]','恨取一官晚，公人未展衙。',48,'全唐诗/poet.song.169000.json','["恨取一官晚，公人未展衙。", "空傳讀書苦，留與後生誇。", "有子聯三俊，成名王兩家。", "會須酬貴骨，野燎報宣麻。"]'),
('32c6a979-38f4-41a4-9c8a-e586d9f48ae3','陳侍郎挽詞','葉適','宋','宋诗','song-poetry','','[]','生死悲歡地，長嗟付短吟。',48,'全唐诗/poet.song.169000.json','["生死悲歡地，長嗟付短吟。", "北門晨鵲趁，西甸晚鴉尋。", "三品官名重，千年墓色深。", "廣東正思憶，淚激海潮音。"]'),
('6a6608a3-8c0f-4874-b7ce-b0aef342415c','太令人胡氏挽詞','葉適','宋','宋诗','song-poetry','','[]','已刻溪西誌，潸然淚滿袪。',48,'全唐诗/poet.song.169000.json','["已刻溪西誌，潸然淚滿袪。", "軻喪嫌後侈，參養要前餘。", "甫里送錦纜，館頭迎布車。", "爲題楓葉往，蟲籀不成書。"]'),
('10df223e-f400-4686-b8dc-b6c758db3bbb','題張提舉園','葉適','宋','宋诗','song-poetry','','[]','竹外萬雲合，荷心一雁來。',48,'全唐诗/poet.song.169000.json','["竹外萬雲合，荷心一雁來。", "若無歌舞閙，應有鬼神猜。", "野岸鋤難遍，幽根暖易栽。", "前山未放入，好閣更南開。"]'),
('52db4494-88ea-4b2c-8331-ef558e4e8616','送謝希孟','葉適','宋','宋诗','song-poetry','','[]','白頭趨幕府，早已負平生。',48,'全唐诗/poet.song.169000.json','["白頭趨幕府，早已負平生。", "未放鵬舒翼，應煩驥斂程。", "驛梅催凍蕊，柁雨送春聲。", "爲語常平使，開懷待子荆。"]'),
('aff9c3ae-6b0a-4063-8c37-97f0a299eb62','送周子靜','葉適','宋','宋诗','song-poetry','','[]','地深湘渚浪，天遠桂陽城。',48,'全唐诗/poet.song.169000.json','["地深湘渚浪，天遠桂陽城。", "故里楸花別，諸生柳絮迎。", "一夔開跡後，六舞待時行。", "子自調新律，吾衰閟舊聲。"]'),
('1ce95a25-b8d6-40de-b97e-7062dd601ecf','林處士挽詞','葉適','宋','宋诗','song-poetry','','[]','尚平接馬弟，髣髴記前身。',48,'全唐诗/poet.song.169000.json','["尚平接馬弟，髣髴記前身。", "海闊元隨浪，山高別領春。", "難招古渡外，空老夕陽濱。", "順性無生滅，君應了正因。"]'),
('fbbc98d4-46aa-472b-b494-e2bf8730bc7c','錢知縣挽詞','葉適','宋','宋诗','song-poetry','','[]','送子三爲邑，十年嗟往來。',48,'全唐诗/poet.song.169000.json','["送子三爲邑，十年嗟往來。", "誰言債難了，不與命同回。", "卓魯終留愛，龔黄豈蔽材。", "雲愁旦暮雪，雪打又添哀。"]'),
('eec53c31-3262-4c4c-849d-473f9367c7af','送潘景參','葉適','宋','宋诗','song-poetry','','[]','久自知潘令，經曾薦禰衡。',48,'全唐诗/poet.song.169000.json','["久自知潘令，經曾薦禰衡。", "居慚薄氣力，何以助聲名。", "松柏非無歲，鹽梅會有羹。", "又從沙際別，把酒候潮生。"]'),
('ef8fe34c-10d0-44d8-8098-4314da73acc0','贈徐靈淵','葉適','宋','宋诗','song-poetry','','[]','歐虞兼褚薛，事遠跡爲塵。',48,'全唐诗/poet.song.169000.json','["歐虞兼褚薛，事遠跡爲塵。", "今日觀來翰，如親見古人。", "盡歸嚴號令，富有活精神。", "碑板荒唐久，遄看走四鄰。"]'),
('b8378977-5634-488d-9497-b2c7c724dd8a','戴肖望挽詞  其一','葉適','宋','宋诗','song-poetry','','[]','巖巖蕭太傅，謇謇鄭尚書。',48,'全唐诗/poet.song.169000.json','["巖巖蕭太傅，謇謇鄭尚書。", "可惜流光晚，翻無急詔除。", "交情梅蕊盡，哀意柳芽疎。", "只有安江滿，長涵夜月虛。"]'),
('0b80263c-33ef-4761-b4fe-6e139f63b1cd','戴肖望挽詞  其二','葉適','宋','宋诗','song-poetry','','[]','老失平生友，悲尋路轉迷。',48,'全唐诗/poet.song.169000.json','["老失平生友，悲尋路轉迷。", "水肥應返釣，田瘦合歸犁。", "草與地蕭瑟，雲垂天慘凄。", "無因再商略，短日送寒鷄。"]'),
('05de443c-ebca-45bb-a0b9-f33bbefdcec7','徐靈淵挽詞','葉適','宋','宋诗','song-poetry','','[]','自卜西南宅，始聞幽賞多。',48,'全唐诗/poet.song.169000.json','["自卜西南宅，始聞幽賞多。", "山供映門樹，水獻捲簾荷。", "近局棋頻賭，鄰篘酒屢歌。", "誰云祕此樂，拋擲與流梭。"]'),
('2017e1cf-3a7f-42a6-89f1-18addfb6ee09','包顒叟挽詞二首  其一','葉適','宋','宋诗','song-poetry','','[]','風沙江上宅，斥鹵望中村。',48,'全唐诗/poet.song.169000.json','["風沙江上宅，斥鹵望中村。", "密竹元遮徑，崇蘭早映門。", "笑談看磊落，材力可騰掀。", "誰復知心事，滄波霧雨昏。"]'),
('762eb2a2-de4a-44f7-9f12-d82c5af38214','包顒叟挽詞二首  其二','葉適','宋','宋诗','song-poetry','','[]','養志諸郎事，專經永夜殘。',48,'全唐诗/poet.song.169000.json','["養志諸郎事，專經永夜殘。", "雖云綠衫易，更覺綵衣難。", "客散棋奩閉，庭虛酒盎乾。", "無言慰孤苦，持此問漫漫。"]'),
('ce69abfa-7b12-4d8c-ba26-65531aaef6e3','林敬之挽詞','葉適','宋','宋诗','song-poetry','','[]','雜遝新河市，酸寒處士廬。',48,'全唐诗/poet.song.169000.json','["雜遝新河市，酸寒處士廬。", "甘辭魯穆饋，獨著孟軻書。", "籬壞從兒補，禾荒付客鋤。", "永嘉新有志，莫遣姓名疎。"]'),
('128cc9b7-d9a8-48a9-a7aa-4fd673e93813','王運使挽詞','葉適','宋','宋诗','song-poetry','','[]','種虜昔逾塞，三邊各受師。',48,'全唐诗/poet.song.169000.json','["種虜昔逾塞，三邊各受師。", "共傳君善守，能護國西陲。", "卿秩恩雖早，郎班詔已遲。", "須將未盡賞，酬折在豐碑。"]'),
('e8cbb1dc-a953-47de-a06c-523185da0307','薛子舒罷官久無所授端明得謝始換承務郎','葉適','宋','宋诗','song-poetry','','[]','男子行藏地，自求難問天。',48,'全唐诗/poet.song.169000.json','["男子行藏地，自求難問天。", "空多賈誼學，突過馬周年。", "願改京官後，常趨黼扆前。", "太平如致了，別造會昌船。"]'),
('8a5de623-c220-474a-b096-b7c5690d14dc','贈呂縣丞','葉適','宋','宋诗','song-poetry','','[]','自得長官後，邑人詩轉工。',48,'全唐诗/poet.song.169000.json','["自得長官後，邑人詩轉工。", "批書月屢滿，覓薦歲常空。", "柳已如藍碧，桃元勝錦紅。", "終歸剡溪上，舉棹謝東風。"]'),
('5aca0098-fc86-49cd-bf31-c0bf1c96f5c5','詹魯山解元以壽母求詩','葉適','宋','宋诗','song-poetry','','[]','九十人稀有，追歡盡橐金。',48,'全唐诗/poet.song.169000.json','["九十人稀有，追歡盡橐金。", "猶嫌兒舞拙，不怕酒行深。", "寄鮓未垂訓，設鷄先賞音。", "維舟橘花晚，霧雨噀前林。"]'),
('3a2def56-104b-4cc3-9b31-12fd6b79646f','贈蔡茂材貫之子與','葉適','宋','宋诗','song-poetry','','[]','蔡家五千卷，藏向石庵中。',48,'全唐诗/poet.song.169000.json','["蔡家五千卷，藏向石庵中。", "講誦今幾日，飄零隨隕風。", "隔垣孤響度，別井暗泉通。", "安得無爻象，與將吾道東。"]'),
('ef7bd9bf-38f8-4fbe-8697-b99271636b7a','余知府挽詩二首  其一','葉適','宋','宋诗','song-poetry','','[]','壽者福之首，中兼典郡來。',48,'全唐诗/poet.song.169000.json','["壽者福之首，中兼典郡來。", "聖知天上事，磨盡世間材。", "此傺靈龜往，何方化鶴回。", "所親都不恨，有識自興哀。"]'),
('254e179a-091f-4013-adf9-5f61ac8729c7','余知府挽詩二首  其二','葉適','宋','宋诗','song-poetry','','[]','憐我抱空意，鬢間饒白絲。',48,'全唐诗/poet.song.169000.json','["憐我抱空意，鬢間饒白絲。", "已從真率集，那復少年時。", "柳糝春前葉，松鎪雪後枝。", "建炎無故老，難話省方悲。"]'),
('8c8194ee-86c3-4c76-89d4-83a36d8f3ca7','趙知縣挽詞','葉適','宋','宋诗','song-poetry','','[]','僧館經年學，書籤盡日抽。',48,'全唐诗/poet.song.169000.json','["僧館經年學，書籤盡日抽。", "空聞割鷄笑，不見化鳬留。", "瘴月曉還落，蠻雲冷未收。", "西華夜來雨，浄洗一生愁。"]'),
('303c7dfe-3e31-452c-ae1c-de0e7ca5a80a','趙清叔挽詞','葉適','宋','宋诗','song-poetry','','[]','昔我共筆硯，知君賢弟昆。',48,'全唐诗/poet.song.169000.json','["昔我共筆硯，知君賢弟昆。", "門邀百客醉，囊諱一金存。", "忽與鐘聲盡，長悲磬色昏。", "多年趙家府，銷減惠王孫。"]'),
('4f5315d6-a48d-4f18-92de-477c7b8380b3','贈聽聲歐陽承務','葉適','宋','宋诗','song-poetry','','[]','無心立臧否，有術驗榮衰。',48,'全唐诗/poet.song.169000.json','["無心立臧否，有術驗榮衰。", "舉世聲中動，浮生骨带來。", "彈輕知福地，欬小應靈臺。", "笑我老何及，是身惟死灰。"]'),
('a95504c1-3efa-43cd-81b6-bb7c748bddf1','送包通判兼寄滕季度','葉適','宋','宋诗','song-poetry','','[]','風雨逍遥地，衙排印簏新。',48,'全唐诗/poet.song.169000.json','["風雨逍遥地，衙排印簏新。", "鈿車分路闊，寶瑟聽歌頻。", "燈市曉侵月，花田晚占春。", "却過張翰宅，方信有閑人。"]'),
('ffeaaa9f-0cfc-473c-9540-8fb0a769ebae','趙尚書挽詩  其一','葉適','宋','宋诗','song-poetry','','[]','材業將時偶，聲名鬭寵新。',48,'全唐诗/poet.song.169000.json','["材業將時偶，聲名鬭寵新。", "文昌留不住，大尹政通神。", "力說和戎好，從撩相國嗔。", "春花插秋鬢，還得自由身。"]'),
('e2b52471-f725-4e39-95d6-d7f5231214cc','趙尚書挽詩  其二','葉適','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','江北江南曲，吟高許和同。',48,'全唐诗/poet.song.169000.json','["江北江南曲，吟高許和同。", "相迎黄篾浪，失笑白蘋風。", "老病猶貪活，漂零各隕空。", "長懷洞庭橘，買宅傍牆東。"]'),
('fcc90f78-213a-4f1f-b924-c8f2c6d9990e','周宗夷東山堂','葉適','宋','宋诗','song-poetry','','[]','城嶂標辰極，誰家特有山。',48,'全唐诗/poet.song.169000.json','["城嶂標辰極，誰家特有山。", "偏憐東崦好，只對北堂閑。", "動石低簷住，流鶑拂檻還。", "仙關鎖瓊海，幽夢或時攀。"]'),
('8c16c7f6-388c-4974-968e-d4c6f8c16377','丘安人挽詩','葉適','宋','宋诗','song-poetry','','[]','左司遺事遠，介婦古風存。',48,'全唐诗/poet.song.169000.json','["左司遺事遠，介婦古風存。", "業廣添新宅，儒多起舊門。", "真亭留壽影，雲物護山原。", "我欲攀車別，衰殘阻故園。"]'),
('7a4e0faa-849e-4ec0-a302-24aac495e533','題郭希呂劉詠道游鴈蕩詩後','葉適','宋','宋诗','song-poetry','','[]','隠劉甘隠淪，老郭亦離羣。',48,'全唐诗/poet.song.169000.json','["隠劉甘隠淪，老郭亦離羣。", "自鎖魚亭月，同穿雁蕩雲。", "排峰造龍質，懸水迸簾紋。", "百種聚奇怪，從君句裏分。"]'),
('4ab1336b-8faa-41d5-a4b6-fdef5f4eb85d','送戴宣子','葉適','宋','宋诗','song-poetry','','[]','爲愛千竿玉，垂陰似古城。',48,'全唐诗/poet.song.169000.json','["爲愛千竿玉，垂陰似古城。", "弟兄俱挺立，文獻各標名。", "握粟親年晚，浮家越浪輕。", "相期早得意，還伴此君清。"]'),
('7afaae1f-5e18-45e1-8e43-e2df884106cd','題仰孝廉事實後','葉適','宋','宋诗','song-poetry','','[]','孝子久傳名，誠通物表靈。',48,'全唐诗/poet.song.169000.json','["孝子久傳名，誠通物表靈。", "當年虎失猛，此日竹還青。", "墓墾無留菽，庭荒枕舊廳。", "惟存古題誌，寶惜勝如經。"]'),
('8ab53b8e-b4fb-4b8a-9563-233980c796b5','贈盧次夔','葉適','宋','宋诗','song-poetry','','[]','家住東郊深，能詩人共尋。',48,'全唐诗/poet.song.169000.json','["家住東郊深，能詩人共尋。", "冰梭間道錦，玉軫斷文琴。", "城漏宵添滴，窗花晝減陰。", "新凉白頭句，清甚費悲吟。"]');
